# Access RW
# -----------------------------------------------------------------
FTINT_ADDR_EIRQMDR               = 0x1000006c
# -----------------------------------------------------------------
# ------
FTINT_EIRQMDR_BITS               = 32
FTINT_EIRQMDR_LSB                = 0
FTINT_EIRQMDR_MSB                = 31
FTINT_EIRQMDR_MASK               = 0xffffffff
FTINT_EIRQMDR_SH                 = 0
FTINT_EIRQMDR_DEF                = 0x00000000
# -----------------------------------------------------------------
