# -----------------------------------------------------------------
FTINT_ADDR_EIRQTGR               = 0x10000070
# -----------------------------------------------------------------
# ------
FTINT_EIRQTGR_BITS               = 32
FTINT_EIRQTGR_LSB                = 0
FTINT_EIRQTGR_MSB                = 31
FTINT_EIRQTGR_MASK               = 0xffffffff
FTINT_EIRQTGR_SH                 = 0
FTINT_EIRQTGR_DEF                = 0x00000000
