FTINT_EIRQSTSR_BITS              = 32
FTINT_EIRQSTSR_LSB               = 0
FTINT_EIRQSTSR_MSB               = 31
FTINT_EIRQSTSR_MASK              = 0xffffffff
FTINT_EIRQSTSR_SH                = 0
FTINT_EIRQSTSR_DEF               = 0x00000000
# -----------------------------------------------------------------
