FTINT_EFIQDEB_SH                 = 0
FTINT_EFIQDEB_DEF                = 0x00000000

# =================================================================
# ftspi: Faraday SPI Flash Controller
# The registers between offsets 0x10 and 0x54, 0x100 except 0x30, can be
# accessed as BYTE, HWORD, or WORD. The command queue (Offsets
# 0x00-0x0C, 0x30) input entry can only accept WORD accesses.
# -----------------------------------------------------------------
# ftspi CMD_W0: Command Register 0
# One command contains four words. One command will be executed when the
# fourth word of a command is written. The command must be executed
# before reading/writing the data into FIFO. For write commands, users
# must check and clear the command complete interrupt before writing the
# next command. For read status commands, users must check and clear the
# command complete interrupt before writing the next command. For read
# data commands, users must finish reading the data from RXFIFO; and
# check and clear the command complete interrupt before writing the next
# command.
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_CMD_W0                = 0x10010000
# -----------------------------------------------------------------
# ------
# ADDR: 
# Access RW
# SPI Flash Address. 
FTSPI_CMD_W0_ADDR_BITS           = 32
FTSPI_CMD_W0_ADDR_LSB            = 0
FTSPI_CMD_W0_ADDR_MSB            = 31
FTSPI_CMD_W0_ADDR_MASK           = 0xffffffff
FTSPI_CMD_W0_ADDR_SH             = 0
FTSPI_CMD_W0_ADDR_DEF            = 0x00000000
# -----------------------------------------------------------------
# ftspi CMD_W1: Command Register 1
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_CMD_W1                = 0x10010004
# -----------------------------------------------------------------
# ------
# ADDR_LEN: 
# Access RW
# Number of SPI address bytes from 0 to 4. For  XIP port access, the
# value is decided by the SPI_addr_cyc port. When the address length is
# 0, there will be no dummy cycle ([23:16]) and continuous read mode
# code (0x000C[23 :16]) will occur.
FTSPI_CMD_W1_ADDR_LEN_BITS       = 3
FTSPI_CMD_W1_ADDR_LEN_LSB        = 0
FTSPI_CMD_W1_ADDR_LEN_MSB        = 2
FTSPI_CMD_W1_ADDR_LEN_MASK       = 0x00000007
FTSPI_CMD_W1_ADDR_LEN_SH         = 0
FTSPI_CMD_W1_ADDR_LEN_DEF        = 0x00000003
# ------
# DUM_2ND: 
# Access RW
# Number of Second Dummy Cycle States from 0 to 32. Second dummy state
# is located between the address and the data state that excludes the
# continuous read mode state. Users can check whether the dummy state
# exists between the address and the data state or not in the SPI Flash
# specification. The host controller will issue logic 1 in the dummy
# cycle.
FTSPI_CMD_W1_DUM_2ND_BITS        = 8
FTSPI_CMD_W1_DUM_2ND_LSB         = 16
FTSPI_CMD_W1_DUM_2ND_MSB         = 23
FTSPI_CMD_W1_DUM_2ND_MASK        = 0x00ff0000
FTSPI_CMD_W1_DUM_2ND_SH          = 16
FTSPI_CMD_W1_DUM_2ND_DEF         = 0x00000000
# ------
# ILEN: 
# Access RW
# Instruction code length from 0 to 2 bytes. When users want to execute
# a SPI Flash command, the instruction code must be included. Different
# SPI Flash vendors have different instruction lengths. Therefore, users
# can set this register to meet different behaviors. Instruction code is
# normally 1 byte. However, if users set the 2-byte instruction length,
# the host controller will issue this instruction code twice.
FTSPI_CMD_W1_ILEN_BITS           = 2
FTSPI_CMD_W1_ILEN_LSB            = 24
FTSPI_CMD_W1_ILEN_MSB            = 25
FTSPI_CMD_W1_ILEN_MASK           = 0x03000000
FTSPI_CMD_W1_ILEN_SH             = 24
FTSPI_CMD_W1_ILEN_DEF            = 0x00000001
# ------
# CRM: 
# Access RW
# Continous Read Mode Enable. The continuous read mode state is located
# between the address and second dummy state. It can eliminate the
# instruction state after the second read command in the continuous read
# mode. Please do not enable this bit while data counter (Cmd_w2) is 0.
FTSPI_CMD_W1_CRM_BIT             = 28
FTSPI_CMD_W1_CRM_MASK            = 0x10000000
FTSPI_CMD_W1_CRM_SH              = 28
FTSPI_CMD_W1_CRM_DEF             = 0x00000000
# -----------------------------------------------------------------
# ftspi CMD_W2: Command Register 2
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_CMD_W2                = 0x10010008
# -----------------------------------------------------------------
# ------
# DATA_COUNTER: 
# Access RW
# Read/Write data counter. Set this to the number of bytes to read or
# written. It must not be set to 0 except when the command is read
# status or write enable. This register must be set to 0 when performing
# the read status command.
FTSPI_CMD_W2_DATA_COUNTER_BITS   = 32
FTSPI_CMD_W2_DATA_COUNTER_LSB    = 0
FTSPI_CMD_W2_DATA_COUNTER_MSB    = 31
FTSPI_CMD_W2_DATA_COUNTER_MASK   = 0xffffffff
FTSPI_CMD_W2_DATA_COUNTER_SH     = 0
FTSPI_CMD_W2_DATA_COUNTER_DEF    = 0x00000000
# -----------------------------------------------------------------
# ftspi CMD_W3: Command Register 3
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_CMD_W3                = 0x1001000c
# -----------------------------------------------------------------
# ------
# WREN: 
# Access RW
# Write enable. Enable the SPI write data, except for the read data or
# read status (Read the data return path); users must set the write
# enable = 1 for other SPI commands. Please note that in the write data
# or erase Flash command, write enable is set to 1. Only when in the
# read data or read status command, write enable must be set to 0.
FTSPI_CMD_W3_WREN_BIT            = 1
FTSPI_CMD_W3_WREN_MASK           = 0x00000002
FTSPI_CMD_W3_WREN_SH             = 1
FTSPI_CMD_W3_WREN_DEF            = 0x00000000
# ------
# RDSTEN: 
# Access RW
# Read status enable. To read the SPI status the wren bit must be 0 and
# users must issue the SPI read status command.
FTSPI_CMD_W3_RDSTEN_BIT          = 2
FTSPI_CMD_W3_RDSTEN_MASK         = 0x00000004
FTSPI_CMD_W3_RDSTEN_SH           = 2
FTSPI_CMD_W3_RDSTEN_DEF          = 0x00000000
# ------
# RDST: 
# Access RW
# Disable reading of SPI status by the hardware. When cleared the
# controller will poll the status until the status is ready (Not busy)
# and write the status register. When set SW issues the read status
# command.
FTSPI_CMD_W3_RDST_BIT            = 3
FTSPI_CMD_W3_RDST_MASK           = 0x00000008
FTSPI_CMD_W3_RDST_SH             = 3
FTSPI_CMD_W3_RDST_DEF            = 0x00000000
# ------
# DTR: 
# Access RW
# Double Data Transfer Rate Mode. DTR mode should only bet set for read
# data commands.
FTSPI_CMD_W3_DTR_BIT             = 4
FTSPI_CMD_W3_DTR_MASK            = 0x00000010
FTSPI_CMD_W3_DTR_SH              = 4
FTSPI_CMD_W3_DTR_DEF             = 0x00000000
# ------
# SPIMODE: 
# Access RW
# SPI operate mode. 0: Serial Mode, 1: Dual Mode, 2: Quad Mode, 3: Dual
# I/O Mode, 4: Quad I/O Mode.
FTSPI_CMD_W3_SPIMODE_BITS        = 3
FTSPI_CMD_W3_SPIMODE_LSB         = 5
FTSPI_CMD_W3_SPIMODE_MSB         = 7
FTSPI_CMD_W3_SPIMODE_MASK        = 0x000000e0
FTSPI_CMD_W3_SPIMODE_SH          = 5
FTSPI_CMD_W3_SPIMODE_DEF         = 0x00000000
# ------
# CRM_CODE: 
# Access RW
# Continuous read mode operate code. Users can fill this code to execute
# the continuous read mode. To do the continuous read mode with this
# Flash, users have to issue 0xA0 as the mode bit because it does not
# need the instruction code for the next read command.
FTSPI_CMD_W3_CRM_CODE_BITS       = 8
FTSPI_CMD_W3_CRM_CODE_LSB        = 16
FTSPI_CMD_W3_CRM_CODE_MSB        = 23
FTSPI_CMD_W3_CRM_CODE_MASK       = 0x00ff0000
FTSPI_CMD_W3_CRM_CODE_SH         = 16
FTSPI_CMD_W3_CRM_CODE_DEF        = 0x00000000
# ------
# INSTR: 
# Access RW
# SPI Flash Instruction Code.
FTSPI_CMD_W3_INSTR_BITS          = 8
FTSPI_CMD_W3_INSTR_LSB           = 24
FTSPI_CMD_W3_INSTR_MSB           = 31
FTSPI_CMD_W3_INSTR_MASK          = 0xff000000
FTSPI_CMD_W3_INSTR_SH            = 24
FTSPI_CMD_W3_INSTR_DEF           = 0x00000000
# -----------------------------------------------------------------
# ftspi CR: Control Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_CR                    = 0x10010010
# -----------------------------------------------------------------
# ------
# CLKDIV: 
# Access RW
# Divide the SPI input clock to derive the SPI output clock. Divisor = 2
# << clkdiv.
FTSPI_CR_CLKDIV_BITS             = 2
FTSPI_CR_CLKDIV_LSB              = 0
FTSPI_CR_CLKDIV_MSB              = 1
FTSPI_CR_CLKDIV_MASK             = 0x00000003
FTSPI_CR_CLKDIV_SH               = 0
FTSPI_CR_CLKDIV_DEF              = 0x00000000
# ------
# CLKMODE: 
# Access RW
# SPI clock level at the IDLE state. 0: clock low, 1: clock high.
FTSPI_CR_CLKMODE_BIT             = 4
FTSPI_CR_CLKMODE_MASK            = 0x00000010
FTSPI_CR_CLKMODE_SH              = 4
FTSPI_CR_CLKMODE_DEF             = 0x00000000
# ------
# XIP_IDLE: 
# Access RO
# XIP Idle Status. 0: busy, 1: idle.
FTSPI_CR_XIP_IDLE_BIT            = 7
FTSPI_CR_XIP_IDLE_MASK           = 0x00000080
FTSPI_CR_XIP_IDLE_SH             = 7
FTSPI_CR_XIP_IDLE_DEF            = 0x00000000
# ------
# ABORT: 
# Access RW
# Flush all commands and FIFOS, and reset the state machine. his bit
# will be automatically cleared to zero.
FTSPI_CR_ABORT_BIT               = 8
FTSPI_CR_ABORT_MASK              = 0x00000100
FTSPI_CR_ABORT_SH                = 8
FTSPI_CR_ABORT_DEF               = 0x00000000
# ------
# RDY_LOC: 
# Access RW
# Indicates which bit of the SPI status is the busy bit.
FTSPI_CR_RDY_LOC_BITS            = 3
FTSPI_CR_RDY_LOC_LSB             = 16
FTSPI_CR_RDY_LOC_MSB             = 18
FTSPI_CR_RDY_LOC_MASK            = 0x00070000
FTSPI_CR_RDY_LOC_SH              = 16
FTSPI_CR_RDY_LOC_DEF             = 0x00000000
# ------
# XIP_MODE: 
# Access RW
# XIP Mode Enable. 0: Command Slave Port, 1: XIP Port. When the bit is
# toggled, FTSPI020 will automatically issue the abort function. Users
# must wait until the abort function is finished to issue a command.
FTSPI_CR_XIP_MODE_BIT            = 20
FTSPI_CR_XIP_MODE_MASK           = 0x00100000
FTSPI_CR_XIP_MODE_SH             = 20
FTSPI_CR_XIP_MODE_DEF            = 0x00000001
# -----------------------------------------------------------------
# ftspi ACTR: AC Timing Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_ACTR                  = 0x10010014
# -----------------------------------------------------------------
# ------
# CS_DELAY: 
# Access RW
# cs delay is the number of SPI clocks-1 from inactive cs to active cs,
# which means that the timing is from high to low. Please follow the SPI
# flash specification for details. The unit is the sck_out period, and
# the default setting is 16 sck_out periods.
FTSPI_ACTR_CS_DELAY_BITS         = 4
FTSPI_ACTR_CS_DELAY_LSB          = 0
FTSPI_ACTR_CS_DELAY_MSB          = 3
FTSPI_ACTR_CS_DELAY_MASK         = 0x0000000f
FTSPI_ACTR_CS_DELAY_SH           = 0
FTSPI_ACTR_CS_DELAY_DEF          = 0x0000000f
# -----------------------------------------------------------------
# ftspi SR: Status Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_SR                    = 0x10010018
# -----------------------------------------------------------------
# ------
# TXF_RDY: 
# Access RO
# TxFIFO ready status. 1 when the FIFO is ready to accept data.
FTSPI_SR_TXF_RDY_BIT             = 0
FTSPI_SR_TXF_RDY_MASK            = 0x00000001
FTSPI_SR_TXF_RDY_SH              = 0
FTSPI_SR_TXF_RDY_DEF             = 0x00000001
# ------
# RXF_RDY: 
# Access RO
# RxFIFO ready status. 1 when the FIFO has data to read.
FTSPI_SR_RXF_RDY_BIT             = 1
FTSPI_SR_RXF_RDY_MASK            = 0x00000002
FTSPI_SR_RXF_RDY_SH              = 1
FTSPI_SR_RXF_RDY_DEF             = 0x00000000
# -----------------------------------------------------------------
# ftspi ICR: Interrupt Control Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_ICR                   = 0x10010020
# -----------------------------------------------------------------
# ------
# DMA_EN: 
# Access RW
# Enable DMA hardware handshake. disable this bit first before switching
# from the command-based slave port to the XIP port.
FTSPI_ICR_DMA_EN_BIT             = 0
FTSPI_ICR_DMA_EN_MASK            = 0x00000001
FTSPI_ICR_DMA_EN_SH              = 0
FTSPI_ICR_DMA_EN_DEF             = 0x00000000
# ------
# CCIE: 
# Access RW
# Command Complete Interrupt Enable.
FTSPI_ICR_CCIE_BIT               = 1
FTSPI_ICR_CCIE_MASK              = 0x00000002
FTSPI_ICR_CCIE_SH                = 1
FTSPI_ICR_CCIE_DEF               = 0x00000000
# ------
# TXF_THR: 
# Access RW
# Tx FIFO threshold for generating an interrupt. 0: 8, 1: 16, 2: 24.
FTSPI_ICR_TXF_THR_BITS           = 2
FTSPI_ICR_TXF_THR_LSB            = 8
FTSPI_ICR_TXF_THR_MSB            = 9
FTSPI_ICR_TXF_THR_MASK           = 0x00000300
FTSPI_ICR_TXF_THR_SH             = 8
FTSPI_ICR_TXF_THR_DEF            = 0x00000000
# ------
# RXF_THR: 
# Access RW
# Rx FIFO threshold for generating an interrupt. 0: 8, 1: 16, 2: 24.
FTSPI_ICR_RXF_THR_BITS           = 2
FTSPI_ICR_RXF_THR_LSB            = 12
FTSPI_ICR_RXF_THR_MSB            = 13
FTSPI_ICR_RXF_THR_MASK           = 0x00003000
FTSPI_ICR_RXF_THR_SH             = 12
FTSPI_ICR_RXF_THR_DEF            = 0x00000000
# -----------------------------------------------------------------
# ftspi ISR: Interrupt Status Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_ISR                   = 0x10010024
# -----------------------------------------------------------------
# ------
# CCS: 
# Access W1C
# Command Complete Status. This bit will be set when a command is
# completed.
FTSPI_ISR_CCS_BIT                = 0
FTSPI_ISR_CCS_MASK               = 0x00000001
FTSPI_ISR_CCS_SH                 = 0
FTSPI_ISR_CCS_DEF                = 0x00000000
# -----------------------------------------------------------------
# ftspi SPISR: SPI Read Status Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_SPISR                 = 0x10010028
# -----------------------------------------------------------------
# ------
# STATUS: 
# Access RO
# Host issues the read SPI Flash status command and stores the return
# data at this register. Users can read this register to check the SPI
# Flash status.
FTSPI_SPISR_STATUS_BITS          = 8
FTSPI_SPISR_STATUS_LSB           = 0
FTSPI_SPISR_STATUS_MSB           = 7
FTSPI_SPISR_STATUS_MASK          = 0x000000ff
FTSPI_SPISR_STATUS_SH            = 0
FTSPI_SPISR_STATUS_DEF           = 0x00000000
# -----------------------------------------------------------------
# ftspi SPIFSR: SPI Flash Size Register
# For the direct address mapped function, the address of system is
# always larger than the address of the SPI Flash. Users need to mask
# the higher bits of the system address to fit the SPI Flash size.
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_SPIFSR                = 0x1001002c
# -----------------------------------------------------------------
# ------
FTSPI_SPIFSR_BITS                = 32
FTSPI_SPIFSR_LSB                 = 0
FTSPI_SPIFSR_MSB                 = 31
FTSPI_SPIFSR_MASK                = 0xffffffff
FTSPI_SPIFSR_SH                  = 0
FTSPI_SPIFSR_DEF                 = 0xff000000
# -----------------------------------------------------------------
# ftspi XIPCMD: XIP Command Word Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_XIPCMD                = 0x10010030
# -----------------------------------------------------------------
# ------
# DUM_2ND: 
# Access RW
# Number of Second Dummy Cycle States from 0 to 32. Second dummy state
# is located between the address and the data state that excludes the
# continuous read mode state. Users can check whether the dummy state
# exists between the address and the data state or not in the SPI Flash
# specification. The host controller will issue logic 1 in the dummy
# cycle.
FTSPI_XIPCMD_DUM_2ND_BITS        = 8
FTSPI_XIPCMD_DUM_2ND_LSB         = 0
FTSPI_XIPCMD_DUM_2ND_MSB         = 7
FTSPI_XIPCMD_DUM_2ND_MASK        = 0x000000ff
FTSPI_XIPCMD_DUM_2ND_SH          = 0
FTSPI_XIPCMD_DUM_2ND_DEF         = 0x00000000
# ------
# SPIMODE: 
# Access RW
# SPI operate mode. 0: Serial Mode, 1: Dual Mode, 2: Quad Mode, 3: Dual
# I/O Mode, 4: Quad I/O Mode.
FTSPI_XIPCMD_SPIMODE_BITS        = 3
FTSPI_XIPCMD_SPIMODE_LSB         = 8
FTSPI_XIPCMD_SPIMODE_MSB         = 10
FTSPI_XIPCMD_SPIMODE_MASK        = 0x00000700
FTSPI_XIPCMD_SPIMODE_SH          = 8
FTSPI_XIPCMD_SPIMODE_DEF         = 0x00000000
# ------
# ADDR_LEN: 
# Access RW
# Number of address bytes in XIP SPI commands. 0: 3 bytes, 1: 4 bytes.
FTSPI_XIPCMD_ADDR_LEN_BIT        = 11
FTSPI_XIPCMD_ADDR_LEN_MASK       = 0x00000800
FTSPI_XIPCMD_ADDR_LEN_SH         = 11
FTSPI_XIPCMD_ADDR_LEN_DEF        = 0x00000000
# ------
# INSTR: 
# Access RW
# Instruction code. Users can set this code to execute the SPI Flash
# command for XIP read. If this byte set to 0, XIP will transfer in
# 1-bit mode.
FTSPI_XIPCMD_INSTR_BITS          = 8
FTSPI_XIPCMD_INSTR_LSB           = 12
FTSPI_XIPCMD_INSTR_MSB           = 19
FTSPI_XIPCMD_INSTR_MASK          = 0x000ff000
FTSPI_XIPCMD_INSTR_SH            = 12
FTSPI_XIPCMD_INSTR_DEF           = 0x00000003
# ------
# INSTR_DQ: 
# Access RW
# Instruction code for dual/quad mode I/O. Users have to issue the code,
# for example, 0xB0, as the mode bit because every command needs
# instruction code while the XIP port is reading.
FTSPI_XIPCMD_INSTR_DQ_BITS       = 8
FTSPI_XIPCMD_INSTR_DQ_LSB        = 20
FTSPI_XIPCMD_INSTR_DQ_MSB        = 27
FTSPI_XIPCMD_INSTR_DQ_MASK       = 0x0ff00000
FTSPI_XIPCMD_INSTR_DQ_SH         = 20
FTSPI_XIPCMD_INSTR_DQ_DEF        = 0x000000b0
# ------
# DQ_EN: 
# Access RW
# Dual/Quad Mode I/O enable.
FTSPI_XIPCMD_DQ_EN_BIT           = 28
FTSPI_XIPCMD_DQ_EN_MASK          = 0x10000000
FTSPI_XIPCMD_DQ_EN_SH            = 28
FTSPI_XIPCMD_DQ_EN_DEF           = 0x00000000
# -----------------------------------------------------------------
# ftspi XIPPFO: XIP Prefetch Function Option Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_XIPPFO                = 0x10010034
# -----------------------------------------------------------------
# ------
# BYPASS_CACHE: 
# Access RW
# Bypass the prefetch cache. When this bit is set the SPI controller
# will invalidate cache entries and reads will go straight to the SPI
# flash.
FTSPI_XIPPFO_BYPASS_CACHE_BIT    = 0
FTSPI_XIPPFO_BYPASS_CACHE_MASK   = 0x00000001
FTSPI_XIPPFO_BYPASS_CACHE_SH     = 0
FTSPI_XIPPFO_BYPASS_CACHE_DEF    = 0x00000000
# ------
# SRAM_RD_LAT: 
# Access RW
# Cache SRAM read latency in clock cycles.
FTSPI_XIPPFO_SRAM_RD_LAT_BITS    = 2
FTSPI_XIPPFO_SRAM_RD_LAT_LSB     = 1
FTSPI_XIPPFO_SRAM_RD_LAT_MSB     = 2
FTSPI_XIPPFO_SRAM_RD_LAT_MASK    = 0x00000006
FTSPI_XIPPFO_SRAM_RD_LAT_SH      = 1
FTSPI_XIPPFO_SRAM_RD_LAT_DEF     = 0x00000000
# -----------------------------------------------------------------
# ftspi RR: Revision Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_RR                    = 0x10010050
# -----------------------------------------------------------------
# ------
# REV_VER: 
# Access RO
# Revision number
FTSPI_RR_REV_VER_BITS            = 8
FTSPI_RR_REV_VER_LSB             = 0
FTSPI_RR_REV_VER_MSB             = 7
FTSPI_RR_REV_VER_MASK            = 0x000000ff
FTSPI_RR_REV_VER_SH              = 0
FTSPI_RR_REV_VER_DEF             = 0x00000000
# ------
# MINOR_VER: 
# Access RO
# Minor version number
FTSPI_RR_MINOR_VER_BITS          = 8
FTSPI_RR_MINOR_VER_LSB           = 8
FTSPI_RR_MINOR_VER_MSB           = 15
FTSPI_RR_MINOR_VER_MASK          = 0x0000ff00
FTSPI_RR_MINOR_VER_SH            = 8
FTSPI_RR_MINOR_VER_DEF           = 0x00000005
# ------
# MAJOR_VER: 
# Access RO
# Major version number
FTSPI_RR_MAJOR_VER_BITS          = 8
FTSPI_RR_MAJOR_VER_LSB           = 16
FTSPI_RR_MAJOR_VER_MSB           = 23
FTSPI_RR_MAJOR_VER_MASK          = 0x00ff0000
FTSPI_RR_MAJOR_VER_SH            = 16
FTSPI_RR_MAJOR_VER_DEF           = 0x00000001
# -----------------------------------------------------------------
# ftspi FR: Feature Register
# 
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_FR                    = 0x10010054
# -----------------------------------------------------------------
# ------
# TXFIFO_DEPTH: 
# Access RO
# Tx FIFO Depth in Words.
FTSPI_FR_TXFIFO_DEPTH_BITS       = 8
FTSPI_FR_TXFIFO_DEPTH_LSB        = 0
FTSPI_FR_TXFIFO_DEPTH_MSB        = 7
FTSPI_FR_TXFIFO_DEPTH_MASK       = 0x000000ff
FTSPI_FR_TXFIFO_DEPTH_SH         = 0
FTSPI_FR_TXFIFO_DEPTH_DEF        = 0x00000020
# ------
# RXFIFO_DEPTH: 
# Access RO
# Rx FIFO Depth in Words.
FTSPI_FR_RXFIFO_DEPTH_BITS       = 8
FTSPI_FR_RXFIFO_DEPTH_LSB        = 8
FTSPI_FR_RXFIFO_DEPTH_MSB        = 15
FTSPI_FR_RXFIFO_DEPTH_MASK       = 0x0000ff00
FTSPI_FR_RXFIFO_DEPTH_SH         = 8
FTSPI_FR_RXFIFO_DEPTH_DEF        = 0x00000020
# ------
# IDW: 
# Access RO
# AXI Bus ID Width. Not meaningful since the SPI is on the AHB bus.
FTSPI_FR_IDW_BITS                = 5
FTSPI_FR_IDW_LSB                 = 19
FTSPI_FR_IDW_MSB                 = 23
FTSPI_FR_IDW_MASK                = 0x00f80000
FTSPI_FR_IDW_SH                  = 19
FTSPI_FR_IDW_DEF                 = 0x00000008
# ------
# DTR: 
# Access RO
# DTR mode available.
FTSPI_FR_DTR_BIT                 = 24
FTSPI_FR_DTR_MASK                = 0x01000000
FTSPI_FR_DTR_SH                  = 24
FTSPI_FR_DTR_DEF                 = 0x00000001
# ------
# CLK: 
# Access RO
# System and SPI clocks are asynchronous.
FTSPI_FR_CLK_BIT                 = 25
FTSPI_FR_CLK_MASK                = 0x02000000
FTSPI_FR_CLK_SH                  = 25
FTSPI_FR_CLK_DEF                 = 0x00000000
# ------
# XIP: 
# Access RO
# XIP mode available.
FTSPI_FR_XIP_BIT                 = 29
FTSPI_FR_XIP_MASK                = 0x20000000
FTSPI_FR_XIP_SH                  = 29
FTSPI_FR_XIP_DEF                 = 0x00000000
# ------
# DW: 
# Access RO
# Data bus width is 32 bits.
FTSPI_FR_DW_BIT                  = 30
FTSPI_FR_DW_MASK                 = 0x40000000
FTSPI_FR_DW_SH                   = 30
FTSPI_FR_DW_DEF                  = 0x00000000
# ------
# AHB: 
# Access RO
# The bus interface is AHB.
FTSPI_FR_AHB_BIT                 = 31
FTSPI_FR_AHB_MASK                = 0x80000000
FTSPI_FR_AHB_SH                  = 31
FTSPI_FR_AHB_DEF                 = 0x00000000
# -----------------------------------------------------------------
# ftspi DR: Data Port Register
# Data written goes into the TxFIFO for writing to SPI flash. Data read
# comes from the RxFIFO that was read from the SPI flash or cache in the
# case of prefetching.
# Access RW
# -----------------------------------------------------------------
FTSPI_ADDR_DR                    = 0x10010100
# -----------------------------------------------------------------
# ------
FTSPI_DR_BITS                    = 32
FTSPI_DR_LSB                     = 0
FTSPI_DR_MSB                     = 31
FTSPI_DR_MASK                    = 0xffffffff
FTSPI_DR_SH                      = 0
FTSPI_DR_DEF                     = 0x00000000

# =================================================================
# irom: Interal ROM High Range
# 

# =================================================================
# ftdma: Faraday FTDMAC020 DMA Controller
# The DMA controller supports two channels. The channels are serviced in
# round-robin fashion. Refer to the Ax Architecture document for more
# information about the DMA controller.
# -----------------------------------------------------------------
# ftdma INT: Interrupt Status Register
# This registers it the 'or' of INT_ABT[n], INT_ERR[n] and INT_TC[n].
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_INT                   = 0x10030000
# -----------------------------------------------------------------
# ------
# INT0: 
# Access RO
# Set when the corresponding channel has an interrupt pending.
FTDMA_INT_INT0_BITS              = 2
FTDMA_INT_INT0_LSB               = 0
FTDMA_INT_INT0_MSB               = 1
FTDMA_INT_INT0_MASK              = 0x00000003
FTDMA_INT_INT0_SH                = 0
FTDMA_INT_INT0_DEF               = 0x00000000
# -----------------------------------------------------------------
# ftdma INT_TC_ST: Interrupt Terminal Count Status Register
# This register shows the status of the DMA terminal count interrupts
# after masking. The mask bit of these interrupts is bit 0 (INT_TC_MSK)
# of the Channel Configuration register (Cn_CFG). If this mask bit is
# set, the content of this register is always ?0? regardless of the
# presence of a pending DMA terminal count interrupt.
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_INT_TC_ST             = 0x10030004
# -----------------------------------------------------------------
# ------
# INT0: 
# Access RO
# Set when bit corresponding to channel has a terminal count interrupt
# pending.
FTDMA_INT_TC_ST_INT0_BITS        = 2
FTDMA_INT_TC_ST_INT0_LSB         = 0
FTDMA_INT_TC_ST_INT0_MSB         = 1
FTDMA_INT_TC_ST_INT0_MASK        = 0x00000003
FTDMA_INT_TC_ST_INT0_SH          = 0
FTDMA_INT_TC_ST_INT0_DEF         = 0x00000000
# -----------------------------------------------------------------
# ftdma INT_TC_CLR: Interrupt Terminal Count Clear Register
# Writing 1 to bit n of this register clears both INT_TC[n] and TC[n].
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_INT_TC_CLR            = 0x10030008
# -----------------------------------------------------------------
# ------
# INT0: 
# Access W1C
# Clear terminal count interrupt corresponding to bit set to 1.
FTDMA_INT_TC_CLR_INT0_BITS       = 2
FTDMA_INT_TC_CLR_INT0_LSB        = 0
FTDMA_INT_TC_CLR_INT0_MSB        = 1
FTDMA_INT_TC_CLR_INT0_MASK       = 0x00000003
FTDMA_INT_TC_CLR_INT0_SH         = 0
FTDMA_INT_TC_CLR_INT0_DEF        = 0x00000000
# -----------------------------------------------------------------
# ftdma INT_ERRABT_ST: Interrupt Error/Abort Status Register
# INT_ERR is the status of the DMA error interrupts after masking. The
# mask bit of these interrupts is bit 1 (INT_ERR_MSK) of the channel
# configuration register (Cn_CFG). If this mask bit is set, the content
# of INT_ERR[n] of this register will always be ?0? regardless of the
# presence of a pending DMA error interrupt. If an AHB ERROR response
# happens during the DMA transfer, the DMA controller will stop the
# current DMA transfer and will set ERR[n] to 1. Then, if INT_ERR_MSK is
# not set, the DMA controller will set INT_ERR[n] to 1 and assert the
# dmaint_err and dmaint interrupts. INT_ABT is the status of the DMA
# abort interrupts after masking. The mask bit of these interrupts is
# bit 2 (INT_ABT_MSK) of the channel configuration register (Cn_CFG). If
# this mask bit is set, the content of INT_ABT[n] of this register will
# always be 0, regardless of the presence of a pending DMA abort
# interrupt. If the ABT bit (Bit 15 of the channel control register
# (Cn_CSR)) is set, the DMA controller will stop the current DMA
# transfer and set ABT[n] to 1. Then, if INT_ABT_MSK is not set, the DMA
# controller will set INT_ABT[n] to 1 and assert the dmaint interrupt.
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_INT_ERRABT_ST         = 0x1003000c
# -----------------------------------------------------------------
# ------
# INT_ERR: 
# Access RO
# Set when the corresponding channel has an error interrupt pending.
FTDMA_INT_ERRABT_ST_INT_ERR_BITS = 2
FTDMA_INT_ERRABT_ST_INT_ERR_LSB  = 0
FTDMA_INT_ERRABT_ST_INT_ERR_MSB  = 1
FTDMA_INT_ERRABT_ST_INT_ERR_MASK = 0x00000003
FTDMA_INT_ERRABT_ST_INT_ERR_SH   = 0
FTDMA_INT_ERRABT_ST_INT_ERR_DEF  = 0x00000000
# ------
# INT_ABT: 
# Access RO
# Set when the corresponding channel has an abort interrupt pending.
FTDMA_INT_ERRABT_ST_INT_ABT_BITS = 2
FTDMA_INT_ERRABT_ST_INT_ABT_LSB  = 16
FTDMA_INT_ERRABT_ST_INT_ABT_MSB  = 17
FTDMA_INT_ERRABT_ST_INT_ABT_MASK = 0x00030000
FTDMA_INT_ERRABT_ST_INT_ABT_SH   = 16
FTDMA_INT_ERRABT_ST_INT_ABT_DEF  = 0x00000000
# -----------------------------------------------------------------
# ftdma INT_ERRABT_CLR: Interrupt Error/Abort Clear Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_INT_ERRABT_CLR        = 0x10030010
# -----------------------------------------------------------------
# ------
# INT_ERR_CLR: 
# Access W1C
# Write 1 to clear the corresponding bit.
FTDMA_INT_ERRABT_CLR_INT_ERR_CLR_BITS = 2
FTDMA_INT_ERRABT_CLR_INT_ERR_CLR_LSB = 0
FTDMA_INT_ERRABT_CLR_INT_ERR_CLR_MSB = 1
FTDMA_INT_ERRABT_CLR_INT_ERR_CLR_MASK = 0x00000003
FTDMA_INT_ERRABT_CLR_INT_ERR_CLR_SH = 0
FTDMA_INT_ERRABT_CLR_INT_ERR_CLR_DEF = 0x00000000
# ------
# INT_ABT_CLR: 
# Access W1C
# Write 1 to clear the corresponding bit.
FTDMA_INT_ERRABT_CLR_INT_ABT_CLR_BITS = 2
FTDMA_INT_ERRABT_CLR_INT_ABT_CLR_LSB = 16
FTDMA_INT_ERRABT_CLR_INT_ABT_CLR_MSB = 17
FTDMA_INT_ERRABT_CLR_INT_ABT_CLR_MASK = 0x00030000
FTDMA_INT_ERRABT_CLR_INT_ABT_CLR_SH = 16
FTDMA_INT_ERRABT_CLR_INT_ABT_CLR_DEF = 0x00000000
# -----------------------------------------------------------------
# ftdma TC: Terminal Count Register
# This register shows the status of the DMA terminal count after
# masking. The mask bit for the DMA terminal count is bit 31 (TC_MSK) of
# the channel control register (Cn_CSR). If this mask bit of the Cn_CSR
# register is set, TC[n] of this register will always be 0 regardless of
# the presence of a DMA terminal count.
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_TC                    = 0x10030014
# -----------------------------------------------------------------
# ------
# TC: 
# Access RO
# Bit is set when the corresponding channel has reached its terminal
# count.
FTDMA_TC_TC_BITS                 = 2
FTDMA_TC_TC_LSB                  = 0
FTDMA_TC_TC_MSB                  = 1
FTDMA_TC_TC_MASK                 = 0x00000003
FTDMA_TC_TC_SH                   = 0
FTDMA_TC_TC_DEF                  = 0x00000000
# -----------------------------------------------------------------
# ftdma ERRABT_ST: Error/Abort Status Register Register
# ERR is the status of the DMA error. If an AHB ERROR response happens
# during a DMA transfer, the DMA controller will stop the current DMA
# transfer and set ERR[n] to 1. If INT_ERR_MSK is not set, the DMA
# controller will set INT_ERR[n] to 1 and assert both the dmaint_err and
# dmaint interrupts. ABT is the status of the DMA abort. If the ABT bit
# (Bit 15 of the Channel Control register (Cn_CSR)) is set, the DMA
# controller will stop the current DMA transfer and set ABT[n] to 1. If
# INT_ABT_MSK is not set, the DMA controller will set INT_ABT[n] to 1
# and assert the dmaint interrupt.
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_ERRABT_ST             = 0x10030018
# -----------------------------------------------------------------
# ------
# ERR: 
# Access RO
# Set when the corresponding channel has an error.
FTDMA_ERRABT_ST_ERR_BITS         = 2
FTDMA_ERRABT_ST_ERR_LSB          = 0
FTDMA_ERRABT_ST_ERR_MSB          = 1
FTDMA_ERRABT_ST_ERR_MASK         = 0x00000003
FTDMA_ERRABT_ST_ERR_SH           = 0
FTDMA_ERRABT_ST_ERR_DEF          = 0x00000000
# ------
# ABT: 
# Access RO
# Set when the corresponding channel was aborted.
FTDMA_ERRABT_ST_ABT_BITS         = 2
FTDMA_ERRABT_ST_ABT_LSB          = 16
FTDMA_ERRABT_ST_ABT_MSB          = 17
FTDMA_ERRABT_ST_ABT_MASK         = 0x00030000
FTDMA_ERRABT_ST_ABT_SH           = 16
FTDMA_ERRABT_ST_ABT_DEF          = 0x00000000
# -----------------------------------------------------------------
# ftdma CH_EN: Channel Enable Status Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_CH_EN                 = 0x1003001c
# -----------------------------------------------------------------
# ------
# CH_EN: 
# Access RO
# Set when the corresponding channel is enabled.
FTDMA_CH_EN_CH_EN_BITS           = 2
FTDMA_CH_EN_CH_EN_LSB            = 0
FTDMA_CH_EN_CH_EN_MSB            = 1
FTDMA_CH_EN_CH_EN_MASK           = 0x00000003
FTDMA_CH_EN_CH_EN_SH             = 0
FTDMA_CH_EN_CH_EN_DEF            = 0x00000000
# -----------------------------------------------------------------
# ftdma CH_BUSY: Channel Busy Status  Register
# Care should be exercised when using the busy bit to determine if the
# DMA controller is finished. It is possible that the CPU will read the
# DMA busy bit as not active, before the DMA controller has started and
# actually set the bit. It is recommended to use the Terminal Count
# status instead.
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_CH_BUSY               = 0x10030020
# -----------------------------------------------------------------
# ------
# CH_EN: 
# Access RO
# Set when the corresponding channel is busy.
FTDMA_CH_BUSY_CH_EN_BITS         = 2
FTDMA_CH_BUSY_CH_EN_LSB          = 0
FTDMA_CH_BUSY_CH_EN_MSB          = 1
FTDMA_CH_BUSY_CH_EN_MASK         = 0x00000003
FTDMA_CH_BUSY_CH_EN_SH           = 0
FTDMA_CH_BUSY_CH_EN_DEF          = 0x00000000
# -----------------------------------------------------------------
# ftdma CSR: Configuration Status  Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_CSR                   = 0x10030024
# -----------------------------------------------------------------
# ------
# DMACEN: 
# Access RW
# Set to enable the DMA controller.
FTDMA_CSR_DMACEN_BIT             = 0
FTDMA_CSR_DMACEN_MASK            = 0x00000001
FTDMA_CSR_DMACEN_SH              = 0
FTDMA_CSR_DMACEN_DEF             = 0x00000000
# ------
# M0ENDIAN: 
# Access RW
# Write 0 for Little Endian bus format. Only Little Endian is supported.
FTDMA_CSR_M0ENDIAN_BIT           = 1
FTDMA_CSR_M0ENDIAN_MASK          = 0x00000002
FTDMA_CSR_M0ENDIAN_SH            = 1
FTDMA_CSR_M0ENDIAN_DEF           = 0x00000000
# -----------------------------------------------------------------
# ftdma SYNC: Sync Register
# The synchronization register is used to control the internal
# synchronization logic of the DMA controller for the hardware DMA
# request. To use HW Handshake Mode this bit must set, because the UART
# and SPI Flash run at different speeds.
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_SYNC                  = 0x10030028
# -----------------------------------------------------------------
# ------
# SYNC: 
# Access RW
# Set to enable sync logic.
FTDMA_SYNC_SYNC_BIT              = 0
FTDMA_SYNC_SYNC_MASK             = 0x00000001
FTDMA_SYNC_SYNC_SH               = 0
FTDMA_SYNC_SYNC_DEF              = 0x00000000
# -----------------------------------------------------------------
# ftdma REVISION: DMA Controller Revision Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_REVISION              = 0x10030030
# -----------------------------------------------------------------
# ------
# REL_REV: 
# Access RO
# Release revision number.
FTDMA_REVISION_REL_REV_BITS      = 8
FTDMA_REVISION_REL_REV_LSB       = 0
FTDMA_REVISION_REL_REV_MSB       = 7
FTDMA_REVISION_REL_REV_MASK      = 0x000000ff
FTDMA_REVISION_REL_REV_SH        = 0
FTDMA_REVISION_REL_REV_DEF       = 0x00000000
# ------
# MIN_REV: 
# Access RO
# Minor revision number.
FTDMA_REVISION_MIN_REV_BITS      = 8
FTDMA_REVISION_MIN_REV_LSB       = 8
FTDMA_REVISION_MIN_REV_MSB       = 15
FTDMA_REVISION_MIN_REV_MASK      = 0x0000ff00
FTDMA_REVISION_MIN_REV_SH        = 8
FTDMA_REVISION_MIN_REV_DEF       = 0x00000019
# ------
# MAJ_REV: 
# Access RO
# Major revision number.
FTDMA_REVISION_MAJ_REV_BITS      = 8
FTDMA_REVISION_MAJ_REV_LSB       = 16
FTDMA_REVISION_MAJ_REV_MSB       = 23
FTDMA_REVISION_MAJ_REV_MASK      = 0x00ff0000
FTDMA_REVISION_MAJ_REV_SH        = 16
FTDMA_REVISION_MAJ_REV_DEF       = 0x00000001
# -----------------------------------------------------------------
# ftdma FEATURE: DMA Controller Feature Register
# Since the DMA controller is highly configurable, the individual
# function of the DMA controller can be enabled or disabled before
# synthesizing a real design. This register reflects the actual
# configuration of the HW.
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_FEATURE               = 0x10030034
# -----------------------------------------------------------------
# ------
# FF_ADD_WIDTH: 
# Access RO
# FIFO RAM address width.
FTDMA_FEATURE_FF_ADD_WIDTH_BITS  = 4
FTDMA_FEATURE_FF_ADD_WIDTH_LSB   = 0
FTDMA_FEATURE_FF_ADD_WIDTH_MSB   = 3
FTDMA_FEATURE_FF_ADD_WIDTH_MASK  = 0x0000000f
FTDMA_FEATURE_FF_ADD_WIDTH_SH    = 0
FTDMA_FEATURE_FF_ADD_WIDTH_DEF   = 0x00000003
# ------
# LINKLIST_YES: 
# Access RO
# Design supports chained DMA mode.
FTDMA_FEATURE_LINKLIST_YES_BIT   = 8
FTDMA_FEATURE_LINKLIST_YES_MASK  = 0x00000100
FTDMA_FEATURE_LINKLIST_YES_SH    = 8
FTDMA_FEATURE_LINKLIST_YES_DEF   = 0x00000001
# ------
# AHB1_YES: 
# Access RO
# Design does not support second AHB.
FTDMA_FEATURE_AHB1_YES_BIT       = 9
FTDMA_FEATURE_AHB1_YES_MASK      = 0x00000200
FTDMA_FEATURE_AHB1_YES_SH        = 9
FTDMA_FEATURE_AHB1_YES_DEF       = 0x00000000
# ------
# MAX_CHNO_N: 
# Access RO
# Design supports two channels.
FTDMA_FEATURE_MAX_CHNO_N_BITS    = 4
FTDMA_FEATURE_MAX_CHNO_N_LSB     = 12
FTDMA_FEATURE_MAX_CHNO_N_MSB     = 15
FTDMA_FEATURE_MAX_CHNO_N_MASK    = 0x0000f000
FTDMA_FEATURE_MAX_CHNO_N_SH      = 12
FTDMA_FEATURE_MAX_CHNO_N_DEF     = 0x00000002
# -----------------------------------------------------------------
# ftdma C0_CSR: Channel 0 Control Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_C0_CSR                = 0x10030100
# -----------------------------------------------------------------
# ------
# CH_EN: 
# Access RW
# Set to enable this channel.
FTDMA_C0_CSR_CH_EN_BIT           = 0
FTDMA_C0_CSR_CH_EN_MASK          = 0x00000001
FTDMA_C0_CSR_CH_EN_SH            = 0
FTDMA_C0_CSR_CH_EN_DEF           = 0x00000000
# ------
# DST_SEL: 
# Access RW
# Always set to 0, because a second AHB is not enabled for this design.
FTDMA_C0_CSR_DST_SEL_BIT         = 1
FTDMA_C0_CSR_DST_SEL_MASK        = 0x00000002
FTDMA_C0_CSR_DST_SEL_SH          = 1
FTDMA_C0_CSR_DST_SEL_DEF         = 0x00000000
# ------
# SRC_SEL: 
# Access RW
# Always set to 0, because a second AHB is not enabled for this design.
FTDMA_C0_CSR_SRC_SEL_BIT         = 2
FTDMA_C0_CSR_SRC_SEL_MASK        = 0x00000004
FTDMA_C0_CSR_SRC_SEL_SH          = 2
FTDMA_C0_CSR_SRC_SEL_DEF         = 0x00000000
# ------
# DSTAD_CTL: 
# Access RW
# Destination Address Control. 00: Increment, 01: Decrement, 10: Fixed,
# 11: Reserved.
FTDMA_C0_CSR_DSTAD_CTL_BITS      = 2
FTDMA_C0_CSR_DSTAD_CTL_LSB       = 3
FTDMA_C0_CSR_DSTAD_CTL_MSB       = 4
FTDMA_C0_CSR_DSTAD_CTL_MASK      = 0x00000018
FTDMA_C0_CSR_DSTAD_CTL_SH        = 3
FTDMA_C0_CSR_DSTAD_CTL_DEF       = 0x00000000
# ------
# SRCAD_CTL: 
# Access RW
# Destination Address Control. 00: Increment, 01: Decrement, 10: Fixed,
# 11: Reserved.
FTDMA_C0_CSR_SRCAD_CTL_BITS      = 2
FTDMA_C0_CSR_SRCAD_CTL_LSB       = 5
FTDMA_C0_CSR_SRCAD_CTL_MSB       = 6
FTDMA_C0_CSR_SRCAD_CTL_MASK      = 0x00000060
FTDMA_C0_CSR_SRCAD_CTL_SH        = 5
FTDMA_C0_CSR_SRCAD_CTL_DEF       = 0x00000000
# ------
# MODE: 
# Access RW
# 0: Normal DMA Mode, 1: HW Handshake Mode.
FTDMA_C0_CSR_MODE_BIT            = 7
FTDMA_C0_CSR_MODE_MASK           = 0x00000080
FTDMA_C0_CSR_MODE_SH             = 7
FTDMA_C0_CSR_MODE_DEF            = 0x00000000
# ------
# DST_WIDTH: 
# Access RW
# Destination transfer bit width. 000: 8, 001: 16, 010: 32, Others:
# Reserved. Hardware will automatically pack and unpack data as
# required. Notes: 1. If source transfer width < destination transfer
# width, DMA will pack the source input data. For example, if the source
# transfer width equals to 8 bits and the destination transfer width
# equals to 32 bits, then DMA will pack four sets of 8-bit source data
# and transfer one set of 32-bit data to destination. Limitation: Do not
# set DSTAD_CTL to '01'? (Decrement source address) when the pack
# function works; otherwise DMA will have a wrong action. 2. If source
# transfer width > destination transfer width, DMA will unpack the
# source input data. For example, if the source transfer width equals to
# 32 bits and the destination transfer width equals to 8 bits, then DMA
# will unpack the source of 32-bit data and transfer four sets of 8-bit
# data to destination.
FTDMA_C0_CSR_DST_WIDTH_BITS      = 3
FTDMA_C0_CSR_DST_WIDTH_LSB       = 8
FTDMA_C0_CSR_DST_WIDTH_MSB       = 10
FTDMA_C0_CSR_DST_WIDTH_MASK      = 0x00000700
FTDMA_C0_CSR_DST_WIDTH_SH        = 8
FTDMA_C0_CSR_DST_WIDTH_DEF       = 0x00000002
# ------
# SRC_WIDTH: 
# Access RW
# Source transfer bit width. Handle the same as dst_width.
FTDMA_C0_CSR_SRC_WIDTH_BITS      = 3
FTDMA_C0_CSR_SRC_WIDTH_LSB       = 11
FTDMA_C0_CSR_SRC_WIDTH_MSB       = 13
FTDMA_C0_CSR_SRC_WIDTH_MASK      = 0x00003800
FTDMA_C0_CSR_SRC_WIDTH_SH        = 11
FTDMA_C0_CSR_SRC_WIDTH_DEF       = 0x00000002
# ------
# ABT: 
# Access W1C
# Transaction Abort. Writing 1 to this bit causes DMA to stop the
# current transfer, then set the ABT[n] bit of the Error/Abort Status
# register and assert the dmaint interrupt if INT_ABT_MSK = 0. Note:
# When writing 1 to bit 15 (ABT), all other bits of this register will
# remain the same. That is, users cannot program bit 15 to bit 1 and
# other bits of this register simultaneously.
FTDMA_C0_CSR_ABT_BIT             = 15
FTDMA_C0_CSR_ABT_MASK            = 0x00008000
FTDMA_C0_CSR_ABT_SH              = 15
FTDMA_C0_CSR_ABT_DEF             = 0x00000000
# ------
# SRC_SIZE: 
# Access RW
# Source burst size is the number of transfers the DMA controller should
# move before re-arbitrating. 0: 1, 1: 4, 2: 8, 3: 16, 4: 32, 5: 64, 6:
# 128, 7: 256. Burst size * SRC_WIDTH) must be equal to or larger than
# DST_WIDTH.
FTDMA_C0_CSR_SRC_SIZE_BITS       = 3
FTDMA_C0_CSR_SRC_SIZE_LSB        = 16
FTDMA_C0_CSR_SRC_SIZE_MSB        = 18
FTDMA_C0_CSR_SRC_SIZE_MASK       = 0x00070000
FTDMA_C0_CSR_SRC_SIZE_SH         = 16
FTDMA_C0_CSR_SRC_SIZE_DEF        = 0x00000000
# ------
# PROT1: 
# Access RW
# Memory Protection Settings. 0: User Mode, 1: Privileged Mode.
FTDMA_C0_CSR_PROT1_BIT           = 19
FTDMA_C0_CSR_PROT1_MASK          = 0x00080000
FTDMA_C0_CSR_PROT1_SH            = 19
FTDMA_C0_CSR_PROT1_DEF           = 0x00000000
# ------
# PROT2: 
# Access RW
# Memory Protection Settings. 0: Not bufferable, 1: Bufferable.
FTDMA_C0_CSR_PROT2_BIT           = 20
FTDMA_C0_CSR_PROT2_MASK          = 0x00100000
FTDMA_C0_CSR_PROT2_SH            = 20
FTDMA_C0_CSR_PROT2_DEF           = 0x00000000
# ------
# PROT3: 
# Access RW
# Memory Protection Settings. 0: Not cacheable, 1: Cacheable.
FTDMA_C0_CSR_PROT3_BIT           = 21
FTDMA_C0_CSR_PROT3_MASK          = 0x00200000
FTDMA_C0_CSR_PROT3_SH            = 21
FTDMA_C0_CSR_PROT3_DEF           = 0x00000000
# ------
# DMA_FF_TH: 
# Access RW
# DMA FIFO Threshold Value. DMAC waits until there is at least this much
# space in FIFO before fetching and waits until there are at least this
# many words in the FIFO before beginning a write to the destination.
# Threshold = 1 << DMA_FF_TH.
FTDMA_C0_CSR_DMA_FF_TH_BITS      = 3
FTDMA_C0_CSR_DMA_FF_TH_LSB       = 24
FTDMA_C0_CSR_DMA_FF_TH_MSB       = 26
FTDMA_C0_CSR_DMA_FF_TH_MASK      = 0x07000000
FTDMA_C0_CSR_DMA_FF_TH_SH        = 24
FTDMA_C0_CSR_DMA_FF_TH_DEF       = 0x00000000
# ------
# TC_MSK: 
# Access RW
# Terminal Count Status Mask. 0: When the terminal count is reached, the
# TC status register will be set, 1: When the terminal count is reached
# the TC status register is not set.
FTDMA_C0_CSR_TC_MSK_BIT          = 31
FTDMA_C0_CSR_TC_MSK_MASK         = 0x80000000
FTDMA_C0_CSR_TC_MSK_SH           = 31
FTDMA_C0_CSR_TC_MSK_DEF          = 0x00000000
# -----------------------------------------------------------------
# ftdma C0_CFG: Channel 0 Configuration Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_C0_CFG                = 0x10030104
# -----------------------------------------------------------------
# ------
# INT_TC_MSK: 
# Access RW
# Set to mask terminal count interrupt.
FTDMA_C0_CFG_INT_TC_MSK_BIT      = 0
FTDMA_C0_CFG_INT_TC_MSK_MASK     = 0x00000001
FTDMA_C0_CFG_INT_TC_MSK_SH       = 0
FTDMA_C0_CFG_INT_TC_MSK_DEF      = 0x00000001
# ------
# INT_ERR_MSK: 
# Access RW
# Set to mask error interrupt.
FTDMA_C0_CFG_INT_ERR_MSK_BIT     = 1
FTDMA_C0_CFG_INT_ERR_MSK_MASK    = 0x00000002
FTDMA_C0_CFG_INT_ERR_MSK_SH      = 1
FTDMA_C0_CFG_INT_ERR_MSK_DEF     = 0x00000001
# ------
# INT_ABT_MSK: 
# Access RW
# Set to mask abort interrupt.
FTDMA_C0_CFG_INT_ABT_MSK_BIT     = 2
FTDMA_C0_CFG_INT_ABT_MSK_MASK    = 0x00000004
FTDMA_C0_CFG_INT_ABT_MSK_SH      = 2
FTDMA_C0_CFG_INT_ABT_MSK_DEF     = 0x00000001
# ------
# SRC_RS: 
# Access RW
# Source DMA request select. It specifies the dma_req source and can
# only be used when the DMA hardware handshake mode is enabled. 0: SPI
# Flash, 1: UART Tx, 2: UART Rx.
FTDMA_C0_CFG_SRC_RS_BITS         = 4
FTDMA_C0_CFG_SRC_RS_LSB          = 3
FTDMA_C0_CFG_SRC_RS_MSB          = 6
FTDMA_C0_CFG_SRC_RS_MASK         = 0x00000078
FTDMA_C0_CFG_SRC_RS_SH           = 3
FTDMA_C0_CFG_SRC_RS_DEF          = 0x00000000
# ------
# SRC_HE: 
# Access RW
# Source HW Handshake Mode enable. When users disable the destination
# hardware handshake, DMA will start transferring data without waiting
# for the destination request. This bit will be only valid when DMAC is
# in the hardware handshake mode.
FTDMA_C0_CFG_SRC_HE_BIT          = 7
FTDMA_C0_CFG_SRC_HE_MASK         = 0x00000080
FTDMA_C0_CFG_SRC_HE_SH           = 7
FTDMA_C0_CFG_SRC_HE_DEF          = 0x00000001
# ------
# BUSY: 
# Access RO
# The DMA channel is busy. Care should be exercised when using the busy
# bit to determine if the DMA controller is finished. It is possible
# that the CPU will read the DMA busy bit as not active, before the DMA
# controller has started and actually set the bit. It is recommended to
# use the Terminal Count status instead.
FTDMA_C0_CFG_BUSY_BIT            = 8
FTDMA_C0_CFG_BUSY_MASK           = 0x00000100
FTDMA_C0_CFG_BUSY_SH             = 8
FTDMA_C0_CFG_BUSY_DEF            = 0x00000000
# ------
# DST_RS: 
# Access RW
# Destination DMA request select.  It specifies the dma_req destination
# and can only be used when the DMA hardware handshake mode is enabled.
# 0: SPI Flash, 1: UART Tx, 2: UART Rx.
FTDMA_C0_CFG_DST_RS_BITS         = 4
FTDMA_C0_CFG_DST_RS_LSB          = 9
FTDMA_C0_CFG_DST_RS_MSB          = 12
FTDMA_C0_CFG_DST_RS_MASK         = 0x00001e00
FTDMA_C0_CFG_DST_RS_SH           = 9
FTDMA_C0_CFG_DST_RS_DEF          = 0x00000000
# ------
# DST_HE: 
# Access RW
# Destination HW Handshake Mode enable. When users disable the source
# hardware handshake, DMA will start transferring data without waiting
# for the source request. This bit will be only valid when DMAC is in
# the hardware handshake mode.
FTDMA_C0_CFG_DST_HE_BIT          = 13
FTDMA_C0_CFG_DST_HE_MASK         = 0x00002000
FTDMA_C0_CFG_DST_HE_SH           = 13
FTDMA_C0_CFG_DST_HE_DEF          = 0x00000001
# ------
# LLP_CNT: 
# Access RO
# Chain transfer counter. This counter is reset to 0 when CH_EN changes
# from 0 to 1. If the chain transfer is enabled after each block data
# transfer is finished, LLP_CNT will be increased by 1.
FTDMA_C0_CFG_LLP_CNT_BITS        = 4
FTDMA_C0_CFG_LLP_CNT_LSB         = 16
FTDMA_C0_CFG_LLP_CNT_MSB         = 19
FTDMA_C0_CFG_LLP_CNT_MASK        = 0x000f0000
FTDMA_C0_CFG_LLP_CNT_SH          = 16
FTDMA_C0_CFG_LLP_CNT_DEF         = 0x00000000
# -----------------------------------------------------------------
# ftdma C0_SRCADDR: Channel 0 Source Address Register
# Source starting address. Note that when the DMA transaction is
# complete, its value will reflect the DMA source ending address.
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_C0_SRCADDR            = 0x10030108
# -----------------------------------------------------------------
# ------
FTDMA_C0_SRCADDR_BITS            = 32
FTDMA_C0_SRCADDR_LSB             = 0
FTDMA_C0_SRCADDR_MSB             = 31
FTDMA_C0_SRCADDR_MASK            = 0xffffffff
FTDMA_C0_SRCADDR_SH              = 0
FTDMA_C0_SRCADDR_DEF             = 0x00000000
# -----------------------------------------------------------------
# ftdma C0_DSTADDR: Channel 0 Destination Address Register
# Destination starting address. Note that when the DMA transaction is
# complete, its value will reflect the DMA destination ending address.
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_C0_DSTADDR            = 0x1003010c
# -----------------------------------------------------------------
# ------
FTDMA_C0_DSTADDR_BITS            = 32
FTDMA_C0_DSTADDR_LSB             = 0
FTDMA_C0_DSTADDR_MSB             = 31
FTDMA_C0_DSTADDR_MASK            = 0xffffffff
FTDMA_C0_DSTADDR_SH              = 0
FTDMA_C0_DSTADDR_DEF             = 0x00000000
# -----------------------------------------------------------------
# ftdma C0_LLP: Channel 0 Link List Pointer Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_C0_LLP                = 0x10030110
# -----------------------------------------------------------------
# ------
# LLP_MASTER: 
# Access RW
# Master for loading the next LLP. Always 0 for the Ax design.
FTDMA_C0_LLP_LLP_MASTER_BIT      = 0
FTDMA_C0_LLP_LLP_MASTER_MASK     = 0x00000001
FTDMA_C0_LLP_LLP_MASTER_SH       = 0
FTDMA_C0_LLP_LLP_MASTER_DEF      = 0x00000000
# ------
# LLP_ADDR: 
# Access RW
# Linked list pointer address. This field specifies the upper 30 bits of
# the address. The lower 2 bits are assumed to be 0.
FTDMA_C0_LLP_LLP_ADDR_BITS       = 30
FTDMA_C0_LLP_LLP_ADDR_LSB        = 2
FTDMA_C0_LLP_LLP_ADDR_MSB        = 31
FTDMA_C0_LLP_LLP_ADDR_MASK       = 0xfffffffc
FTDMA_C0_LLP_LLP_ADDR_SH         = 2
FTDMA_C0_LLP_LLP_ADDR_DEF        = 0x00000000
# -----------------------------------------------------------------
# ftdma C0_SIZE: Channel 0 Transfer Size Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_C0_SIZE               = 0x10030114
# -----------------------------------------------------------------
# ------
# TOT_SIZE: 
# Access RW
# Total transfer beats of the bus size. When the transfer is complete
# this register should read as 0.
FTDMA_C0_SIZE_TOT_SIZE_BITS      = 22
FTDMA_C0_SIZE_TOT_SIZE_LSB       = 0
FTDMA_C0_SIZE_TOT_SIZE_MSB       = 21
FTDMA_C0_SIZE_TOT_SIZE_MASK      = 0x003fffff
FTDMA_C0_SIZE_TOT_SIZE_SH        = 0
FTDMA_C0_SIZE_TOT_SIZE_DEF       = 0x00000000
# -----------------------------------------------------------------
# ftdma C1_CSR: Channel 1 Control Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_C1_CSR                = 0x10030120
# -----------------------------------------------------------------
# ------
# CH_EN: 
# Access RW
# Set to enable this channel.
FTDMA_C1_CSR_CH_EN_BIT           = 0
FTDMA_C1_CSR_CH_EN_MASK          = 0x00000001
FTDMA_C1_CSR_CH_EN_SH            = 0
FTDMA_C1_CSR_CH_EN_DEF           = 0x00000000
# ------
# DST_SEL: 
# Access RW
# Always set to 0, because a second AHB is not enabled for this design.
FTDMA_C1_CSR_DST_SEL_BIT         = 1
FTDMA_C1_CSR_DST_SEL_MASK        = 0x00000002
FTDMA_C1_CSR_DST_SEL_SH          = 1
FTDMA_C1_CSR_DST_SEL_DEF         = 0x00000000
# ------
# SRC_SEL: 
# Access RW
# Always set to 0, because a second AHB is not enabled for this design.
FTDMA_C1_CSR_SRC_SEL_BIT         = 2
FTDMA_C1_CSR_SRC_SEL_MASK        = 0x00000004
FTDMA_C1_CSR_SRC_SEL_SH          = 2
FTDMA_C1_CSR_SRC_SEL_DEF         = 0x00000000
# ------
# DSTAD_CTL: 
# Access RW
# Destination Address Control. 00: Increment, 01: Decrement, 10: Fixed,
# 11: Reserved.
FTDMA_C1_CSR_DSTAD_CTL_BITS      = 2
FTDMA_C1_CSR_DSTAD_CTL_LSB       = 3
FTDMA_C1_CSR_DSTAD_CTL_MSB       = 4
FTDMA_C1_CSR_DSTAD_CTL_MASK      = 0x00000018
FTDMA_C1_CSR_DSTAD_CTL_SH        = 3
FTDMA_C1_CSR_DSTAD_CTL_DEF       = 0x00000000
# ------
# SRCAD_CTL: 
# Access RW
# Destination Address Control. 00: Increment, 01: Decrement, 10: Fixed,
# 11: Reserved.
FTDMA_C1_CSR_SRCAD_CTL_BITS      = 2
FTDMA_C1_CSR_SRCAD_CTL_LSB       = 5
FTDMA_C1_CSR_SRCAD_CTL_MSB       = 6
FTDMA_C1_CSR_SRCAD_CTL_MASK      = 0x00000060
FTDMA_C1_CSR_SRCAD_CTL_SH        = 5
FTDMA_C1_CSR_SRCAD_CTL_DEF       = 0x00000000
# ------
# MODE: 
# Access RW
# 0: Normal DMA Mode, 1: HW Handshake Mode.
FTDMA_C1_CSR_MODE_BIT            = 7
FTDMA_C1_CSR_MODE_MASK           = 0x00000080
FTDMA_C1_CSR_MODE_SH             = 7
FTDMA_C1_CSR_MODE_DEF            = 0x00000000
# ------
# DST_WIDTH: 
# Access RW
# Destination transfer bit width. 000: 8, 001: 16, 010: 32, Others:
# Reserved. Hardware will automatically pack and unpack data as
# required. Notes: 1. If source transfer width < destination transfer
# width, DMA will pack the source input data. For example, if the source
# transfer width equals to 8 bits and the destination transfer width
# equals to 32 bits, then DMA will pack four sets of 8-bit source data
# and transfer one set of 32-bit data to destination. Limitation: Do not
# set DSTAD_CTL to '01'? (Decrement source address) when the pack
# function works; otherwise DMA will have a wrong action. 2. If source
# transfer width > destination transfer width, DMA will unpack the
# source input data. For example, if the source transfer width equals to
# 32 bits and the destination transfer width equals to 8 bits, then DMA
# will unpack the source of 32-bit data and transfer four sets of 8-bit
# data to destination.
FTDMA_C1_CSR_DST_WIDTH_BITS      = 3
FTDMA_C1_CSR_DST_WIDTH_LSB       = 8
FTDMA_C1_CSR_DST_WIDTH_MSB       = 10
FTDMA_C1_CSR_DST_WIDTH_MASK      = 0x00000700
FTDMA_C1_CSR_DST_WIDTH_SH        = 8
FTDMA_C1_CSR_DST_WIDTH_DEF       = 0x00000002
# ------
# SRC_WIDTH: 
# Access RW
# Source transfer bit width. Handle the same as dst_width.
FTDMA_C1_CSR_SRC_WIDTH_BITS      = 3
FTDMA_C1_CSR_SRC_WIDTH_LSB       = 11
FTDMA_C1_CSR_SRC_WIDTH_MSB       = 13
FTDMA_C1_CSR_SRC_WIDTH_MASK      = 0x00003800
FTDMA_C1_CSR_SRC_WIDTH_SH        = 11
FTDMA_C1_CSR_SRC_WIDTH_DEF       = 0x00000002
# ------
# ABT: 
# Access W1C
# Transaction Abort. Writing 1 to this bit causes DMA to stop the
# current transfer, then set the ABT[n] bit of the Error/Abort Status
# register and assert the dmaint interrupt if INT_ABT_MSK = 0. Note:
# When writing 1 to bit 15 (ABT), all other bits of this register will
# remain the same. That is, users cannot program bit 15 to bit 1 and
# other bits of this register simultaneously.
FTDMA_C1_CSR_ABT_BIT             = 15
FTDMA_C1_CSR_ABT_MASK            = 0x00008000
FTDMA_C1_CSR_ABT_SH              = 15
FTDMA_C1_CSR_ABT_DEF             = 0x00000000
# ------
# SRC_SIZE: 
# Access RW
# Source burst size is the number of transfers the DMA controller should
# move before re-arbitrating. 0: 1, 1: 4, 2: 8, 3: 16, 4: 32, 5: 64, 6:
# 128, 7: 256. Burst size * SRC_WIDTH) must be equal to or larger than
# DST_WIDTH.
FTDMA_C1_CSR_SRC_SIZE_BITS       = 3
FTDMA_C1_CSR_SRC_SIZE_LSB        = 16
FTDMA_C1_CSR_SRC_SIZE_MSB        = 18
FTDMA_C1_CSR_SRC_SIZE_MASK       = 0x00070000
FTDMA_C1_CSR_SRC_SIZE_SH         = 16
FTDMA_C1_CSR_SRC_SIZE_DEF        = 0x00000000
# ------
# PROT1: 
# Access RW
# Memory Protection Settings. 0: User Mode, 1: Privileged Mode.
FTDMA_C1_CSR_PROT1_BIT           = 19
FTDMA_C1_CSR_PROT1_MASK          = 0x00080000
FTDMA_C1_CSR_PROT1_SH            = 19
FTDMA_C1_CSR_PROT1_DEF           = 0x00000000
# ------
# PROT2: 
# Access RW
# Memory Protection Settings. 0: Not bufferable, 1: Bufferable.
FTDMA_C1_CSR_PROT2_BIT           = 20
FTDMA_C1_CSR_PROT2_MASK          = 0x00100000
FTDMA_C1_CSR_PROT2_SH            = 20
FTDMA_C1_CSR_PROT2_DEF           = 0x00000000
# ------
# PROT3: 
# Access RW
# Memory Protection Settings. 0: Not cacheable, 1: Cacheable.
FTDMA_C1_CSR_PROT3_BIT           = 21
FTDMA_C1_CSR_PROT3_MASK          = 0x00200000
FTDMA_C1_CSR_PROT3_SH            = 21
FTDMA_C1_CSR_PROT3_DEF           = 0x00000000
# ------
# DMA_FF_TH: 
# Access RW
# DMA FIFO Threshold Value. DMAC waits until there is at least this much
# space in FIFO before fetching and waits until there are at least this
# many words in the FIFO before beginning a write to the destination.
# Threshold = 1 << DMA_FF_TH.
FTDMA_C1_CSR_DMA_FF_TH_BITS      = 3
FTDMA_C1_CSR_DMA_FF_TH_LSB       = 24
FTDMA_C1_CSR_DMA_FF_TH_MSB       = 26
FTDMA_C1_CSR_DMA_FF_TH_MASK      = 0x07000000
FTDMA_C1_CSR_DMA_FF_TH_SH        = 24
FTDMA_C1_CSR_DMA_FF_TH_DEF       = 0x00000000
# ------
# TC_MSK: 
# Access RW
# Terminal Count Status Mask. 0: When the terminal count is reached, the
# TC status register will be set, 1: When the terminal count is reached
# the TC status register is not set.
FTDMA_C1_CSR_TC_MSK_BIT          = 31
FTDMA_C1_CSR_TC_MSK_MASK         = 0x80000000
FTDMA_C1_CSR_TC_MSK_SH           = 31
FTDMA_C1_CSR_TC_MSK_DEF          = 0x00000000
# -----------------------------------------------------------------
# ftdma C1_CFG: Channel 1 Configuration Register
# 
# Access RW
# -----------------------------------------------------------------
FTDMA_ADDR_C1_CFG                = 0x10030124
# -----------------------------------------------------------------
# ------
# INT_TC_MSK: 
# Access RW
# Set to mask terminal count interrupt.
FTDMA_C1_CFG_INT_TC_MSK_BIT      = 0
FTDMA_C1_CFG_INT_TC_MSK_MASK     = 0x00000001
FTDMA_C1_CFG_INT_TC_MSK_SH       = 0
FTDMA_C1_CFG_INT_TC_MSK_DEF      = 0x00000001
# ------
# INT_ERR_MSK: 
# Access RW
# Set to mask error interrupt.
FTDMA_C1_CFG_INT_ERR_MSK_BIT     = 1
FTDMA_C1_CFG_INT_ERR_MSK_MASK    = 0x00000002
FTDMA_C1_CFG_INT_ERR_MSK_SH      = 1
FTDMA_C1_CFG_INT_ERR_MSK_DEF     = 0x00000001
# ------
# INT_ABT_MSK: 
# Access RW
# Set to mask abort interrupt.
FTDMA_C1_CFG_INT_ABT_MSK_BIT     = 2
FTDMA_C1_CFG_INT_ABT_MSK_MASK    = 0x00000004
FTDMA_C1_CFG_INT_ABT_MSK_SH      = 2
FTDMA_C1_CFG_INT_ABT_MSK_DEF     = 0x00000001
# ------
# SRC_RS: 
# Access RW
# Source DMA request select. It specifies the dma_req source and can
# only be used when the DMA hardware handshake mode is enabled. 0: SPI
# Flash, 1: UART Tx, 2: UART Rx.
FTDMA_C1_CFG_SRC_RS_BITS         = 4
FTDMA_C1_CFG_SRC_RS_LSB          = 3
FTDMA_C1_CFG_SRC_RS_MSB          = 6
FTDMA_C1_CFG_SRC_RS_MASK         = 0x00000078
FTDMA_C1_CFG_SRC_RS_SH           = 3
FTDMA_C1_CFG_SRC_RS_DEF          = 0x00000000
# ------
# SRC_HE: 
# Access RW
# Source HW Handshake Mode enable. When users disable the destination
# hardware handshake, DMA will start transferring data without waiting
# for the destination request. This bit will be only valid when DMAC is
# in the hardware handshake mode.
FTDMA_C1_CFG_SRC_HE_BIT          = 7
FTDMA_C1_CFG_SRC_HE_MASK         = 0x00000080
FTDMA_C1_CFG_SRC_HE_SH           = 7
FTDMA_C1_CFG_SRC_HE_DEF          = 0x00000001
# ------
# BUSY: 
# Access RO
# The DMA channel is busy. Care should be exercised when using the busy
# bit to determine if the DMA controller is finished. It is possible
# that the CPU will read the DMA busy bit as not active, before the DMA
# controller has started and actually set the bit. It is recommended to
# use the Terminal Count status instead.
FTDMA_C1_CFG_BUSY_BIT            = 8
FTDMA_C1_CFG_BUSY_MASK           = 0x00000100
FTDMA_C1_CFG_BUSY_SH             = 8
FTDMA_C1_CFG_BUSY_DEF            = 0x00000000
# ------
# DST_RS: 
# Access RW
# Destination DMA request select.  It specifies the dma_req destination
# and can only be used when the DMA hardware handshake mode is enabled.
# 0: SPI Flash, 1: UART Tx, 2: UART Rx.
FTDMA_C1_CFG_DST_RS_BITS         = 4
FTDMA_C1_CFG_DST_RS_LSB          = 9
FTDMA_C1_CFG_DST_RS_MSB          = 12
FTDMA_C1_CFG_DST_RS_MASK         = 0x00001e00
FTDMA_C1_CFG_DST_RS_SH           = 9
FTDMA_C1_CFG_DST_RS_DEF          = 0x00000000
# ------
# DST_HE: 
# Access RW
# Destination HW Handshake Mode enable. When users disable the source
# hardware handshake, DMA will start transferring data without waiting
# for the source request. This bit will be only valid when DMAC is in
# the hardware handshake mode.
FTDMA_C1_CFG_DST_HE_BIT          = 13
FTDMA_C1_CFG_DST_HE_MASK         = 0x00002000
FTDMA_C1_CFG_DST_HE_SH           = 13
FTDMA_C1_CFG_DST_HE_DEF          = 0x00000001
# ------
# LLP_CNT: 
# Access RO
# Chain transfer counter. This counter is reset to 0 when CH_EN changes
# from 0 to 1. If the chain transfer is enabled after each block data
# transfer is finished, LLP_CNT will be increased by 1.
FTDMA_C1_CFG_LLP_CNT_BITS        = 4
FTDMA_C1_CFG_LLP_CNT_LSB         = 16
FTDMA_C1_CFG_LLP_CNT_MSB         = 19
FTDMA_C1_CFG_LLP_CNT_MASK        = 0x000f0000
