# =================================================================
# ftwdt: Watch Dog Timer
# The Faraday WatchDog Timer (WDT) is used to prevent system from
# infinite loop if software gets trapped in the deadlock. Under normal
# operation, users will restart WDT at the regular intervals before
# counter counts down to 0. If the counter does reach 0, WDT will
# generate one or a combination of signals, system reset, system
# interrupt, and external interrupt to reset the system, interrupt the
# system, or interrupt an external device correspondingly. After the
# programmer turns on the enable bit of WDT in the WatchDog timer
# control register, the WDT counter starts to reduce the counting. If
# the Watch Dog timer reaches 0, the wd_rst signal, wd_intr signal, or
# wd_ext signal will be triggered. As long as the signal is set in the
# WdInstlen register, the assertion of this signal will depend on the
# WdRst, WdIntr, and WdExt bits in the WatchDog timer control register,
# the signal will keep asserted for a period of time. The WdStatus bit
# is used to check if the counter reaches 0 or not. The programmer can
# clear the WdStatus bit by writing 1 to the WdClear bit. To prevent the
# unexpected reset, the programmer needs to write 0x5AB9 to the
# WdRestart register as the password to activate the down counting
# function. If the WdRestart register equals 0x5AB9, the value of the
# WdLoad register will be loaded into the counter of the WatchDog timer.
# The default reset value of the WdRestart register is 0, and the
# WdRestart register will automatically return to 0 after each write.
# The default value of the WdLoad register is set to 0x3EF1480. The
# programmer can write this register to customize the operation of the
# WatchDog timer reset.
# -----------------------------------------------------------------
# ftwdt WDCOUNTER: Watch Dog Count Register
# WdCounter contains the current counter value. When it is reset, the
# WdCounter register will be set to 0x3EF1480. After programmers write
# 0x5AB9 to WdRestart, the value of WdLoad will be loaded into
# WdCounter. WdCounter will start to decrease once WdCR[0], and the
# WatchDog timer enable bit is set. If the WatchDog timer is disabled,
# WdCounter will hold the value. If WdCR [4] is set, the register will
# be driven by an external clock, and WdCounter will decrease at the
# EXTCLK frequency.
# Access RO
# -----------------------------------------------------------------
FTWDT_ADDR_WDCOUNTER             = 0x10110000
# -----------------------------------------------------------------
# ------
FTWDT_WDCOUNTER_BITS             = 32
FTWDT_WDCOUNTER_LSB              = 0
FTWDT_WDCOUNTER_MSB              = 31
FTWDT_WDCOUNTER_MASK             = 0xffffffff
FTWDT_WDCOUNTER_SH               = 0
FTWDT_WDCOUNTER_DEF              = 0x03ef1480
# -----------------------------------------------------------------
# ftwdt WDLOAD: Watch Dog Load Register
# WdLoad contains the value which will be loaded into WdCounter. When it
# is reset or restarted, the value of WdLoad will be automatically
# loaded into the WdCounter register.
# Access RW
# -----------------------------------------------------------------
FTWDT_ADDR_WDLOAD                = 0x10110004
# -----------------------------------------------------------------
# ------
FTWDT_WDLOAD_BITS                = 32
FTWDT_WDLOAD_LSB                 = 0
FTWDT_WDLOAD_MSB                 = 31
FTWDT_WDLOAD_MASK                = 0xffffffff
FTWDT_WDLOAD_SH                  = 0
FTWDT_WDLOAD_DEF                 = 0x03ef1480
# -----------------------------------------------------------------
# ftwdt WDRESTART: Watch Dog Restart Register
# Writing 0x5AB9 to this register causes the WatchDog timer counter to
# load WdLoad into the WdCounter register and the WatchDog timer counter
# will begin to count down. After finishing the write cycle, WdRestart
# will automatically be reset to 0.
# Access WO
# -----------------------------------------------------------------
FTWDT_ADDR_WDRESTART             = 0x10110008
# -----------------------------------------------------------------
# ------
FTWDT_WDRESTART_BITS             = 32
FTWDT_WDRESTART_LSB              = 0
FTWDT_WDRESTART_MSB              = 31
FTWDT_WDRESTART_MASK             = 0xffffffff
FTWDT_WDRESTART_SH               = 0
FTWDT_WDRESTART_DEF              = 0x00000000
# -----------------------------------------------------------------
# ftwdt WDCR: Watch Dog Control Register
# 
# Access RW
# -----------------------------------------------------------------
FTWDT_ADDR_WDCR                  = 0x1011000c
# -----------------------------------------------------------------
# ------
# ENABLE: 
# Access RW
# {0: Disabled, 1: Enabled}
FTWDT_WDCR_ENABLE_BIT            = 0
FTWDT_WDCR_ENABLE_MASK           = 0x00000001
FTWDT_WDCR_ENABLE_SH             = 0
FTWDT_WDCR_ENABLE_DEF            = 0x00000000
# ------
# RESET: 
# Access RW
# {0: normal, 1: reset}
FTWDT_WDCR_RESET_BIT             = 1
FTWDT_WDCR_RESET_MASK            = 0x00000002
FTWDT_WDCR_RESET_SH              = 1
FTWDT_WDCR_RESET_DEF             = 0x00000000
# ------
# INTR: 
# Access RW
# {0: Interrupt disabled, 1: Interrupt enabled}
FTWDT_WDCR_INTR_BIT              = 2
FTWDT_WDCR_INTR_MASK             = 0x00000004
FTWDT_WDCR_INTR_SH               = 2
FTWDT_WDCR_INTR_DEF              = 0x00000000
# ------
# CLOCK: 
# Access RW
# Clock source {0: 104/125 MHz, 1: 10 MHz}
FTWDT_WDCR_CLOCK_BIT             = 4
FTWDT_WDCR_CLOCK_MASK            = 0x00000010
FTWDT_WDCR_CLOCK_SH              = 4
FTWDT_WDCR_CLOCK_DEF             = 0x00000000
# -----------------------------------------------------------------
# ftwdt WDSTATUS: Watch Dog Status Register
# 
# Access RW
# -----------------------------------------------------------------
FTWDT_ADDR_WDSTATUS              = 0x10110010
# -----------------------------------------------------------------
# ------
# EXPIRED: 
# Access RO
# Reads 1 when the counter has counted down to 0.
FTWDT_WDSTATUS_EXPIRED_BIT       = 0
FTWDT_WDSTATUS_EXPIRED_MASK      = 0x00000001
FTWDT_WDSTATUS_EXPIRED_SH        = 0
FTWDT_WDSTATUS_EXPIRED_DEF       = 0x00000000
# -----------------------------------------------------------------
# ftwdt WDCLEAR: Watch Dog Status Clear Register
# 
# Access RW
# -----------------------------------------------------------------
FTWDT_ADDR_WDCLEAR               = 0x10110014
# -----------------------------------------------------------------
# ------
# EXPIRED: 
# Access W1C
# Write a 1 to clear the WD Status Register.
FTWDT_WDCLEAR_EXPIRED_BIT        = 0
FTWDT_WDCLEAR_EXPIRED_MASK       = 0x00000001
FTWDT_WDCLEAR_EXPIRED_SH         = 0
FTWDT_WDCLEAR_EXPIRED_DEF        = 0x00000000
# -----------------------------------------------------------------
# ftwdt WDINTRLEN: Watch Dog Interrupt Length Register
# 
# Access RW
# -----------------------------------------------------------------
FTWDT_ADDR_WDINTRLEN             = 0x10110018
# -----------------------------------------------------------------
# ------
# LENGTH: 
# Access RW
# Number of clocks the interrupt signal will be asserted when it fires.
FTWDT_WDINTRLEN_LENGTH_BITS      = 8
FTWDT_WDINTRLEN_LENGTH_LSB       = 0
FTWDT_WDINTRLEN_LENGTH_MSB       = 7
FTWDT_WDINTRLEN_LENGTH_MASK      = 0x000000ff
FTWDT_WDINTRLEN_LENGTH_SH        = 0
FTWDT_WDINTRLEN_LENGTH_DEF       = 0x00000000
# -----------------------------------------------------------------
# ftwdt REV: Watch Dog Revision Register
# 
# Access RO
# -----------------------------------------------------------------
FTWDT_ADDR_REV                   = 0x1011001c
# -----------------------------------------------------------------
# ------
FTWDT_REV_BITS                   = 32
FTWDT_REV_LSB                    = 0
FTWDT_REV_MSB                    = 31
FTWDT_REV_MASK                   = 0xffffffff
FTWDT_REV_SH                     = 0
FTWDT_REV_DEF                    = 0x00010700

# =================================================================
# ftx2h: Faraday AXI to AHB Bridge
# FTX2H030 is a bridge connecting the AXI fabric to the AHB bus.
# -----------------------------------------------------------------
# ftx2h DFIFO_THR: Data FIFO Threshold Register
# The data FIFO threshold register includes the write data and read data
# FIFO thresholds. The thresholds should not exceed the FIFO depth of
# the write data or read data, which is hardware configurable.
# Access RW
# -----------------------------------------------------------------
FTX2H_ADDR_DFIFO_THR             = 0x10120004
# -----------------------------------------------------------------
# ------
# WRTHR: 
# Access RW
# Data FIFO Write Threshold Level. 1 << wrthr. Maximum value is 4.
FTX2H_DFIFO_THR_WRTHR_BITS       = 3
FTX2H_DFIFO_THR_WRTHR_LSB        = 0
FTX2H_DFIFO_THR_WRTHR_MSB        = 2
FTX2H_DFIFO_THR_WRTHR_MASK       = 0x00000007
FTX2H_DFIFO_THR_WRTHR_SH         = 0
FTX2H_DFIFO_THR_WRTHR_DEF        = 0x00000000
# ------
# RDTHR: 
# Access RW
# Data FIFO Read Threshold Level. 1 << rdthr. Maximum value is 4.
FTX2H_DFIFO_THR_RDTHR_BITS       = 3
FTX2H_DFIFO_THR_RDTHR_LSB        = 4
FTX2H_DFIFO_THR_RDTHR_MSB        = 6
FTX2H_DFIFO_THR_RDTHR_MASK       = 0x00000070
FTX2H_DFIFO_THR_RDTHR_SH         = 4
FTX2H_DFIFO_THR_RDTHR_DEF        = 0x00000000
# -----------------------------------------------------------------
# ftx2h ERR_MASK: APB Slave Error Mask Register
# When users access the register offset over the legal range (Offset:
# 0x18), FTX2H030 will respond Slave Error from the APB port. The APB
# slave error mask register can mask the response and will always
# respond Slave Okay from the APB port.
# Access RW
# -----------------------------------------------------------------
FTX2H_ADDR_ERR_MASK              = 0x10120008
# -----------------------------------------------------------------
# ------
# APB_ERR: 
# Access RW
# When set the response will always be Slave OK.
FTX2H_ERR_MASK_APB_ERR_BIT       = 0
FTX2H_ERR_MASK_APB_ERR_MASK      = 0x00000001
FTX2H_ERR_MASK_APB_ERR_SH        = 0
FTX2H_ERR_MASK_APB_ERR_DEF       = 0x00000000
# -----------------------------------------------------------------
# ftx2h FR1: Feature Register 1
# 
# Access RW
# -----------------------------------------------------------------
FTX2H_ADDR_FR1                   = 0x10120010
# -----------------------------------------------------------------
# ------
# AHB_DW: 
# Access RO
# AHB Bus is 32 bits.
FTX2H_FR1_AHB_DW_BITS            = 8
FTX2H_FR1_AHB_DW_LSB             = 0
FTX2H_FR1_AHB_DW_MSB             = 7
FTX2H_FR1_AHB_DW_MASK            = 0x000000ff
FTX2H_FR1_AHB_DW_SH              = 0
FTX2H_FR1_AHB_DW_DEF             = 0x00000002
# ------
# AXI_DW: 
# Access RO
# AXI Bus is 64 bits.
FTX2H_FR1_AXI_DW_BITS            = 8
FTX2H_FR1_AXI_DW_LSB             = 8
FTX2H_FR1_AXI_DW_MSB             = 15
FTX2H_FR1_AXI_DW_MASK            = 0x0000ff00
FTX2H_FR1_AXI_DW_SH              = 8
FTX2H_FR1_AXI_DW_DEF             = 0x00000003
# ------
# EXEN: 
# Access RO
# One monitor.
FTX2H_FR1_EXEN_BITS              = 4
FTX2H_FR1_EXEN_LSB               = 16
FTX2H_FR1_EXEN_MSB               = 19
FTX2H_FR1_EXEN_MASK              = 0x000f0000
FTX2H_FR1_EXEN_SH                = 16
FTX2H_FR1_EXEN_DEF               = 0x00000001
# ------
# AHB_IF: 
# Access RO
# AHB Master Interface.
FTX2H_FR1_AHB_IF_BIT             = 20
FTX2H_FR1_AHB_IF_MASK            = 0x00100000
FTX2H_FR1_AHB_IF_SH              = 20
FTX2H_FR1_AHB_IF_DEF             = 0x00000001
# ------
# AHB_PR: 
# Access RO
# Lite AHB Protocol.
FTX2H_FR1_AHB_PR_BIT             = 21
FTX2H_FR1_AHB_PR_MASK            = 0x00200000
FTX2H_FR1_AHB_PR_SH              = 21
FTX2H_FR1_AHB_PR_DEF             = 0x00000001
# ------
# CLOCK_MODE: 
# Access RO
# The AHB bus is asynchronous to the AXI bus.
FTX2H_FR1_CLOCK_MODE_BITS        = 2
FTX2H_FR1_CLOCK_MODE_LSB         = 22
FTX2H_FR1_CLOCK_MODE_MSB         = 23
FTX2H_FR1_CLOCK_MODE_MASK        = 0x00c00000
FTX2H_FR1_CLOCK_MODE_SH          = 22
FTX2H_FR1_CLOCK_MODE_DEF         = 0x00000001
# ------
# IDW: 
# Access RO
# AXI ID Width is 8 bits.
FTX2H_FR1_IDW_BITS               = 4
FTX2H_FR1_IDW_LSB                = 24
FTX2H_FR1_IDW_MSB                = 27
FTX2H_FR1_IDW_MASK               = 0x0f000000
FTX2H_FR1_IDW_SH                 = 24
FTX2H_FR1_IDW_DEF                = 0x00000008
# ------
# AXI4: 
# Access RO
# AXI-3 Protocol.
FTX2H_FR1_AXI4_BIT               = 31
FTX2H_FR1_AXI4_MASK              = 0x80000000
FTX2H_FR1_AXI4_SH                = 31
FTX2H_FR1_AXI4_DEF               = 0x00000000
# -----------------------------------------------------------------
# ftx2h FR2: Feature Register 2
# 
# Access RW
# -----------------------------------------------------------------
FTX2H_ADDR_FR2                   = 0x10120014
# -----------------------------------------------------------------
# ------
# RD_DEPTH: 
# Access RO
# Read data queue depth is 4.
FTX2H_FR2_RD_DEPTH_BITS          = 8
FTX2H_FR2_RD_DEPTH_LSB           = 0
FTX2H_FR2_RD_DEPTH_MSB           = 7
FTX2H_FR2_RD_DEPTH_MASK          = 0x000000ff
FTX2H_FR2_RD_DEPTH_SH            = 0
FTX2H_FR2_RD_DEPTH_DEF           = 0x00000004
# ------
# WR_DEPTH: 
# Access RO
# Write response queue depth is 4.
FTX2H_FR2_WR_DEPTH_BITS          = 8
FTX2H_FR2_WR_DEPTH_LSB           = 8
FTX2H_FR2_WR_DEPTH_MSB           = 15
FTX2H_FR2_WR_DEPTH_MASK          = 0x0000ff00
FTX2H_FR2_WR_DEPTH_SH            = 8
FTX2H_FR2_WR_DEPTH_DEF           = 0x00000004
# ------
# WD_DEPTH: 
# Access RO
# Write data queue depth is 4.
FTX2H_FR2_WD_DEPTH_BITS          = 8
FTX2H_FR2_WD_DEPTH_LSB           = 16
FTX2H_FR2_WD_DEPTH_MSB           = 23
FTX2H_FR2_WD_DEPTH_MASK          = 0x00ff0000
FTX2H_FR2_WD_DEPTH_SH            = 16
FTX2H_FR2_WD_DEPTH_DEF           = 0x00000008
# ------
# CMDQ_DEPTH: 
# Access RO
# Command queue depth is 4.
FTX2H_FR2_CMDQ_DEPTH_BITS        = 8
FTX2H_FR2_CMDQ_DEPTH_LSB         = 24
FTX2H_FR2_CMDQ_DEPTH_MSB         = 31
FTX2H_FR2_CMDQ_DEPTH_MASK        = 0xff000000
FTX2H_FR2_CMDQ_DEPTH_SH          = 24
FTX2H_FR2_CMDQ_DEPTH_DEF         = 0x00000008
# -----------------------------------------------------------------
# ftx2h RR: Revision Register
# 
# Access RW
# -----------------------------------------------------------------
FTX2H_ADDR_RR                    = 0x1012000c
# -----------------------------------------------------------------
# ------
# REV_VER: 
# Access RO
# Revision number
FTX2H_RR_REV_VER_BITS            = 8
FTX2H_RR_REV_VER_LSB             = 0
FTX2H_RR_REV_VER_MSB             = 7
FTX2H_RR_REV_VER_MASK            = 0x000000ff
FTX2H_RR_REV_VER_SH              = 0
FTX2H_RR_REV_VER_DEF             = 0x00000000
# ------
# MINOR_VER: 
# Access RO
# Minor version number
FTX2H_RR_MINOR_VER_BITS          = 8
FTX2H_RR_MINOR_VER_LSB           = 8
FTX2H_RR_MINOR_VER_MSB           = 15
FTX2H_RR_MINOR_VER_MASK          = 0x0000ff00
FTX2H_RR_MINOR_VER_SH            = 8
FTX2H_RR_MINOR_VER_DEF           = 0x00000003
# ------
# MAJOR_VER: 
# Access RO
# Major version number
FTX2H_RR_MAJOR_VER_BITS          = 8
FTX2H_RR_MAJOR_VER_LSB           = 16
FTX2H_RR_MAJOR_VER_MSB           = 23
FTX2H_RR_MAJOR_VER_MASK          = 0x00ff0000
FTX2H_RR_MAJOR_VER_SH            = 16
FTX2H_RR_MAJOR_VER_DEF           = 0x00000002

# =================================================================
# fth2x: Faraday AHB to AXI Bridge
# FTH2X030 provides a bridge between the AHB bus and the AXI bus. It
# converts an AHB command of the AHB bus into an AXI command of the AXI
# bus.
# -----------------------------------------------------------------
# fth2x CR: Control Registers
# 
# Access RW
# -----------------------------------------------------------------
FTH2X_ADDR_CR                    = 0x10130000
# -----------------------------------------------------------------
# ------
# INTEN: 
# Access RW
# Interrupt Enable. Enable an interrupt signal to CPU when H2X receives
# an AXI error response for a bufferable AHB write command.
FTH2X_CR_INTEN_BIT               = 0
FTH2X_CR_INTEN_MASK              = 0x00000001
FTH2X_CR_INTEN_SH                = 0
FTH2X_CR_INTEN_DEF               = 0x00000000
# ------
# DISAPBSLVERR: 
# Access RW
# Disable APB Error Respons. The output signal, PSlvErr, will always be
# 0 even when this blocks APB interface receives a non-existing address.
FTH2X_CR_DISAPBSLVERR_BIT        = 1
FTH2X_CR_DISAPBSLVERR_MASK       = 0x00000002
FTH2X_CR_DISAPBSLVERR_SH         = 1
FTH2X_CR_DISAPBSLVERR_DEF        = 0x00000000
# ------
# HPROTTYPE_W: 
# Access RW
# Write data queue control. 00: AHB write data will be buffered if HProt
# in received request is bufferable. 01: AHB write data will always be
# buffered regardless of input request HProt value. 10: AHB write data
# will never be buffered regardless of received request HProt value.
FTH2X_CR_HPROTTYPE_W_BITS        = 2
FTH2X_CR_HPROTTYPE_W_LSB         = 2
FTH2X_CR_HPROTTYPE_W_MSB         = 3
FTH2X_CR_HPROTTYPE_W_MASK        = 0x0000000c
FTH2X_CR_HPROTTYPE_W_SH          = 2
FTH2X_CR_HPROTTYPE_W_DEF         = 0x00000000
# ------
# HPROTTYPE_R: 
# Access RW
# Read data queue control. 00: AHB read data will be cached if HProt in
# received request is cached. 01: AHB read data will always be buffered
# regardless of input request HProt value. 10: AHB read data will never
# be cached regardless of received request HProt value.
FTH2X_CR_HPROTTYPE_R_BITS        = 2
FTH2X_CR_HPROTTYPE_R_LSB         = 4
FTH2X_CR_HPROTTYPE_R_MSB         = 5
FTH2X_CR_HPROTTYPE_R_MASK        = 0x00000030
FTH2X_CR_HPROTTYPE_R_SH          = 4
FTH2X_CR_HPROTTYPE_R_DEF         = 0x00000000
# -----------------------------------------------------------------
# fth2x SR: Status Register
# 
# Access RW
# -----------------------------------------------------------------
FTH2X_ADDR_SR                    = 0x10130004
# -----------------------------------------------------------------
# ------
# AXIERR: 
# Access W1C
# This bit is set when AXI interface receives an AXI error response for
# an AHB bufferable write command.
FTH2X_SR_AXIERR_BIT              = 0
FTH2X_SR_AXIERR_MASK             = 0x00000001
FTH2X_SR_AXIERR_SH               = 0
FTH2X_SR_AXIERR_DEF              = 0x00000000
# ------
# H2XIDLE: 
# Access RO
# Set when the H2X bridge has no commands to process.
FTH2X_SR_H2XIDLE_BIT             = 1
FTH2X_SR_H2XIDLE_MASK            = 0x00000002
FTH2X_SR_H2XIDLE_SH              = 1
FTH2X_SR_H2XIDLE_DEF             = 0x00000000
# -----------------------------------------------------------------
# fth2x FR: Feature Register
# 
# Access RW
# -----------------------------------------------------------------
FTH2X_ADDR_FR                    = 0x10130008
# -----------------------------------------------------------------
# ------
# AHB_DW: 
# Access RO
# AHB Bus is 32 bits.
FTH2X_FR_AHB_DW_BIT              = 0
FTH2X_FR_AHB_DW_MASK             = 0x00000001
FTH2X_FR_AHB_DW_SH               = 0
FTH2X_FR_AHB_DW_DEF              = 0x00000000
# ------
# AXI_DW: 
# Access RO
# AXI Bus is 64 bits.
FTH2X_FR_AXI_DW_BIT              = 1
FTH2X_FR_AXI_DW_MASK             = 0x00000002
FTH2X_FR_AXI_DW_SH               = 1
FTH2X_FR_AXI_DW_DEF              = 0x00000001
# ------
# CMDQ_DEPTH: 
# Access RO
# Command queue depth is 2.
FTH2X_FR_CMDQ_DEPTH_BITS         = 3
FTH2X_FR_CMDQ_DEPTH_LSB          = 2
FTH2X_FR_CMDQ_DEPTH_MSB          = 4
FTH2X_FR_CMDQ_DEPTH_MASK         = 0x0000001c
FTH2X_FR_CMDQ_DEPTH_SH           = 2
FTH2X_FR_CMDQ_DEPTH_DEF          = 0x00000002
# ------
# WDQ_DEPTH: 
# Access RO
# Write data queue depth is 4.
FTH2X_FR_WDQ_DEPTH_BITS          = 4
FTH2X_FR_WDQ_DEPTH_LSB           = 5
FTH2X_FR_WDQ_DEPTH_MSB           = 8
FTH2X_FR_WDQ_DEPTH_MASK          = 0x000001e0
FTH2X_FR_WDQ_DEPTH_SH            = 5
FTH2X_FR_WDQ_DEPTH_DEF           = 0x00000004
# ------
# RDQ_DEPTH: 
# Access RO
# Read data queue depth is 4.
FTH2X_FR_RDQ_DEPTH_BITS          = 4
FTH2X_FR_RDQ_DEPTH_LSB           = 9
FTH2X_FR_RDQ_DEPTH_MSB           = 12
FTH2X_FR_RDQ_DEPTH_MASK          = 0x00001e00
FTH2X_FR_RDQ_DEPTH_SH            = 9
FTH2X_FR_RDQ_DEPTH_DEF           = 0x00000004
# ------
# AHB_BUS: 
# Access RO
# The H2X bridge is connected to the AHB bus.
FTH2X_FR_AHB_BUS_BIT             = 13
FTH2X_FR_AHB_BUS_MASK            = 0x00002000
FTH2X_FR_AHB_BUS_SH              = 13
FTH2X_FR_AHB_BUS_DEF             = 0x00000001
# ------
# CLOCK_MODE: 
# Access RO
# The AHB bus is asynchronous to the AXI bus.
FTH2X_FR_CLOCK_MODE_BITS         = 2
FTH2X_FR_CLOCK_MODE_LSB          = 14
FTH2X_FR_CLOCK_MODE_MSB          = 15
FTH2X_FR_CLOCK_MODE_MASK         = 0x0000c000
FTH2X_FR_CLOCK_MODE_SH           = 14
FTH2X_FR_CLOCK_MODE_DEF          = 0x00000001
# -----------------------------------------------------------------
# fth2x RR: Revision Register
# 
# Access RW
# -----------------------------------------------------------------
FTH2X_ADDR_RR                    = 0x1013000c
# -----------------------------------------------------------------
# ------
# REV_VER: 
# Access RO
# Revision number
FTH2X_RR_REV_VER_BITS            = 8
FTH2X_RR_REV_VER_LSB             = 0
FTH2X_RR_REV_VER_MSB             = 7
FTH2X_RR_REV_VER_MASK            = 0x000000ff
FTH2X_RR_REV_VER_SH              = 0
FTH2X_RR_REV_VER_DEF             = 0x00000001
# ------
# MINOR_VER: 
# Access RO
# Minor version number
FTH2X_RR_MINOR_VER_BITS          = 8
FTH2X_RR_MINOR_VER_LSB           = 8
FTH2X_RR_MINOR_VER_MSB           = 15
FTH2X_RR_MINOR_VER_MASK          = 0x0000ff00
FTH2X_RR_MINOR_VER_SH            = 8
FTH2X_RR_MINOR_VER_DEF           = 0x00000006
# ------
# MAJOR_VER: 
# Access RO
# Major version number
FTH2X_RR_MAJOR_VER_BITS          = 8
FTH2X_RR_MAJOR_VER_LSB           = 16
FTH2X_RR_MAJOR_VER_MSB           = 23
FTH2X_RR_MAJOR_VER_MASK          = 0x00ff0000
FTH2X_RR_MAJOR_VER_SH            = 16
FTH2X_RR_MAJOR_VER_DEF           = 0x00000000

# =================================================================
# ftx2x_pcie: Faraday AXI to AXI Bridge for PCIe DBI Slave
# FTX2X030 is a bridge connecting the 64 bit AXI fabric to the 32 bit
# PCIe AXI slave interface.
# -----------------------------------------------------------------
# ftx2x_pcie ERR_MASK: APB Slave Error Mask Register
# When users access the register offset over the legal range, FTX2X will
# respond Slave Error from the APB port. The APB slave error mask
# register can mask the response and will always respond Slave Okay from
# the APB port.
# Access RW
# -----------------------------------------------------------------
FTX2X_PCIE_ADDR_ERR_MASK         = 0x10140000
# -----------------------------------------------------------------
# ------
# APB_ERR: 
# Access RW
# When this bit is 0 the response will always be Slave OK.
FTX2X_PCIE_ERR_MASK_APB_ERR_BIT  = 0
FTX2X_PCIE_ERR_MASK_APB_ERR_MASK = 0x00000001
FTX2X_PCIE_ERR_MASK_APB_ERR_SH   = 0
FTX2X_PCIE_ERR_MASK_APB_ERR_DEF  = 0x00000001
# -----------------------------------------------------------------
# ftx2x_pcie FR1: Feature Register 1
# 
# Access RW
# -----------------------------------------------------------------
FTX2X_PCIE_ADDR_FR1              = 0x10140010
# -----------------------------------------------------------------
# ------
# AXIM_DW: 
# Access RO
# AXI Master Bus is 64 bits.
FTX2X_PCIE_FR1_AXIM_DW_BITS      = 8
FTX2X_PCIE_FR1_AXIM_DW_LSB       = 0
FTX2X_PCIE_FR1_AXIM_DW_MSB       = 7
FTX2X_PCIE_FR1_AXIM_DW_MASK      = 0x000000ff
FTX2X_PCIE_FR1_AXIM_DW_SH        = 0
FTX2X_PCIE_FR1_AXIM_DW_DEF       = 0x00000002
# ------
# AXIS_DW: 
# Access RO
# AXI Slave Bus is 64 bits.
FTX2X_PCIE_FR1_AXIS_DW_BITS      = 8
FTX2X_PCIE_FR1_AXIS_DW_LSB       = 8
FTX2X_PCIE_FR1_AXIS_DW_MSB       = 15
FTX2X_PCIE_FR1_AXIS_DW_MASK      = 0x0000ff00
FTX2X_PCIE_FR1_AXIS_DW_SH        = 8
FTX2X_PCIE_FR1_AXIS_DW_DEF       = 0x00000003
# ------
# IDW: 
# Access RO
# AXI ID Width is 8 bits.
FTX2X_PCIE_FR1_IDW_BITS          = 5
FTX2X_PCIE_FR1_IDW_LSB           = 16
FTX2X_PCIE_FR1_IDW_MSB           = 20
FTX2X_PCIE_FR1_IDW_MASK          = 0x001f0000
FTX2X_PCIE_FR1_IDW_SH            = 16
FTX2X_PCIE_FR1_IDW_DEF           = 0x00000008
# ------
# CLOCK_MODE: 
# Access RO
# The AXI master bus is synchronous to the AXI slave bus.
FTX2X_PCIE_FR1_CLOCK_MODE_BITS   = 2
FTX2X_PCIE_FR1_CLOCK_MODE_LSB    = 21
FTX2X_PCIE_FR1_CLOCK_MODE_MSB    = 22
FTX2X_PCIE_FR1_CLOCK_MODE_MASK   = 0x00600000
FTX2X_PCIE_FR1_CLOCK_MODE_SH     = 21
FTX2X_PCIE_FR1_CLOCK_MODE_DEF    = 0x00000002
# ------
# AXI_PR: 
# Access RO
# AXI-3 Protocol.
FTX2X_PCIE_FR1_AXI_PR_BITS       = 3
FTX2X_PCIE_FR1_AXI_PR_LSB        = 23
