FTSCU_PWRMOD_SELFR_CMD_OFF_MASK  = 0x80000000
FTSCU_PWRMOD_SELFR_CMD_OFF_SH    = 31
FTSCU_PWRMOD_SELFR_CMD_OFF_DEF   = 0x00000000
