# -----------------------------------------------------------------
# ftscu PLLCTRL: PLL Control Register
# The register contains the PLL programmable setting values, the loop
# divider (PLLNS), pre-divider (MS), and frequency range (PLLFRANG).
# PLLEN controls the power-down modesetting signal of PLL, and PLLSTABLE
# refers that the PLL clock is at the locking state.
# Access RW
# -----------------------------------------------------------------
FTSCU_ADDR_PLLCTRL               = 0x10180030
# -----------------------------------------------------------------
# ------
# PLLEN: 
# Access RW
# PLL enable control, the PLL cannot directly be turned ON/OFF when the
# bit is set. The procedure should accompany a FCS command to stop or
# enable PLL.
FTSCU_PLLCTRL_PLLEN_BIT          = 0
FTSCU_PLLCTRL_PLLEN_MASK         = 0x00000001
FTSCU_PLLCTRL_PLLEN_SH           = 0
FTSCU_PLLCTRL_PLLEN_DEF          = 0x00000000
# ------
# PLLSTABLE: 
# Access RO
# 0: PLL is not stable. 1: PLL is stable.
FTSCU_PLLCTRL_PLLSTABLE_BIT      = 1
FTSCU_PLLCTRL_PLLSTABLE_MASK     = 0x00000002
FTSCU_PLLCTRL_PLLSTABLE_SH       = 1
FTSCU_PLLCTRL_PLLSTABLE_DEF      = 0x00000000
# ------
# PLLFRANG: 
# Access RW
# PLL post divider value. 0: 8, 1: 10, 2: 12, 3: 16.
FTSCU_PLLCTRL_PLLFRANG_BITS      = 4
FTSCU_PLLCTRL_PLLFRANG_LSB       = 8
FTSCU_PLLCTRL_PLLFRANG_MSB       = 11
FTSCU_PLLCTRL_PLLFRANG_MASK      = 0x00000f00
FTSCU_PLLCTRL_PLLFRANG_SH        = 8
FTSCU_PLLCTRL_PLLFRANG_DEF       = 0x00000000
# ------
# PLLMS: 
# Access RW
# This field sets the M value of the embedded PLL to control the PLL
# frequency output.
