FTSCU_PLLCTRL_PLLMS_LSB          = 16
FTSCU_PLLCTRL_PLLMS_MSB          = 23
FTSCU_PLLCTRL_PLLMS_MASK         = 0x00ff0000
FTSCU_PLLCTRL_PLLMS_SH           = 16
FTSCU_PLLCTRL_PLLMS_DEF          = 0x00000000
# ------
# PLLNS: 
# Access RW
# This field sets the N value of the embedded PLL to control the PLL
# frequency output.
FTSCU_PLLCTRL_PLLNS_BITS         = 8
FTSCU_PLLCTRL_PLLNS_LSB          = 24
FTSCU_PLLCTRL_PLLNS_MSB          = 31
FTSCU_PLLCTRL_PLLNS_MASK         = 0xff000000
FTSCU_PLLCTRL_PLLNS_SH           = 24
FTSCU_PLLCTRL_PLLNS_DEF          = 0x00000000
