# -----------------------------------------------------------------
# ------
# APP_LTSSM_ENABLE: 
# Access RW
# app_ltssm_enable controls when the PCIe core is allowed to begin link
# training and establish the link. When X_SYS_RESET is de-asserted the
# app_ltssm_enable bit latches in the inverse of X_CPU_ENABLE. When
# X_CPU_ENABLE is asserted, app_ltssm_enable is low preventing the PCIe
# core from entering link training. This allows the CPU to configure the
# PCIe core before the link is established. The CPU then enables the
# PCIe core by writing a 1 to this bit.
FTSCU_PCIEC_APP_LTSSM_ENABLE_BIT = 0
FTSCU_PCIEC_APP_LTSSM_ENABLE_MASK = 0x00000001
FTSCU_PCIEC_APP_LTSSM_ENABLE_SH  = 0
