# CLKSEL: 
# Access RW
# Reference clock source selection This static control signal cannot be
# changed within one operation. This signal selects the source of the
# reference clock to be the crystal or external source. 0: Select the
# crystal as the reference clock source (XSCI/XSCO) 1: Select the
# external reference clock source (CORECLKIN). Should always be 1 in
# EchoNous design.
FTSCU_USBC_CLKSEL_BIT            = 4
FTSCU_USBC_CLKSEL_MASK           = 0x00000010
FTSCU_USBC_CLKSEL_SH             = 4
FTSCU_USBC_CLKSEL_DEF            = 0x00000001
