# =================================================================
# ftusb: Faraday USB Controller
# Registers with offsets < 0x1800 are Host Mode registers. Registers
# with offsets >= 0x1800 and < 0x2000 are OTG and Global registers.
# Registers with offsets >= 0x2000 are Device Mode registers.
# -----------------------------------------------------------------
# ftusb CAPLENGTH: Capability Registers Length Register
# This register is part of the Host Controller Capability Register set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_CAPLENGTH             = 0x10300000
# -----------------------------------------------------------------
# ------
# CL: 
# Access RO
# This register is used as an offset to add to register base to find the
# beginning of the Operational Register Space.
FTUSB_CAPLENGTH_CL_BITS          = 8
FTUSB_CAPLENGTH_CL_LSB           = 0
FTUSB_CAPLENGTH_CL_MSB           = 7
FTUSB_CAPLENGTH_CL_MASK          = 0x000000ff
FTUSB_CAPLENGTH_CL_SH            = 0
FTUSB_CAPLENGTH_CL_DEF           = 0x00000020
# -----------------------------------------------------------------
# ftusb HCIVERSION: Host Controller Interface Version Number Register
# This register is part of the Host Controller Capability Register set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_HCIVERSION            = 0x10300002
# -----------------------------------------------------------------
# ------
# VERSION: 
# Access RO
# This is a two byte register containing a BCD encoding of the revision
# number of the XHCI specification supported by this host controller.
# The MSB represents a major revision and the LSB is the minor revision.
# This IP currently implements XHCI specification version 1.0.
FTUSB_HCIVERSION_VERSION_BITS    = 16
FTUSB_HCIVERSION_VERSION_LSB     = 0
FTUSB_HCIVERSION_VERSION_MSB     = 15
FTUSB_HCIVERSION_VERSION_MASK    = 0x0000ffff
FTUSB_HCIVERSION_VERSION_SH      = 0
FTUSB_HCIVERSION_VERSION_DEF     = 0x00000100
# -----------------------------------------------------------------
# ftusb HCSPARAMS1: Host Controller Structural Parameters Register 1
# This register is part of the Host Controller Capability Register set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_HCSPARAMS1            = 0x10300004
# -----------------------------------------------------------------
# ------
# MAXSLOTS: 
# Access RO
# Number of device slots.  Maximum number of Device Context Structures
# and Doorbell Array entries that this host controller supports.
FTUSB_HCSPARAMS1_MAXSLOTS_BITS   = 8
FTUSB_HCSPARAMS1_MAXSLOTS_LSB    = 0
FTUSB_HCSPARAMS1_MAXSLOTS_MSB    = 7
FTUSB_HCSPARAMS1_MAXSLOTS_MASK   = 0x000000ff
FTUSB_HCSPARAMS1_MAXSLOTS_SH     = 0
FTUSB_HCSPARAMS1_MAXSLOTS_DEF    = 0x0000007f
# ------
# MAXINTRS: 
# Access RO
# Number of interrupters. This field indicates how many interrupt
# register sets are addressable in the Runtime Registers Space.
FTUSB_HCSPARAMS1_MAXINTRS_BITS   = 11
FTUSB_HCSPARAMS1_MAXINTRS_LSB    = 8
FTUSB_HCSPARAMS1_MAXINTRS_MSB    = 18
FTUSB_HCSPARAMS1_MAXINTRS_MASK   = 0x0007ff00
FTUSB_HCSPARAMS1_MAXINTRS_SH     = 8
FTUSB_HCSPARAMS1_MAXINTRS_DEF    = 0x00000001
# ------
# MAXPORTS: 
# Access RO
# This field specifies the maximum number of Port Register Sets that are
# addressable in the Operational Register Space.
FTUSB_HCSPARAMS1_MAXPORTS_BITS   = 8
FTUSB_HCSPARAMS1_MAXPORTS_LSB    = 24
FTUSB_HCSPARAMS1_MAXPORTS_MSB    = 31
FTUSB_HCSPARAMS1_MAXPORTS_MASK   = 0xff000000
FTUSB_HCSPARAMS1_MAXPORTS_SH     = 24
FTUSB_HCSPARAMS1_MAXPORTS_DEF    = 0x00000002
# -----------------------------------------------------------------
# ftusb HCSPARAMS2: Host Controller Structural Parameters Register 2
# This register is part of the Host Controller Capability Register set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_HCSPARAMS2            = 0x10300008
# -----------------------------------------------------------------
# ------
# IST: 
# Access RO
# Isochronous Scheduling Threshold.  Minimum time required to stay ahead
# of the host controller while adding TRBs so that the host controller
# can process them at the correct time. The valuer is specified in
# number of frames/microframes. SW can add a TRB no later than 1
# microframe before that TRB is scheduled to be executed.
FTUSB_HCSPARAMS2_IST_BITS        = 4
FTUSB_HCSPARAMS2_IST_LSB         = 0
FTUSB_HCSPARAMS2_IST_MSB         = 3
FTUSB_HCSPARAMS2_IST_MASK        = 0x0000000f
FTUSB_HCSPARAMS2_IST_SH          = 0
FTUSB_HCSPARAMS2_IST_DEF         = 0x00000001
# ------
# ERST: 
# Access RO
# Event Ring Segment Table Max. Maximum value supported by the Event
# Ring Segment Table base size register. Max entries = 1 << erst.
FTUSB_HCSPARAMS2_ERST_BITS       = 4
FTUSB_HCSPARAMS2_ERST_LSB        = 4
FTUSB_HCSPARAMS2_ERST_MSB        = 7
FTUSB_HCSPARAMS2_ERST_MASK       = 0x000000f0
FTUSB_HCSPARAMS2_ERST_SH         = 4
FTUSB_HCSPARAMS2_ERST_DEF        = 0x00000002
# ------
# SPR: 
# Access RO
# Scratchpad restore. The IP does not support this feature.
FTUSB_HCSPARAMS2_SPR_BIT         = 26
FTUSB_HCSPARAMS2_SPR_MASK        = 0x04000000
FTUSB_HCSPARAMS2_SPR_SH          = 26
FTUSB_HCSPARAMS2_SPR_DEF         = 0x00000000
# ------
# SCRBUFS: 
# Access RO
# Max scratchpad buffers. The IP does not support this feature.
FTUSB_HCSPARAMS2_SCRBUFS_BITS    = 4
FTUSB_HCSPARAMS2_SCRBUFS_LSB     = 27
FTUSB_HCSPARAMS2_SCRBUFS_MSB     = 30
FTUSB_HCSPARAMS2_SCRBUFS_MASK    = 0x78000000
FTUSB_HCSPARAMS2_SCRBUFS_SH      = 27
FTUSB_HCSPARAMS2_SCRBUFS_DEF     = 0x00000000
# -----------------------------------------------------------------
# ftusb HCSPARAMS3: Host Controller Structural Parameters Register 3
# This register is part of the Host Controller Capability Register set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_HCSPARAMS3            = 0x1030000c
# -----------------------------------------------------------------
# ------
# U1_EXIT_LATENCY: 
# Access RO
# U1 Device Exit Latency from U1 to U0 expressed in microseconds.
FTUSB_HCSPARAMS3_U1_EXIT_LATENCY_BITS = 8
FTUSB_HCSPARAMS3_U1_EXIT_LATENCY_LSB = 0
FTUSB_HCSPARAMS3_U1_EXIT_LATENCY_MSB = 7
FTUSB_HCSPARAMS3_U1_EXIT_LATENCY_MASK = 0x000000ff
FTUSB_HCSPARAMS3_U1_EXIT_LATENCY_SH = 0
FTUSB_HCSPARAMS3_U1_EXIT_LATENCY_DEF = 0x00000001
# ------
# U2_EXIT_LATENCY: 
