FTUSB_HCSPARAMS3_U2_EXIT_LATENCY_BITS = 16
FTUSB_HCSPARAMS3_U2_EXIT_LATENCY_LSB = 16
FTUSB_HCSPARAMS3_U2_EXIT_LATENCY_MSB = 31
