FTUSB_HCCPARAMS_LHRC_BIT         = 5
FTUSB_HCCPARAMS_LHRC_MASK        = 0x00000020
FTUSB_HCCPARAMS_LHRC_SH          = 5
FTUSB_HCCPARAMS_LHRC_DEF         = 0x00000000
# ------
# LTC: 
# Access RO
