FTUSB_HCCPARAMS_LTC_BIT          = 6
FTUSB_HCCPARAMS_LTC_MASK         = 0x00000040
FTUSB_HCCPARAMS_LTC_SH           = 6
FTUSB_HCCPARAMS_LTC_DEF          = 0x00000000
# ------
# NSS: 
# Access RO
