FTUSB_HCCPARAMS_NSS_BIT          = 7
FTUSB_HCCPARAMS_NSS_MASK         = 0x00000080
FTUSB_HCCPARAMS_NSS_SH           = 7
FTUSB_HCCPARAMS_NSS_DEF          = 0x00000001
# ------
