FTUSB_HCCPARAMS_MAXPSASIZE_LSB   = 12
FTUSB_HCCPARAMS_MAXPSASIZE_MSB   = 15
FTUSB_HCCPARAMS_MAXPSASIZE_MASK  = 0x0000f000
