FTUSB_U3HOSTCNTRL_TXDEEMPH_LEVEL_LSB = 2
FTUSB_U3HOSTCNTRL_TXDEEMPH_LEVEL_MSB = 3
FTUSB_U3HOSTCNTRL_TXDEEMPH_LEVEL_MASK = 0x0000000c
FTUSB_U3HOSTCNTRL_TXDEEMPH_LEVEL_SH = 2
FTUSB_U3HOSTCNTRL_TXDEEMPH_LEVEL_DEF = 0x00000001
# ------
# SS_TX_SWING: 
