FTUSB_U3HOSTCNTRL_SS_TX_SWING_BIT = 4
FTUSB_U3HOSTCNTRL_SS_TX_SWING_MASK = 0x00000010
FTUSB_U3HOSTCNTRL_SS_TX_SWING_SH = 4
FTUSB_U3HOSTCNTRL_SS_TX_SWING_DEF = 0x00000000
# -----------------------------------------------------------------
# ftusb U3PCINTERR: USB3 Port Controller Internal Error Register
# This register is part of the XHCI Special Purpose Registers set. There
# is one U3PCINTERR register for every port attached to the root hub.
