FTUSB_U3PCINTERR_ARFIFO_OVERFLOW_MASK = 0x00000001
FTUSB_U3PCINTERR_ARFIFO_OVERFLOW_SH = 0
FTUSB_U3PCINTERR_ARFIFO_OVERFLOW_DEF = 0x00000000
