FTUSB_OTGINTRSTS_ROLECHG_MASK    = 0x00000002
FTUSB_OTGINTRSTS_ROLECHG_SH      = 1
FTUSB_OTGINTRSTS_ROLECHG_DEF     = 0x00000000
