# IDCHG_EN: 
# Access RW
# ID Change Enable.
FTUSB_OTGINTREN_IDCHG_EN_BIT     = 0
FTUSB_OTGINTREN_IDCHG_EN_MASK    = 0x00000001
FTUSB_OTGINTREN_IDCHG_EN_SH      = 0
FTUSB_OTGINTREN_IDCHG_EN_DEF     = 0x00000000
# ------
