FTUSB_OTGINTREN_ROLECHG_EN_MASK  = 0x00000002
FTUSB_OTGINTREN_ROLECHG_EN_SH    = 1
FTUSB_OTGINTREN_ROLECHG_EN_DEF   = 0x00000000
