FTUSB_GLBINTREN_OTGINTR_EN_BIT   = 0
FTUSB_GLBINTREN_OTGINTR_EN_MASK  = 0x00000001
FTUSB_GLBINTREN_OTGINTR_EN_SH    = 0
FTUSB_GLBINTREN_OTGINTR_EN_DEF   = 0x00000000
# ------
