# POLL_TO_DIS_CNT: 
# Access RW
# Counter of polling to disable. When the quality of signals on USB
# cable is very bad, FOTG330 may fail to connect with host for the SS
# link and start to try the HS link. This field indicates that FOTG330
# will try to re-build the SS connection until this counter is timeout.
FTUSB_GCR_POLL_TO_DIS_CNT_BITS   = 4
FTUSB_GCR_POLL_TO_DIS_CNT_LSB    = 12
FTUSB_GCR_POLL_TO_DIS_CNT_MSB    = 15
FTUSB_GCR_POLL_TO_DIS_CNT_MASK   = 0x0000f000
FTUSB_GCR_POLL_TO_DIS_CNT_SH     = 12
FTUSB_GCR_POLL_TO_DIS_CNT_DEF    = 0x00000003
# -----------------------------------------------------------------
# ftusb GTM: Global Test Mode Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_GTM                   = 0x10302004
# -----------------------------------------------------------------
# ------
# TST_MODE: 
# Access RW
# Turbo mode. This bit should only be set to 1 during a simulation. When
# this bit is set to 1, FOTG330 enters the turbo mode to shorten the
# simulation time.
FTUSB_GTM_TST_MODE_BIT           = 0
FTUSB_GTM_TST_MODE_MASK          = 0x00000001
FTUSB_GTM_TST_MODE_SH            = 0
FTUSB_GTM_TST_MODE_DEF           = 0x00000000
# ------
# TST_FIFO_DEG: 
# Access RW
# FIFO debug. After setting this bit, SW can access the context of FIFO
# without affecting the read/write pointer.
FTUSB_GTM_TST_FIFO_DEG_BIT       = 1
FTUSB_GTM_TST_FIFO_DEG_MASK      = 0x00000002
FTUSB_GTM_TST_FIFO_DEG_SH        = 1
FTUSB_GTM_TST_FIFO_DEG_DEF       = 0x00000000
# ------
# TST_EP_NUM: 
# Access RW
# EP number in the debug mode. This field indicates that the context of
# Buffer Management Debug Table maps to the context of specified EP.
# This bit will be effective when TST_FIFO_DEG is set to 1.
FTUSB_GTM_TST_EP_NUM_BITS        = 4
FTUSB_GTM_TST_EP_NUM_LSB         = 4
FTUSB_GTM_TST_EP_NUM_MSB         = 7
FTUSB_GTM_TST_EP_NUM_MASK        = 0x000000f0
FTUSB_GTM_TST_EP_NUM_SH          = 4
FTUSB_GTM_TST_EP_NUM_DEF         = 0x00000000
# ------
# TST_EP_ENTRY: 
# Access RO
# EP entry in the debug mode. This filed indicates that the context of
# Buffer Management Debug Table maps to the context of specified entry
# in specified EP number. This bit will be effective when TST_FIFO_DEG
# is set to 1.
FTUSB_GTM_TST_EP_ENTRY_BITS      = 4
FTUSB_GTM_TST_EP_ENTRY_LSB       = 8
FTUSB_GTM_TST_EP_ENTRY_MSB       = 11
FTUSB_GTM_TST_EP_ENTRY_MASK      = 0x00000f00
FTUSB_GTM_TST_EP_ENTRY_SH        = 8
FTUSB_GTM_TST_EP_ENTRY_DEF       = 0x00000000
# ------
# TST_CUR_EP_ENTRY: 
# Access RW
# Number of current entries. This field indicates that the current
# operating entry in BFM for specified EP based on the value of
# TST_EP_NUM.
FTUSB_GTM_TST_CUR_EP_ENTRY_BITS  = 4
FTUSB_GTM_TST_CUR_EP_ENTRY_LSB   = 12
FTUSB_GTM_TST_CUR_EP_ENTRY_MSB   = 15
FTUSB_GTM_TST_CUR_EP_ENTRY_MASK  = 0x0000f000
FTUSB_GTM_TST_CUR_EP_ENTRY_SH    = 12
FTUSB_GTM_TST_CUR_EP_ENTRY_DEF   = 0x00000000
# ------
# TST_DIS_SOFGEN: 
# Access RW
# Disable the generation of SOF. When this bit is set to 1, FOTG330
# disables the self-generate SOF in the HS/FS mode and uses SOF issued
# by the host.
FTUSB_GTM_TST_DIS_SOFGEN_BIT     = 16
FTUSB_GTM_TST_DIS_SOFGEN_MASK    = 0x00010000
FTUSB_GTM_TST_DIS_SOFGEN_SH      = 16
FTUSB_GTM_TST_DIS_SOFGEN_DEF     = 0x00000000
# ------
# TST_FORCE_SS: 
# Access RW
# Force the SuperSpeed device. This bit informs FOTG330 to operate in
# the SuperSpeed mode. FOTG330 never operates in the HS/FS mode after
# the bit setting.
FTUSB_GTM_TST_FORCE_SS_BIT       = 17
FTUSB_GTM_TST_FORCE_SS_MASK      = 0x00020000
FTUSB_GTM_TST_FORCE_SS_SH        = 17
FTUSB_GTM_TST_FORCE_SS_DEF       = 0x00000000
# ------
# TST_FORCE_HS: 
# Access RW
# Force the High-Speed device. This bit informs FOTG330 to operate in
# the High-Speed/Full-Speed mode.
FTUSB_GTM_TST_FORCE_HS_BIT       = 18
FTUSB_GTM_TST_FORCE_HS_MASK      = 0x00040000
FTUSB_GTM_TST_FORCE_HS_SH        = 18
FTUSB_GTM_TST_FORCE_HS_DEF       = 0x00000000
# ------
# TST_FORCE_FS: 
# Access RW
# Force the Full-Speed device. This bit informs FOTG330 to operate in
# the Full-Speed mode.
FTUSB_GTM_TST_FORCE_FS_BIT       = 19
FTUSB_GTM_TST_FORCE_FS_MASK      = 0x00080000
FTUSB_GTM_TST_FORCE_FS_SH        = 19
FTUSB_GTM_TST_FORCE_FS_DEF       = 0x00000000
# -----------------------------------------------------------------
# ftusb DAR: Device Address Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_DAR                   = 0x10302008
# -----------------------------------------------------------------
# ------
# DEV_ADDR: 
# Access RW
# Device address. SW should set this field to the latest device address
# when the SET_ADDRESS request is successfully executed. This bit will
# be reset to 0 by the hot reset and warm reset in the SS mode and the
# bus reset in the HS/FS mode.
FTUSB_DAR_DEV_ADDR_BITS          = 7
FTUSB_DAR_DEV_ADDR_LSB           = 0
FTUSB_DAR_DEV_ADDR_MSB           = 6
FTUSB_DAR_DEV_ADDR_MASK          = 0x0000007f
FTUSB_DAR_DEV_ADDR_SH            = 0
FTUSB_DAR_DEV_ADDR_DEF           = 0x00000000
