# SET_CONFIG: 
# Access RW
# SET_CONFIGURATION done. SW should set this bit when SET_CONFIGURATION
# is successfully executed. Before this bit is set, FOTG330 will not
# respond to any non-control transfer. This bit will be reset to 0 by
# the hot reset and warm reset in the SS mode, and the bus reset in the
# HS/FS mode.
FTUSB_DAR_SET_CONFIG_BIT         = 7
FTUSB_DAR_SET_CONFIG_MASK        = 0x00000080
FTUSB_DAR_SET_CONFIG_SH          = 7
FTUSB_DAR_SET_CONFIG_DEF         = 0x00000000
# -----------------------------------------------------------------
# ftusb CX_CONFIG_STATUS: Control Transfer Configuration and Status
# Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_CX_CONFIG_STATUS      = 0x1030200c
# -----------------------------------------------------------------
# ------
# DX_DONE: 
# Access RW
# Data transfer is done for control transfer. This bit should be set
# when all data for this control transfer is transferred. This bit is
# cleared automatically by hardware after ACK of Status stage is
# transmitted/received to/from the host. This bit will be reset to 0 by
# the hot reset and warm reset in the SS mode and the bus reset in the
# HS/FS mode. This bit will also be cleared by the interrupts of
# cx_cmdfail_int and cx_cmdabt_int.
FTUSB_CX_CONFIG_STATUS_DX_DONE_BIT = 0
FTUSB_CX_CONFIG_STATUS_DX_DONE_MASK = 0x00000001
FTUSB_CX_CONFIG_STATUS_DX_DONE_SH = 0
FTUSB_CX_CONFIG_STATUS_DX_DONE_DEF = 0x00000000
# ------
# CX_STL: 
# Access RW
# Stall CX. Writing 1 to this bit can stall EP0, and the CX FIFO will be
# cleared at the same time. Once CX_STL is set, SW cannot access CX FIFO
# until this bit is cleared. The bit will be cleared after the SETUP
# token is received. This bit will be reset to 0 by the hot reset and
# warm reset in the SS mode, and the bus reset in the HS/FS mode.
FTUSB_CX_CONFIG_STATUS_CX_STL_BIT = 1
FTUSB_CX_CONFIG_STATUS_CX_STL_MASK = 0x00000002
FTUSB_CX_CONFIG_STATUS_CX_STL_SH = 1
FTUSB_CX_CONFIG_STATUS_CX_STL_DEF = 0x00000000
# ------
# CXF_CLR: 
# Access RW
# Clear CX FIFO data (For debugging usage only). Write 1 to clear the
# data in CX FIFO. This bit will be cleared automatically by hardware.
# Please note that when setting this bit, CX FIFO will be cleared no
# matter the previous SETUP, IN, or OUT transactions have completed or
# not.
FTUSB_CX_CONFIG_STATUS_CXF_CLR_BIT = 2
FTUSB_CX_CONFIG_STATUS_CXF_CLR_MASK = 0x00000004
FTUSB_CX_CONFIG_STATUS_CXF_CLR_SH = 2
FTUSB_CX_CONFIG_STATUS_CXF_CLR_DEF = 0x00000000
# ------
# CXF_FUL: 
# Access RO
# CX FIFO is full. 1 indicates that the CX FIFO is full.
FTUSB_CX_CONFIG_STATUS_CXF_FUL_BIT = 3
FTUSB_CX_CONFIG_STATUS_CXF_FUL_MASK = 0x00000008
FTUSB_CX_CONFIG_STATUS_CXF_FUL_SH = 3
FTUSB_CX_CONFIG_STATUS_CXF_FUL_DEF = 0x00000000
# ------
# CXF_EMP: 
# Access RO
# CX FIFO is empty. 1 indicates that the CX FIFO is empty.
FTUSB_CX_CONFIG_STATUS_CXF_EMP_BIT = 4
FTUSB_CX_CONFIG_STATUS_CXF_EMP_MASK = 0x00000010
FTUSB_CX_CONFIG_STATUS_CXF_EMP_SH = 4
FTUSB_CX_CONFIG_STATUS_CXF_EMP_DEF = 0x00000001
# ------
# CXF_LEN: 
# Access RW
# Data length of CX FIFO. For the OUT transaction, this field indicates
# the byte count of data in CX_FIFO that SW should read out. For the IN
# transaction, this field indicates the byte count of total data that SW
# should write to CX_FIFO. SW should program this field after decoding
# the 8-byte command of the SETUP transfer. After writing the total
# data, CX_DONE of SW must be set. This field will be reset to 0 by the
# hot reset and warm reset in the SS mode, and the bus reset in the
# HS/FS mode.
FTUSB_CX_CONFIG_STATUS_CXF_LEN_BITS = 16
FTUSB_CX_CONFIG_STATUS_CXF_LEN_LSB = 8
FTUSB_CX_CONFIG_STATUS_CXF_LEN_MSB = 23
FTUSB_CX_CONFIG_STATUS_CXF_LEN_MASK = 0x00ffff00
FTUSB_CX_CONFIG_STATUS_CXF_LEN_SH = 8
FTUSB_CX_CONFIG_STATUS_CXF_LEN_DEF = 0x00000000
# -----------------------------------------------------------------
# ftusb CX_PORT0: Control Trnasfer Data Port Register
# This register is part of the Device Special Purpose Registers set. SW
# can access the data in CX FIFO through the fixed address, 0x2010, or
# the burst address, 0x2010 ~ 0x201C.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_CX_PORT0              = 0x10302010
# -----------------------------------------------------------------
# ------
# CDP: 
# Access RW
# iThe Data Port of Control Transfer. SW can access the data to control
# the transfer through the data port.
FTUSB_CX_PORT0_CDP_BITS          = 32
FTUSB_CX_PORT0_CDP_LSB           = 0
FTUSB_CX_PORT0_CDP_MSB           = 31
FTUSB_CX_PORT0_CDP_MASK          = 0xffffffff
FTUSB_CX_PORT0_CDP_SH            = 0
FTUSB_CX_PORT0_CDP_DEF           = 0x00000000
# -----------------------------------------------------------------
# ftusb CX_PORT1: Control Trnasfer Data Port Register
# This register is part of the Device Special Purpose Registers set. SW
# can access the data in CX FIFO through the fixed address, 0x2010, or
# the burst address, 0x2010 ~ 0x201C.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_CX_PORT1              = 0x10302014
# -----------------------------------------------------------------
# ------
# CDP: 
# Access RW
# iThe Data Port of Control Transfer. SW can access the data to control
# the transfer through the data port.
FTUSB_CX_PORT1_CDP_BITS          = 32
FTUSB_CX_PORT1_CDP_LSB           = 0
FTUSB_CX_PORT1_CDP_MSB           = 31
FTUSB_CX_PORT1_CDP_MASK          = 0xffffffff
FTUSB_CX_PORT1_CDP_SH            = 0
FTUSB_CX_PORT1_CDP_DEF           = 0x00000000
# -----------------------------------------------------------------
# ftusb CX_PORT2: Control Trnasfer Data Port Register
# This register is part of the Device Special Purpose Registers set. SW
# can access the data in CX FIFO through the fixed address, 0x2010, or
# the burst address, 0x2010 ~ 0x201C.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_CX_PORT2              = 0x10302018
# -----------------------------------------------------------------
# ------
# CDP: 
# Access RW
# iThe Data Port of Control Transfer. SW can access the data to control
# the transfer through the data port.
FTUSB_CX_PORT2_CDP_BITS          = 32
FTUSB_CX_PORT2_CDP_LSB           = 0
FTUSB_CX_PORT2_CDP_MSB           = 31
FTUSB_CX_PORT2_CDP_MASK          = 0xffffffff
FTUSB_CX_PORT2_CDP_SH            = 0
FTUSB_CX_PORT2_CDP_DEF           = 0x00000000
# -----------------------------------------------------------------
# ftusb CX_PORT3: Control Trnasfer Data Port Register
# This register is part of the Device Special Purpose Registers set. SW
# can access the data in CX FIFO through the fixed address, 0x2010, or
# the burst address, 0x2010 ~ 0x201C.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_CX_PORT3              = 0x1030201c
# -----------------------------------------------------------------
# ------
# CDP: 
# Access RW
# iThe Data Port of Control Transfer. SW can access the data to control
# the transfer through the data port.
FTUSB_CX_PORT3_CDP_BITS          = 32
FTUSB_CX_PORT3_CDP_LSB           = 0
FTUSB_CX_PORT3_CDP_MSB           = 31
FTUSB_CX_PORT3_CDP_MASK          = 0xffffffff
FTUSB_CX_PORT3_CDP_SH            = 0
FTUSB_CX_PORT3_CDP_DEF           = 0x00000000
# -----------------------------------------------------------------
# ftusb EP0_SET0: EP0 Setting 0 Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP0_SET0              = 0x10302020
# -----------------------------------------------------------------
# ------
# EP_STL: 
# Access RW
# EPn Stall. This bit will be reset to 0 by the hot reset and warm reset
# in the SS mode, the bus reset in the HS/FS mode, and the interrupt of
# VBUS_chg_int. SW must clear the stall bit of the corresponding EP when
# receiving the command of CLEAR_FEATURE. This bit can be cleared with
# setting EPn_STL_CLR. 1: Stall this EPn 0: Not stall this EPn Note:
# Before setting this bit, SW must check if SYNC FIFO is empty for IN
# EP. It is to confirm that all data have been written to BFM. Note: For
# OUT EP, SW shall confirm if internal DMA is complete before setting
# the bit.
FTUSB_EP0_SET0_EP_STL_BIT        = 0
FTUSB_EP0_SET0_EP_STL_MASK       = 0x00000001
FTUSB_EP0_SET0_EP_STL_SH         = 0
FTUSB_EP0_SET0_EP_STL_DEF        = 0x00000000
# ------
# EP_CLR_SEQNUM: 
# Access RW
# Reset Sequence/Toggle bit of EP. SW resets the sequence number of EP
# by writing a 1 to this bit. This bit is immediately cleared by
# hardware. When SW receives the Set Configuration, Set Interface or
# ClearFeature (ENDPOINT_HALT) command, SW must reset the
# sequence/toggle bit.
FTUSB_EP0_SET0_EP_CLR_SEQNUM_BIT = 1
FTUSB_EP0_SET0_EP_CLR_SEQNUM_MASK = 0x00000002
FTUSB_EP0_SET0_EP_CLR_SEQNUM_SH  = 1
FTUSB_EP0_SET0_EP_CLR_SEQNUM_DEF = 0x00000000
# ------
# EP_STL_CLR: 
# Access RW
# EPn Stall Clear. Writing 1 to clear the register, EPn_STL. This bit is
# immediately cleared by hardware. SW writes this bit to 1 with
# receiving the command, CLEAR_FEATURE (ENDPOINT_HALT). If EPn_STL is 1,
# SW sets EPn_STL_CLR and EPn_CLR_SEQNUM must be set at the same time.
# If EPn_STL is 0, SW sets EPn_STL_CLR and EPn_CLR_SEQNUM must be set
# after 2.5 us.
FTUSB_EP0_SET0_EP_STL_CLR_BIT    = 3
FTUSB_EP0_SET0_EP_STL_CLR_MASK   = 0x00000008
FTUSB_EP0_SET0_EP_STL_CLR_SH     = 3
FTUSB_EP0_SET0_EP_STL_CLR_DEF    = 0x00000000
# -----------------------------------------------------------------
# ftusb EP0_SET1: EP0 Setting 1 Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP0_SET1              = 0x10302024
# -----------------------------------------------------------------
# ------
# EP_ACTIVE: 
# Access RW
# EPn active. 0: Disable EPn. 1: Enable EPn. When the USB host accesses
# the disabled EPn, no response will be returned.
FTUSB_EP0_SET1_EP_ACTIVE_BIT     = 0
FTUSB_EP0_SET1_EP_ACTIVE_MASK    = 0x00000001
FTUSB_EP0_SET1_EP_ACTIVE_SH      = 0
FTUSB_EP0_SET1_EP_ACTIVE_DEF     = 0x00000000
# ------
# EP_DIR: 
# Access RW
# EPn direction. 0: OUT EP. 1: IN EP.
FTUSB_EP0_SET1_EP_DIR_BIT        = 1
FTUSB_EP0_SET1_EP_DIR_MASK       = 0x00000002
FTUSB_EP0_SET1_EP_DIR_SH         = 1
FTUSB_EP0_SET1_EP_DIR_DEF        = 0x00000000
# ------
# EP_TYPE: 
# Access RW
# Transfer type. 00: Reserved 01: Isochronous 10: Bulk 11: Interrupt
FTUSB_EP0_SET1_EP_TYPE_BITS      = 2
FTUSB_EP0_SET1_EP_TYPE_LSB       = 2
FTUSB_EP0_SET1_EP_TYPE_MSB       = 3
FTUSB_EP0_SET1_EP_TYPE_MASK      = 0x0000000c
FTUSB_EP0_SET1_EP_TYPE_SH        = 2
FTUSB_EP0_SET1_EP_TYPE_DEF       = 0x00000000
# ------
# EP_BW_NUM: 
# Access RW
# Transaction number for the High-Speed ISO bandwidth. In the HS mode,
# this field indicates that the number of transactions that EP can
# service during one micro-frame.
FTUSB_EP0_SET1_EP_BW_NUM_BITS    = 2
FTUSB_EP0_SET1_EP_BW_NUM_LSB     = 4
FTUSB_EP0_SET1_EP_BW_NUM_MSB     = 5
FTUSB_EP0_SET1_EP_BW_NUM_MASK    = 0x00000030
FTUSB_EP0_SET1_EP_BW_NUM_SH      = 4
FTUSB_EP0_SET1_EP_BW_NUM_DEF     = 0x00000000
# ------
# EP_ISO_IN_PKTNUM: 
# Access RW
# The number of packets for ISO IN during each service interval in the
# SS mode. This filed indicates that the total number of packets for ISO
# IN EP will be transmitted during each service interval. This value
# should be less than 48 and the application must provide sufficient
# bandwidth for total packets during each service interval.
FTUSB_EP0_SET1_EP_ISO_IN_PKTNUM_BITS = 6
FTUSB_EP0_SET1_EP_ISO_IN_PKTNUM_LSB = 6
FTUSB_EP0_SET1_EP_ISO_IN_PKTNUM_MSB = 11
FTUSB_EP0_SET1_EP_ISO_IN_PKTNUM_MASK = 0x00000fc0
FTUSB_EP0_SET1_EP_ISO_IN_PKTNUM_SH = 6
FTUSB_EP0_SET1_EP_ISO_IN_PKTNUM_DEF = 0x00000000
# ------
# EP_FIFO_ENTRY: 
# Access RW
# The number of the FIFO entries for EPn to store the data. For the SS
# mode, the value of this field should be equal to the burst number. For
# the HS/FS mode, the value of this field should be 1, 2, or 3 for
# single, double, or triple FIFOs, respectively.
FTUSB_EP0_SET1_EP_FIFO_ENTRY_BITS = 5
FTUSB_EP0_SET1_EP_FIFO_ENTRY_LSB = 12
FTUSB_EP0_SET1_EP_FIFO_ENTRY_MSB = 16
FTUSB_EP0_SET1_EP_FIFO_ENTRY_MASK = 0x0001f000
FTUSB_EP0_SET1_EP_FIFO_ENTRY_SH  = 12
FTUSB_EP0_SET1_EP_FIFO_ENTRY_DEF = 0x00000000
# ------
# EP_START_FIFO_ENTRY: 
# Access RW
# The first index of the EP FIFO entry. This field indicates the first
# FIFO entry, and EPn starts to store the data. The formula is:
# EPn_START_FIFO_ENTRY = EPn-1_START_FIFO_ENTRY + EPn-1_FIFO_ENTRY
# Please note that the value of this field for the minimum active EP
# must be 0.
FTUSB_EP0_SET1_EP_START_FIFO_ENTRY_BITS = 8
FTUSB_EP0_SET1_EP_START_FIFO_ENTRY_LSB = 24
FTUSB_EP0_SET1_EP_START_FIFO_ENTRY_MSB = 31
FTUSB_EP0_SET1_EP_START_FIFO_ENTRY_MASK = 0xff000000
FTUSB_EP0_SET1_EP_START_FIFO_ENTRY_SH = 24
FTUSB_EP0_SET1_EP_START_FIFO_ENTRY_DEF = 0x00000000
# -----------------------------------------------------------------
# ftusb EP0_SET2: EP0 Setting 2 Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP0_SET2              = 0x10302028
# -----------------------------------------------------------------
# ------
# EP_MPS: 
# Access RW
# Max Packet Size of EPn. Maximum packet size of EPn is capable of
# sending or receiving data of less than or equal to this size.
FTUSB_EP0_SET2_EP_MPS_BITS       = 11
FTUSB_EP0_SET2_EP_MPS_LSB        = 0
FTUSB_EP0_SET2_EP_MPS_MSB        = 10
FTUSB_EP0_SET2_EP_MPS_MASK       = 0x000007ff
FTUSB_EP0_SET2_EP_MPS_SH         = 0
FTUSB_EP0_SET2_EP_MPS_DEF        = 0x00000000
# ------
# EP_FF_ADDR_OFS: 
# Access RW
# EPn Base FIFO address offset. This field indicates that EPn maps to
# the FIFO index. The formula is EPn_FF_ADDR_OFS = ((EPn-1_MPS[10:3] +
# (EPn-1_MPS[2:0] ? 1:0)) * EPn-1_FIFO_ENTRY) + EPn-1_FF_ADDR_OFS.
# Please note that the value of this field for the minimum active EP
# must be 0.
FTUSB_EP0_SET2_EP_FF_ADDR_OFS_BITS = 15
FTUSB_EP0_SET2_EP_FF_ADDR_OFS_LSB = 16
FTUSB_EP0_SET2_EP_FF_ADDR_OFS_MSB = 30
FTUSB_EP0_SET2_EP_FF_ADDR_OFS_MASK = 0x7fff0000
FTUSB_EP0_SET2_EP_FF_ADDR_OFS_SH = 16
FTUSB_EP0_SET2_EP_FF_ADDR_OFS_DEF = 0x00000000
# -----------------------------------------------------------------
# ftusb EP0_FFR: EP0 FIFO Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP0_FFR               = 0x1030202c
# -----------------------------------------------------------------
# ------
# EP_FF_BYCNT: 
# Access RW
# EPn Transfer Byte Count. For OUT, this field indicates how many data
# in the FIFO. This field only shows the byte count of one packet. For
# IN, SW must set the field to inform FOTG330 that the total byte counts
# are sent in this transfer.
FTUSB_EP0_FFR_EP_FF_BYCNT_BITS   = 21
FTUSB_EP0_FFR_EP_FF_BYCNT_LSB    = 0
FTUSB_EP0_FFR_EP_FF_BYCNT_MSB    = 20
FTUSB_EP0_FFR_EP_FF_BYCNT_MASK   = 0x001fffff
FTUSB_EP0_FFR_EP_FF_BYCNT_SH     = 0
FTUSB_EP0_FFR_EP_FF_BYCNT_DEF    = 0x00000000
# ------
# EP_TX0BYTE: 
# Access RW
# EPn Transfer 0 Byte. SW set this bit to 1 to inform FOTG330 to
# transmit the zero-length data packet. This bit will be cleared by
# hardware once the data packet is sent out. This bit will be reset to 0
# by the hot reset and warm reset in the SS mode, the bus reset in the
# HS/FS mode, and the interrupt of VBUS_chg_int.
FTUSB_EP0_FFR_EP_TX0BYTE_BIT     = 28
FTUSB_EP0_FFR_EP_TX0BYTE_MASK    = 0x10000000
FTUSB_EP0_FFR_EP_TX0BYTE_SH      = 28
FTUSB_EP0_FFR_EP_TX0BYTE_DEF     = 0x00000000
# ------
# EP_FF_EMPTY: 
# Access RO
# EPn FIFO empty.
FTUSB_EP0_FFR_EP_FF_EMPTY_BIT    = 29
FTUSB_EP0_FFR_EP_FF_EMPTY_MASK   = 0x20000000
FTUSB_EP0_FFR_EP_FF_EMPTY_SH     = 29
FTUSB_EP0_FFR_EP_FF_EMPTY_DEF    = 0x00000001
# ------
# EP_FF_FULL: 
# Access RO
# EPn FIFO full.
FTUSB_EP0_FFR_EP_FF_FULL_BIT     = 30
FTUSB_EP0_FFR_EP_FF_FULL_MASK    = 0x40000000
FTUSB_EP0_FFR_EP_FF_FULL_SH      = 30
FTUSB_EP0_FFR_EP_FF_FULL_DEF     = 0x00000000
# ------
# EP_FF_RST: 
# Access RW
# EPn FIFO reset. Writing 1 will reset all read/write pointers of EPn
# FIFO. Please note the bit of all active EPs shall be set when SW
# receives the interrupt of Set Address request.
FTUSB_EP0_FFR_EP_FF_RST_BIT      = 31
FTUSB_EP0_FFR_EP_FF_RST_MASK     = 0x80000000
FTUSB_EP0_FFR_EP_FF_RST_SH       = 31
FTUSB_EP0_FFR_EP_FF_RST_DEF      = 0x00000000
# -----------------------------------------------------------------
# ftusb EP0_STR_ID: EP0 Stream ID Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP0_STR_ID            = 0x10302040
# -----------------------------------------------------------------
# ------
# EP_STR_ID: 
# Access RW
# EPn Stream ID.
FTUSB_EP0_STR_ID_EP_STR_ID_BITS  = 16
FTUSB_EP0_STR_ID_EP_STR_ID_LSB   = 0
FTUSB_EP0_STR_ID_EP_STR_ID_MSB   = 15
FTUSB_EP0_STR_ID_EP_STR_ID_MASK  = 0x0000ffff
FTUSB_EP0_STR_ID_EP_STR_ID_SH    = 0
FTUSB_EP0_STR_ID_EP_STR_ID_DEF   = 0x00000000
# ------
# EP_STR_EN: 
# Access RW
# EPn Stream ID Enable. This bit activates the FOTG330 proposal,
# EPn_STR_ID, to host. This bit will be cleared by hardware once FOTG330
# sends out ERDY with EPn_STR_ID. This bit will be reset to 0 by the hot
# reset and the warm reset in the SS mode and the bus is reset in the
# HS/FS mode.
FTUSB_EP0_STR_ID_EP_STR_EN_BIT   = 16
FTUSB_EP0_STR_ID_EP_STR_EN_MASK  = 0x00010000
FTUSB_EP0_STR_ID_EP_STR_EN_SH    = 16
FTUSB_EP0_STR_ID_EP_STR_EN_DEF   = 0x00000000
