FTUSB_EP1_SET0_EP_CLR_SEQNUM_BIT = 1
FTUSB_EP1_SET0_EP_CLR_SEQNUM_MASK = 0x00000002
FTUSB_EP1_SET0_EP_CLR_SEQNUM_SH  = 1
FTUSB_EP1_SET0_EP_CLR_SEQNUM_DEF = 0x00000000
# ------
