FTUSB_EP1_FFR_EP_FF_RST_MASK     = 0x80000000
FTUSB_EP1_FFR_EP_FF_RST_SH       = 31
FTUSB_EP1_FFR_EP_FF_RST_DEF      = 0x00000000
# -----------------------------------------------------------------
# ftusb EP1_STR_ID: EP1 Stream ID Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP1_STR_ID            = 0x10302060
# -----------------------------------------------------------------
# ------
# EP_STR_ID: 
# Access RW
# EPn Stream ID.
