FTUSB_EP2_SET1_EP_ISO_IN_PKTNUM_BITS = 6
FTUSB_EP2_SET1_EP_ISO_IN_PKTNUM_LSB = 6
FTUSB_EP2_SET1_EP_ISO_IN_PKTNUM_MSB = 11
FTUSB_EP2_SET1_EP_ISO_IN_PKTNUM_MASK = 0x00000fc0
