# the HS/FS mode, the value of this field should be 1, 2, or 3 for
# single, double, or triple FIFOs, respectively.
FTUSB_EP2_SET1_EP_FIFO_ENTRY_BITS = 5
FTUSB_EP2_SET1_EP_FIFO_ENTRY_LSB = 12
FTUSB_EP2_SET1_EP_FIFO_ENTRY_MSB = 16
FTUSB_EP2_SET1_EP_FIFO_ENTRY_MASK = 0x0001f000
FTUSB_EP2_SET1_EP_FIFO_ENTRY_SH  = 12
FTUSB_EP2_SET1_EP_FIFO_ENTRY_DEF = 0x00000000
# ------
# EP_START_FIFO_ENTRY: 
# Access RW
# The first index of the EP FIFO entry. This field indicates the first
# FIFO entry, and EPn starts to store the data. The formula is:
