FTUSB_EP2_SET1_EP_START_FIFO_ENTRY_BITS = 8
FTUSB_EP2_SET1_EP_START_FIFO_ENTRY_LSB = 24
FTUSB_EP2_SET1_EP_START_FIFO_ENTRY_MSB = 31
FTUSB_EP2_SET1_EP_START_FIFO_ENTRY_MASK = 0xff000000
FTUSB_EP2_SET1_EP_START_FIFO_ENTRY_SH = 24
FTUSB_EP2_SET1_EP_START_FIFO_ENTRY_DEF = 0x00000000
