FTUSB_EP14_FFR_EP_TX0BYTE_SH     = 28
FTUSB_EP14_FFR_EP_TX0BYTE_DEF    = 0x00000000
# ------
# EP_FF_EMPTY: 
# Access RO
# EPn FIFO empty.
FTUSB_EP14_FFR_EP_FF_EMPTY_BIT   = 29
FTUSB_EP14_FFR_EP_FF_EMPTY_MASK  = 0x20000000
FTUSB_EP14_FFR_EP_FF_EMPTY_SH    = 29
FTUSB_EP14_FFR_EP_FF_EMPTY_DEF   = 0x00000001
# ------
# EP_FF_FULL: 
# Access RO
# EPn FIFO full.
FTUSB_EP14_FFR_EP_FF_FULL_BIT    = 30
FTUSB_EP14_FFR_EP_FF_FULL_MASK   = 0x40000000
FTUSB_EP14_FFR_EP_FF_FULL_SH     = 30
FTUSB_EP14_FFR_EP_FF_FULL_DEF    = 0x00000000
# ------
# EP_FF_RST: 
# Access RW
# EPn FIFO reset. Writing 1 will reset all read/write pointers of EPn
# FIFO. Please note the bit of all active EPs shall be set when SW
# receives the interrupt of Set Address request.
FTUSB_EP14_FFR_EP_FF_RST_BIT     = 31
FTUSB_EP14_FFR_EP_FF_RST_MASK    = 0x80000000
FTUSB_EP14_FFR_EP_FF_RST_SH      = 31
FTUSB_EP14_FFR_EP_FF_RST_DEF     = 0x00000000
# -----------------------------------------------------------------
# ftusb EP15_SET0: EP15 Setting 0 Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP15_SET0             = 0x103022f0
# -----------------------------------------------------------------
# ------
# EP_STL: 
# Access RW
# EPn Stall. This bit will be reset to 0 by the hot reset and warm reset
# in the SS mode, the bus reset in the HS/FS mode, and the interrupt of
# VBUS_chg_int. SW must clear the stall bit of the corresponding EP when
# receiving the command of CLEAR_FEATURE. This bit can be cleared with
# setting EPn_STL_CLR. 1: Stall this EPn 0: Not stall this EPn Note:
# Before setting this bit, SW must check if SYNC FIFO is empty for IN
# EP. It is to confirm that all data have been written to BFM. Note: For
# OUT EP, SW shall confirm if internal DMA is complete before setting
# the bit.
FTUSB_EP15_SET0_EP_STL_BIT       = 0
FTUSB_EP15_SET0_EP_STL_MASK      = 0x00000001
FTUSB_EP15_SET0_EP_STL_SH        = 0
FTUSB_EP15_SET0_EP_STL_DEF       = 0x00000000
# ------
# EP_CLR_SEQNUM: 
# Access RW
# Reset Sequence/Toggle bit of EP. SW resets the sequence number of EP
# by writing a 1 to this bit. This bit is immediately cleared by
# hardware. When SW receives the Set Configuration, Set Interface or
# ClearFeature (ENDPOINT_HALT) command, SW must reset the
# sequence/toggle bit.
FTUSB_EP15_SET0_EP_CLR_SEQNUM_BIT = 1
FTUSB_EP15_SET0_EP_CLR_SEQNUM_MASK = 0x00000002
FTUSB_EP15_SET0_EP_CLR_SEQNUM_SH = 1
FTUSB_EP15_SET0_EP_CLR_SEQNUM_DEF = 0x00000000
# ------
# EP_STL_CLR: 
# Access RW
# EPn Stall Clear. Writing 1 to clear the register, EPn_STL. This bit is
# immediately cleared by hardware. SW writes this bit to 1 with
# receiving the command, CLEAR_FEATURE (ENDPOINT_HALT). If EPn_STL is 1,
# SW sets EPn_STL_CLR and EPn_CLR_SEQNUM must be set at the same time.
# If EPn_STL is 0, SW sets EPn_STL_CLR and EPn_CLR_SEQNUM must be set
# after 2.5 us.
FTUSB_EP15_SET0_EP_STL_CLR_BIT   = 3
FTUSB_EP15_SET0_EP_STL_CLR_MASK  = 0x00000008
FTUSB_EP15_SET0_EP_STL_CLR_SH    = 3
FTUSB_EP15_SET0_EP_STL_CLR_DEF   = 0x00000000
# -----------------------------------------------------------------
# ftusb EP15_SET1: EP15 Setting 1 Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP15_SET1             = 0x103022f4
# -----------------------------------------------------------------
# ------
# EP_ACTIVE: 
# Access RW
# EPn active. 0: Disable EPn. 1: Enable EPn. When the USB host accesses
# the disabled EPn, no response will be returned.
FTUSB_EP15_SET1_EP_ACTIVE_BIT    = 0
FTUSB_EP15_SET1_EP_ACTIVE_MASK   = 0x00000001
FTUSB_EP15_SET1_EP_ACTIVE_SH     = 0
FTUSB_EP15_SET1_EP_ACTIVE_DEF    = 0x00000000
# ------
# EP_DIR: 
# Access RW
# EPn direction. 0: OUT EP. 1: IN EP.
FTUSB_EP15_SET1_EP_DIR_BIT       = 1
FTUSB_EP15_SET1_EP_DIR_MASK      = 0x00000002
FTUSB_EP15_SET1_EP_DIR_SH        = 1
FTUSB_EP15_SET1_EP_DIR_DEF       = 0x00000000
# ------
# EP_TYPE: 
# Access RW
# Transfer type. 00: Reserved 01: Isochronous 10: Bulk 11: Interrupt
FTUSB_EP15_SET1_EP_TYPE_BITS     = 2
FTUSB_EP15_SET1_EP_TYPE_LSB      = 2
FTUSB_EP15_SET1_EP_TYPE_MSB      = 3
FTUSB_EP15_SET1_EP_TYPE_MASK     = 0x0000000c
FTUSB_EP15_SET1_EP_TYPE_SH       = 2
FTUSB_EP15_SET1_EP_TYPE_DEF      = 0x00000000
# ------
# EP_BW_NUM: 
# Access RW
# Transaction number for the High-Speed ISO bandwidth. In the HS mode,
# this field indicates that the number of transactions that EP can
# service during one micro-frame.
FTUSB_EP15_SET1_EP_BW_NUM_BITS   = 2
FTUSB_EP15_SET1_EP_BW_NUM_LSB    = 4
FTUSB_EP15_SET1_EP_BW_NUM_MSB    = 5
FTUSB_EP15_SET1_EP_BW_NUM_MASK   = 0x00000030
FTUSB_EP15_SET1_EP_BW_NUM_SH     = 4
FTUSB_EP15_SET1_EP_BW_NUM_DEF    = 0x00000000
# ------
# EP_ISO_IN_PKTNUM: 
# Access RW
# The number of packets for ISO IN during each service interval in the
# SS mode. This filed indicates that the total number of packets for ISO
# IN EP will be transmitted during each service interval. This value
# should be less than 48 and the application must provide sufficient
# bandwidth for total packets during each service interval.
FTUSB_EP15_SET1_EP_ISO_IN_PKTNUM_BITS = 6
FTUSB_EP15_SET1_EP_ISO_IN_PKTNUM_LSB = 6
FTUSB_EP15_SET1_EP_ISO_IN_PKTNUM_MSB = 11
FTUSB_EP15_SET1_EP_ISO_IN_PKTNUM_MASK = 0x00000fc0
FTUSB_EP15_SET1_EP_ISO_IN_PKTNUM_SH = 6
FTUSB_EP15_SET1_EP_ISO_IN_PKTNUM_DEF = 0x00000000
# ------
# EP_FIFO_ENTRY: 
# Access RW
# The number of the FIFO entries for EPn to store the data. For the SS
# mode, the value of this field should be equal to the burst number. For
# the HS/FS mode, the value of this field should be 1, 2, or 3 for
# single, double, or triple FIFOs, respectively.
FTUSB_EP15_SET1_EP_FIFO_ENTRY_BITS = 5
FTUSB_EP15_SET1_EP_FIFO_ENTRY_LSB = 12
FTUSB_EP15_SET1_EP_FIFO_ENTRY_MSB = 16
FTUSB_EP15_SET1_EP_FIFO_ENTRY_MASK = 0x0001f000
FTUSB_EP15_SET1_EP_FIFO_ENTRY_SH = 12
FTUSB_EP15_SET1_EP_FIFO_ENTRY_DEF = 0x00000000
# ------
# EP_START_FIFO_ENTRY: 
# Access RW
# The first index of the EP FIFO entry. This field indicates the first
# FIFO entry, and EPn starts to store the data. The formula is:
# EPn_START_FIFO_ENTRY = EPn-1_START_FIFO_ENTRY + EPn-1_FIFO_ENTRY
# Please note that the value of this field for the minimum active EP
# must be 0.
FTUSB_EP15_SET1_EP_START_FIFO_ENTRY_BITS = 8
FTUSB_EP15_SET1_EP_START_FIFO_ENTRY_LSB = 24
FTUSB_EP15_SET1_EP_START_FIFO_ENTRY_MSB = 31
FTUSB_EP15_SET1_EP_START_FIFO_ENTRY_MASK = 0xff000000
FTUSB_EP15_SET1_EP_START_FIFO_ENTRY_SH = 24
FTUSB_EP15_SET1_EP_START_FIFO_ENTRY_DEF = 0x00000000
# -----------------------------------------------------------------
# ftusb EP15_SET2: EP15 Setting 2 Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP15_SET2             = 0x103022f8
# -----------------------------------------------------------------
# ------
# EP_MPS: 
# Access RW
# Max Packet Size of EPn. Maximum packet size of EPn is capable of
# sending or receiving data of less than or equal to this size.
FTUSB_EP15_SET2_EP_MPS_BITS      = 11
FTUSB_EP15_SET2_EP_MPS_LSB       = 0
FTUSB_EP15_SET2_EP_MPS_MSB       = 10
FTUSB_EP15_SET2_EP_MPS_MASK      = 0x000007ff
FTUSB_EP15_SET2_EP_MPS_SH        = 0
FTUSB_EP15_SET2_EP_MPS_DEF       = 0x00000000
# ------
# EP_FF_ADDR_OFS: 
# Access RW
# EPn Base FIFO address offset. This field indicates that EPn maps to
# the FIFO index. The formula is EPn_FF_ADDR_OFS = ((EPn-1_MPS[10:3] +
# (EPn-1_MPS[2:0] ? 1:0)) * EPn-1_FIFO_ENTRY) + EPn-1_FF_ADDR_OFS.
# Please note that the value of this field for the minimum active EP
# must be 0.
FTUSB_EP15_SET2_EP_FF_ADDR_OFS_BITS = 15
FTUSB_EP15_SET2_EP_FF_ADDR_OFS_LSB = 16
FTUSB_EP15_SET2_EP_FF_ADDR_OFS_MSB = 30
FTUSB_EP15_SET2_EP_FF_ADDR_OFS_MASK = 0x7fff0000
FTUSB_EP15_SET2_EP_FF_ADDR_OFS_SH = 16
FTUSB_EP15_SET2_EP_FF_ADDR_OFS_DEF = 0x00000000
# -----------------------------------------------------------------
# ftusb EP15_FFR: EP15 FIFO Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_EP15_FFR              = 0x103022fc
# -----------------------------------------------------------------
# ------
# EP_FF_BYCNT: 
# Access RW
# EPn Transfer Byte Count. For OUT, this field indicates how many data
# in the FIFO. This field only shows the byte count of one packet. For
# IN, SW must set the field to inform FOTG330 that the total byte counts
# are sent in this transfer.
FTUSB_EP15_FFR_EP_FF_BYCNT_BITS  = 21
FTUSB_EP15_FFR_EP_FF_BYCNT_LSB   = 0
FTUSB_EP15_FFR_EP_FF_BYCNT_MSB   = 20
FTUSB_EP15_FFR_EP_FF_BYCNT_MASK  = 0x001fffff
FTUSB_EP15_FFR_EP_FF_BYCNT_SH    = 0
FTUSB_EP15_FFR_EP_FF_BYCNT_DEF   = 0x00000000
# ------
# EP_TX0BYTE: 
# Access RW
# EPn Transfer 0 Byte. SW set this bit to 1 to inform FOTG330 to
# transmit the zero-length data packet. This bit will be cleared by
# hardware once the data packet is sent out. This bit will be reset to 0
# by the hot reset and warm reset in the SS mode, the bus reset in the
# HS/FS mode, and the interrupt of VBUS_chg_int.
FTUSB_EP15_FFR_EP_TX0BYTE_BIT    = 28
FTUSB_EP15_FFR_EP_TX0BYTE_MASK   = 0x10000000
FTUSB_EP15_FFR_EP_TX0BYTE_SH     = 28
FTUSB_EP15_FFR_EP_TX0BYTE_DEF    = 0x00000000
# ------
# EP_FF_EMPTY: 
# Access RO
# EPn FIFO empty.
FTUSB_EP15_FFR_EP_FF_EMPTY_BIT   = 29
FTUSB_EP15_FFR_EP_FF_EMPTY_MASK  = 0x20000000
FTUSB_EP15_FFR_EP_FF_EMPTY_SH    = 29
FTUSB_EP15_FFR_EP_FF_EMPTY_DEF   = 0x00000001
# ------
# EP_FF_FULL: 
# Access RO
# EPn FIFO full.
FTUSB_EP15_FFR_EP_FF_FULL_BIT    = 30
FTUSB_EP15_FFR_EP_FF_FULL_MASK   = 0x40000000
FTUSB_EP15_FFR_EP_FF_FULL_SH     = 30
FTUSB_EP15_FFR_EP_FF_FULL_DEF    = 0x00000000
# ------
# EP_FF_RST: 
# Access RW
# EPn FIFO reset. Writing 1 will reset all read/write pointers of EPn
# FIFO. Please note the bit of all active EPs shall be set when SW
# receives the interrupt of Set Address request.
FTUSB_EP15_FFR_EP_FF_RST_BIT     = 31
FTUSB_EP15_FFR_EP_FF_RST_MASK    = 0x80000000
FTUSB_EP15_FFR_EP_FF_RST_SH      = 31
FTUSB_EP15_FFR_EP_FF_RST_DEF     = 0x00000000
# -----------------------------------------------------------------
# ftusb HS_PTM: HS PHY Test Mode Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_HS_PTM                = 0x10302300
# -----------------------------------------------------------------
# ------
# TST_JSTA: 
# Access RW
# Writing 1 to this bit, D+/D- is set to the High-Speed J state.
# Programming Sequence for Test_J 1. Received SET_FEATURE (Test_J)
# request. 2. SW must set TST_JSTA after receiving SET_FEATURE (Test_J)
# request. Set CX_DONE. This bit shall set before setting CX_DONE for
# the Control request with TEST_MODE set.
FTUSB_HS_PTM_TST_JSTA_BIT        = 0
FTUSB_HS_PTM_TST_JSTA_MASK       = 0x00000001
FTUSB_HS_PTM_TST_JSTA_SH         = 0
FTUSB_HS_PTM_TST_JSTA_DEF        = 0x00000000
# ------
# TST_KSTA: 
# Access RW
# Writing 1 to this bit, D+/D- is set to the High-Speed K state.
# Programming sequence for Test_K is as follows: 1. Received SET_FEATURE
# (Test_K) request. 2. SW must set TST_KSTA after receiving SET_FEATURE
# (Test_K) request. Set CX_DONE. This bit shall set before setting
# CX_DONE for the Control request with TEST_MODE set.
FTUSB_HS_PTM_TST_KSTA_BIT        = 1
FTUSB_HS_PTM_TST_KSTA_MASK       = 0x00000002
FTUSB_HS_PTM_TST_KSTA_SH         = 1
FTUSB_HS_PTM_TST_KSTA_DEF        = 0x00000000
# ------
# TST_SE0NAK: 
# Access RW
# Writing 1 to this bit, the D+/D- lines will be set to HS at the
# quiescent state. The device only responds to a valid HS IN token and
# always responds to the IN token with NAK. Programming sequence for
# Test_SE0_NAK is as follows: Receive SET_FEATURE(Test_SE0_NAK) request
# SW must set TST_SE0NAK after receiving SET_FEATURE (Test_SE0_NAK)
# request. Set CX_DONE This bit shall set before setting CX_DONE for the
# Control request with TEST_MODE set.
FTUSB_HS_PTM_TST_SE0NAK_BIT      = 2
FTUSB_HS_PTM_TST_SE0NAK_MASK     = 0x00000004
FTUSB_HS_PTM_TST_SE0NAK_SH       = 2
FTUSB_HS_PTM_TST_SE0NAK_DEF      = 0x00000000
# ------
# TST_PKT: 
# Access RW
# Test mode for packet. Writing 1 to this bit, FOTG330 will repeatedly
# send the packet defined in the UTMI specification to the transceiver.
# Programming sequence for Test_Packet is as follows: 1. Device shall be
# at the configured state by bus enumeration. 2. SW must set the bit
# after receiving SET_FEATURE (Test_Packet) request. 3. Set CX_DONE
# Software shall prepare the data payload of test packet and write to
# CX_FIFO. After the SET_FEATURE command shows the test mode and the
# Test_Packet index is decoded, SW must program this bit to 1. This bit
# shall be set before setting CX_DONE for the Control request with
# TEST_MODE set. Software shall prepare the data payload of test packet
# and write to CX_FIFO after setting the bit and CX_DONE.
FTUSB_HS_PTM_TST_PKT_BIT         = 3
FTUSB_HS_PTM_TST_PKT_MASK        = 0x00000008
FTUSB_HS_PTM_TST_PKT_SH          = 3
FTUSB_HS_PTM_TST_PKT_DEF         = 0x00000000
# -----------------------------------------------------------------
# ftusb HS_CR: HS Control Register
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_HS_CR                 = 0x10302304
# -----------------------------------------------------------------
# ------
# IDLE_CNT: 
# Access RW
# This bit controls the timing delay from the time indicated in the
# HS_GOSUSP bit to the time when FOTG330 enters a suspend mode. For
# reference, the delay is denoted as tsusp_delay in the list below:
# 0b000: tsusp_delay = 0 ms 0b001: tsusp_delay = 1.0 ms 0b010:
# tsusp_delay = 2.0 ms 0b011: tsusp_delay = 3.0 ms 0b100: tsusp_delay =
# 4.0 ms 0b101: tsusp_delay = 5.0 ms 0b110: tsusp_delay = 6.0 ms 0b111:
# tsusp_delay = 7.0 ms Please note that the USB 2.0 specification
# defines T2SUSP to mandate that the device should enter the suspend
# mode no later than 10 ms after D+/D- is continuously at the idle state
# for more than 3.0 ms. SW programmer should be cautious when
# programming the value of tsusp_delay.
FTUSB_HS_CR_IDLE_CNT_BITS        = 3
FTUSB_HS_CR_IDLE_CNT_LSB         = 0
FTUSB_HS_CR_IDLE_CNT_MSB         = 2
FTUSB_HS_CR_IDLE_CNT_MASK        = 0x00000007
FTUSB_HS_CR_IDLE_CNT_SH          = 0
FTUSB_HS_CR_IDLE_CNT_DEF         = 0x00000000
# ------
# CAP_RMWKUP: 
# Access RW
# Remote Wake-up Capability. Writing 1 to this bit indicates that
# FOTG330 can be woken up by HS_GORMWKUP. SW programs this bit after
# receiving the SET_FEATURE command when the Feature Selector is
# DEVICE_REMOTE_WAKEUP.
FTUSB_HS_CR_CAP_RMWKUP_BIT       = 3
FTUSB_HS_CR_CAP_RMWKUP_MASK      = 0x00000008
FTUSB_HS_CR_CAP_RMWKUP_SH        = 3
FTUSB_HS_CR_CAP_RMWKUP_DEF       = 0x00000000
# ------
# HS_GORMWKUP: 
# Access RW
# HS Go Remote Wake-up. Writing 1 to this bit activates FOTG330 to
# remote wakeup from the suspend state and this bit is effective when
# CAP_RMWKUP is active. This bit will be cleared automatically after
# FOTG330 has been woken up from suspend. This bit will be reset to 0 by
# the bus reset in the HS/FS mode.
FTUSB_HS_CR_HS_GORMWKUP_BIT      = 4
FTUSB_HS_CR_HS_GORMWKUP_MASK     = 0x00000010
FTUSB_HS_CR_HS_GORMWKUP_SH       = 4
FTUSB_HS_CR_HS_GORMWKUP_DEF      = 0x00000000
# ------
# HS_GOSUSP: 
# Access RW
# HS Go Suspend. Writing 1 to this bit activates the suspend mode. This
# bit will be cleared automatically after FOTG330 has been woken up from
# suspend. This bit will be reset to 0 by the bus reset in the HS/FS
# mode.
FTUSB_HS_CR_HS_GOSUSP_BIT        = 5
FTUSB_HS_CR_HS_GOSUSP_MASK       = 0x00000020
FTUSB_HS_CR_HS_GOSUSP_SH         = 5
FTUSB_HS_CR_HS_GOSUSP_DEF        = 0x00000000
# ------
# CAP_LPM_RMWKUP: 
# Access RW
# Capability of Remote Wake-up from LPM. This bit is set by host with
# the LPM token. SW can check this bit whether the host permits the
# device to the initial remote wakeup.
FTUSB_HS_CR_CAP_LPM_RMWKUP_BIT   = 6
FTUSB_HS_CR_CAP_LPM_RMWKUP_MASK  = 0x00000040
FTUSB_HS_CR_CAP_LPM_RMWKUP_SH    = 6
FTUSB_HS_CR_CAP_LPM_RMWKUP_DEF   = 0x00000000
# ------
# HS_LPM_RMWKUP: 
# Access RW
# Remote Wake-up from LPM. Writing 1 to this bit activates FOTG330 to
# remove the wakeup from the LPM state and this bit is effective when
# CAP_LPM_RMWKUP is active. This bit will be automatically cleared after
# FOTG330 has been woken up from LPM. This bit will be reset to ?0? by
# the bus reset in the HS/FS mode.
FTUSB_HS_CR_HS_LPM_RMWKUP_BIT    = 7
FTUSB_HS_CR_HS_LPM_RMWKUP_MASK   = 0x00000080
FTUSB_HS_CR_HS_LPM_RMWKUP_SH     = 7
FTUSB_HS_CR_HS_LPM_RMWKUP_DEF    = 0x00000000
# ------
# HS_LPM_PERMIT: 
# Access RW
# HS LPM Permission. 1 permits FOTG330 to respond ACK based on whether
# BFM has pending data or not. 0 indicates FOTG330 always responds NYET
# for the LPM request of the host.
FTUSB_HS_CR_HS_LPM_PERMIT_BIT    = 8
FTUSB_HS_CR_HS_LPM_PERMIT_MASK   = 0x00000100
FTUSB_HS_CR_HS_LPM_PERMIT_SH     = 8
FTUSB_HS_CR_HS_LPM_PERMIT_DEF    = 0x00000000
# ------
# LPM_BESL: 
# Access RO
# HS LPM BESL. Upon FOTG330 response ACK for LPM Token, this value will
# be updated with receiving LPM Token BESL field.
FTUSB_HS_CR_LPM_BESL_BITS        = 4
FTUSB_HS_CR_LPM_BESL_LSB         = 9
FTUSB_HS_CR_LPM_BESL_MSB         = 12
FTUSB_HS_CR_LPM_BESL_MASK        = 0x00001e00
FTUSB_HS_CR_LPM_BESL_SH          = 9
FTUSB_HS_CR_LPM_BESL_DEF         = 0x00000000
# ------
# LPM_BESL_PERMIT_MINT: 
# Access RW
# Minimum BESL for LPM Permission. If LPM BESL is smaller than this
# field, FOTG330 will response NYET to reject the LPM request. LPM
# permit condition: HS_LPM_PERMIT = 1 and (LPM_BESL_PERMIT_MIN <
# LPM_BESL < LPM_BESL_PERMIT_MAX).
FTUSB_HS_CR_LPM_BESL_PERMIT_MINT_BITS = 4
FTUSB_HS_CR_LPM_BESL_PERMIT_MINT_LSB = 13
FTUSB_HS_CR_LPM_BESL_PERMIT_MINT_MSB = 16
FTUSB_HS_CR_LPM_BESL_PERMIT_MINT_MASK = 0x0001e000
FTUSB_HS_CR_LPM_BESL_PERMIT_MINT_SH = 13
FTUSB_HS_CR_LPM_BESL_PERMIT_MINT_DEF = 0x00000000
# ------
# LPSM_BESL_PERMIT_MAX: 
# Access RW
# Maximum BESL for LPM Permission. If LPM BESL is larger than this
# field, FOTG330 will response NYET to reject the LPM request. LPM
# permit condition: HS_LPM_PERMIT = 1 and (LPM_BESL_PERMIT_MIN <
# LPM_BESL < LPM_BESL_PERMIT_MAX)
FTUSB_HS_CR_LPSM_BESL_PERMIT_MAX_BITS = 4
FTUSB_HS_CR_LPSM_BESL_PERMIT_MAX_LSB = 17
FTUSB_HS_CR_LPSM_BESL_PERMIT_MAX_MSB = 20
FTUSB_HS_CR_LPSM_BESL_PERMIT_MAX_MASK = 0x001e0000
FTUSB_HS_CR_LPSM_BESL_PERMIT_MAX_SH = 17
FTUSB_HS_CR_LPSM_BESL_PERMIT_MAX_DEF = 0x0000000f
# ------
# HW_LPM_RMWKUP_IN: 
# Access RW
# Enable Hardware LPM remote wakeup for IN transfer. If in transfer is
# in the flow control and this bit is 1, FOTG330 will issue remote
# wakeup to leave LPM state when IN traffic is ready and CAP_LPM_RMWKUP
# is active.
FTUSB_HS_CR_HW_LPM_RMWKUP_IN_BIT = 21
FTUSB_HS_CR_HW_LPM_RMWKUP_IN_MASK = 0x00200000
FTUSB_HS_CR_HW_LPM_RMWKUP_IN_SH  = 21
FTUSB_HS_CR_HW_LPM_RMWKUP_IN_DEF = 0x00000000
# ------
# HW_LPM_RMWKUP_OUT: 
# Access RW
# Enable Hardware LPM remote wakeup for OUT transfer. If out transfer is
# in the flow control and this bit is 1, FOTG330 will issue remote
# wakeup to leave LPM state when OUT buffer is ready and CAP_LPM_RMWKUP
# is active.
FTUSB_HS_CR_HW_LPM_RMWKUP_OUT_BIT = 22
FTUSB_HS_CR_HW_LPM_RMWKUP_OUT_MASK = 0x00400000
FTUSB_HS_CR_HW_LPM_RMWKUP_OUT_SH = 22
FTUSB_HS_CR_HW_LPM_RMWKUP_OUT_DEF = 0x00000000
# ------
# HW_LPM_RMWKUP_CX: 
# Access RW
# Enable Hardware LPM remote wakeup for Control Status Stage. If control
# transfer is in the flow control and this bit is 1, FOTG330 will issue
# remote wakeup to leave LPM state when CX_DONE and CAP_LPM_RMWKUP are
# active.
FTUSB_HS_CR_HW_LPM_RMWKUP_CX_BIT = 23
FTUSB_HS_CR_HW_LPM_RMWKUP_CX_MASK = 0x00800000
FTUSB_HS_CR_HW_LPM_RMWKUP_CX_SH  = 23
FTUSB_HS_CR_HW_LPM_RMWKUP_CX_DEF = 0x00000000
# ------
# HW_LPM_REJECT_IN: 
# Access RW
# Enable HW LPM reject for IN transfer. If this bit is 1, FOTG330 will
# response NYET to reject LPM request if there is no flow control during
# IN transfer. When SW sets one bit of the bit[26:24], other bits shall
# be set simultaneously.
