FTUSB_HS_CR_HW_LPM_REJECT_OUT_MASK = 0x02000000
FTUSB_HS_CR_HW_LPM_REJECT_OUT_SH = 25
FTUSB_HS_CR_HW_LPM_REJECT_OUT_DEF = 0x00000000
# ------
