# control during command done. Please note that when SW sets one bit of
# the bit[26:24], , other bits shall be set simultaneously.
FTUSB_HS_CR_HW_LPM_REJECT_CX_BIT = 26
FTUSB_HS_CR_HW_LPM_REJECT_CX_MASK = 0x04000000
FTUSB_HS_CR_HW_LPM_REJECT_CX_SH  = 26
FTUSB_HS_CR_HW_LPM_REJECT_CX_DEF = 0x00000000
# -----------------------------------------------------------------
# ftusb SS_CR0: SS Control Register 0
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_SS_CR0                = 0x10302308
# -----------------------------------------------------------------
# ------
# U1_FUN_EN: 
# Access RW
# U1 Function Enable. AP must program this bit when AP receives the EP0
# SET_FEATURE command with U1_ENABLE. This bit will enable
# U1_TIMEOUT_TIMER. Once U1_TIMEOUT_TIMER is time out, FOTG330 will
# actively initiate LGO_U1 to the link partner. This bit will be reset
# to 0 by the hot reset or warm reset in the SS mode.
FTUSB_SS_CR0_U1_FUN_EN_BIT       = 0
FTUSB_SS_CR0_U1_FUN_EN_MASK      = 0x00000001
FTUSB_SS_CR0_U1_FUN_EN_SH        = 0
FTUSB_SS_CR0_U1_FUN_EN_DEF       = 0x00000000
# ------
# U2_FUN_EN: 
# Access RW
# U2 Function Enable. AP must program this bit when AP receives the EP0
# SET_FEATURE command with U2_ENABLE. This bit will enable
# U2_TIMEOUT_TIMER. Once U2_TIMEOUT_TIMER is time out, FOTG330 will
# actively initiate LGO_U2 to the link partner. This bit will be reset
# to 0 by the hot reset or warm reset in the SS mode.
FTUSB_SS_CR0_U2_FUN_EN_BIT       = 1
FTUSB_SS_CR0_U2_FUN_EN_MASK      = 0x00000002
FTUSB_SS_CR0_U2_FUN_EN_SH        = 1
FTUSB_SS_CR0_U2_FUN_EN_DEF       = 0x00000000
