# MAX_SINT: 
# Access RW
# Maximum Service Interval. This field indicates the maximum service
# interval between each ISO EP.
FTUSB_SS_CR0_MAX_SINT_BITS       = 3
FTUSB_SS_CR0_MAX_SINT_LSB        = 4
FTUSB_SS_CR0_MAX_SINT_MSB        = 6
FTUSB_SS_CR0_MAX_SINT_MASK       = 0x00000070
FTUSB_SS_CR0_MAX_SINT_SH         = 4
FTUSB_SS_CR0_MAX_SINT_DEF        = 0x00000000
# ------
# SSI_EN: 
# Access RW
# Support Smart ISO Enable. The field indicates whether FOTG330 performs
# SSI or not. All SSI contexts sent from host are ignored if the bit is
# set to 0. Please note that transiting the bit from 1 to 0 makes
# FOTG330 to automatically clear all SSI information received before. 0:
# Disable SSI 1: Enable SSI
FTUSB_SS_CR0_SSI_EN_BIT          = 7
FTUSB_SS_CR0_SSI_EN_MASK         = 0x00000080
FTUSB_SS_CR0_SSI_EN_SH           = 7
FTUSB_SS_CR0_SSI_EN_DEF          = 0x00000000
# ------
# SSI_WAKEUP_DELAY: 
# Access RW
# This field indicates that the time FOTG330 needs to wake up from U2 to
# U0. The unit is a bus-interval (125 us). Please note that the wake-up
# time is related to the characteristics of PHY. 0b00: Zero bus-
# interval. 0b01: One bus-interval (125 us). 0b10: Two bus-intervals
# (250 us). 0b11: Three bus-intervals (375 us).
FTUSB_SS_CR0_SSI_WAKEUP_DELAY_BITS = 2
FTUSB_SS_CR0_SSI_WAKEUP_DELAY_LSB = 8
FTUSB_SS_CR0_SSI_WAKEUP_DELAY_MSB = 9
FTUSB_SS_CR0_SSI_WAKEUP_DELAY_MASK = 0x00000300
FTUSB_SS_CR0_SSI_WAKEUP_DELAY_SH = 8
FTUSB_SS_CR0_SSI_WAKEUP_DELAY_DEF = 0x00000001
# -----------------------------------------------------------------
# ftusb SS_CR1: SS Control Register 1
# This register is part of the Device Special Purpose Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_SS_CR1                = 0x1030230c
# -----------------------------------------------------------------
# ------
# U1_ENTRY_EN: 
# Access RW
# Device Active U1 Entry Enable. When this bit is set, the device will
# actively send out the LGO_U1 command to request the link partner to
# enter to the U1 state. The value is effective no matter U1_FUN_EN sets
# to 1 or not. This bit is cleared by hardware when the interrupt of
# U1_ENTRY_INT is set. This bit will be reset to 0 by the hot reset or
# warm reset in the SS mode.
