FTUSB_SS_CR1_U1_ENTRY_EN_MASK    = 0x00000001
FTUSB_SS_CR1_U1_ENTRY_EN_SH      = 0
FTUSB_SS_CR1_U1_ENTRY_EN_DEF     = 0x00000000
# ------
# U2_ENTRY_EN: 
# Access RW
# Device Active U2 Entry Enable. When this bit is set, the device will
# actively send out the LGO_U2 command to request the link partner to
# enter to the U2 state. The value is effective no matter U2_FUN_EN sets
# to 1 or not. This bit is cleared by hardware when the interrupt of
# U2_ENTRY_INT is set. This bit will be reset to 0 by the hot reset or
# warm reset in the SS mode.
FTUSB_SS_CR1_U2_ENTRY_EN_BIT     = 1
FTUSB_SS_CR1_U2_ENTRY_EN_MASK    = 0x00000002
FTUSB_SS_CR1_U2_ENTRY_EN_SH      = 1
FTUSB_SS_CR1_U2_ENTRY_EN_DEF     = 0x00000000
# ------
# U1_EXIT_EN: 
# Access RW
# Device Active U1 Exit Enable. When this bit is set, the device will
# actively assert U1 Exit LFPS. This bit is cleared by hardware when the
# interrupt of U1_EXIT_INT or U1_EXIT_FAIL_INT is set. This bit is also
# reset to 0 by the hot reset or warm reset in the SS mode.
FTUSB_SS_CR1_U1_EXIT_EN_BIT      = 2
FTUSB_SS_CR1_U1_EXIT_EN_MASK     = 0x00000004
FTUSB_SS_CR1_U1_EXIT_EN_SH       = 2
FTUSB_SS_CR1_U1_EXIT_EN_DEF      = 0x00000000
# ------
# U2_EXIT_EN: 
# Access RW
# Device Active U2 Exit Enable. When this bit is set, the device will
# actively assert U2 Exit LFPS. This bit is cleared by hardware when the
# interrupt of U2_EXIT_INT or U2_EXIT_FAIL_INT is set. This bit is also
# reset to 0 by the hot reset or warm reset in the SS mode.
FTUSB_SS_CR1_U2_EXIT_EN_BIT      = 3
FTUSB_SS_CR1_U2_EXIT_EN_MASK     = 0x00000008
FTUSB_SS_CR1_U2_EXIT_EN_SH       = 3
FTUSB_SS_CR1_U2_EXIT_EN_DEF      = 0x00000000
# ------
# U3_WAKEUP_EN: 
# Access RW
# Device actively U3 Wake-up Enable. When this bit is set, the device
# will actively assert the U3 wakeup LFPS. This bit is cleared by
# hardware when the interrupt of U3_EXIT_INT or U3_EXIT_FAIL_INT is set.
# This bit is also reset to 0 by the hot reset or warm reset in the SS
# mode.
FTUSB_SS_CR1_U3_WAKEUP_EN_BIT    = 4
FTUSB_SS_CR1_U3_WAKEUP_EN_MASK   = 0x00000010
FTUSB_SS_CR1_U3_WAKEUP_EN_SH     = 4
FTUSB_SS_CR1_U3_WAKEUP_EN_DEF    = 0x00000000
# ------
# FORCE_RECOVERY: 
# Access RW
