# immediately force LTSSM from U0 to Recovery.
FTUSB_SS_CR1_FORCE_RECOVERY_BIT  = 5
FTUSB_SS_CR1_FORCE_RECOVERY_MASK = 0x00000020
FTUSB_SS_CR1_FORCE_RECOVERY_SH   = 5
FTUSB_SS_CR1_FORCE_RECOVERY_DEF  = 0x00000000
# ------
