FTUSB_SS_CR1_GO_U3_DONE_BIT      = 8
FTUSB_SS_CR1_GO_U3_DONE_MASK     = 0x00000100
FTUSB_SS_CR1_GO_U3_DONE_SH       = 8
FTUSB_SS_CR1_GO_U3_DONE_DEF      = 0x00000000
