FTUSB_SS_CR1_TXDEEMPH_LEVEL_BITS = 2
FTUSB_SS_CR1_TXDEEMPH_LEVEL_LSB  = 9
FTUSB_SS_CR1_TXDEEMPH_LEVEL_MSB  = 10
FTUSB_SS_CR1_TXDEEMPH_LEVEL_MASK = 0x00000600
FTUSB_SS_CR1_TXDEEMPH_LEVEL_SH   = 9
FTUSB_SS_CR1_TXDEEMPH_LEVEL_DEF  = 0x00000001
