# ftusb IGR1: Interrupt Group 1 Register
# This register is part of the Interrupt Source Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_IGR1                  = 0x10302404
# -----------------------------------------------------------------
# ------
# INT_GRP2: 
# Access RO
# Some interrupts occurred in the Interrupt Group 2 Register.
FTUSB_IGR1_INT_GRP2_BIT          = 0
FTUSB_IGR1_INT_GRP2_MASK         = 0x00000001
FTUSB_IGR1_INT_GRP2_SH           = 0
FTUSB_IGR1_INT_GRP2_DEF          = 0x00000000
# ------
# INT_GRP3: 
# Access RO
# Some interrupts occurred in the Interrupt Group 3 Register.
FTUSB_IGR1_INT_GRP3_BIT          = 1
FTUSB_IGR1_INT_GRP3_MASK         = 0x00000002
FTUSB_IGR1_INT_GRP3_SH           = 1
FTUSB_IGR1_INT_GRP3_DEF          = 0x00000000
# ------
# INT_GRP4: 
# Access RO
# Some interrupts occurred in the Interrupt Group 4 Register.
FTUSB_IGR1_INT_GRP4_BIT          = 2
FTUSB_IGR1_INT_GRP4_MASK         = 0x00000004
FTUSB_IGR1_INT_GRP4_SH           = 2
FTUSB_IGR1_INT_GRP4_DEF          = 0x00000000
# ------
# CX_SETUP_INT: 
# Access RO
# This bit indicates that FOTG330 successfully receives the SETUP packet
# and SW can read eight-byte command from CXF. This bit will remain
# asserted until SW starts to read data from the control transfer FIFO
# (CXF) of FOTG330.
FTUSB_IGR1_CX_SETUP_INT_BIT      = 3
FTUSB_IGR1_CX_SETUP_INT_MASK     = 0x00000008
FTUSB_IGR1_CX_SETUP_INT_SH       = 3
FTUSB_IGR1_CX_SETUP_INT_DEF      = 0x00000000
# ------
# CX_IN_INT: 
# Access RO
# This bit indicates that SW should write data for the control-read
# transfer to the control transfer FIFO. For a control-read with length
# less than, or equal to the maximum packet size of EP0, this bit will
# never be asserted. SW will decode the 8-byte data sent in the SETUP
# stage of the control transfer and directly write the first data
# payload into the control transfer FIFO This bit will be asserted only
# when the length of the control-read transfer is longer than 64
# bytes/512 bytes basedon HS/SS and USB host has successfully received
# the data of the previous packet. For example: For a 65-byte control-
# read transfer for HS, SW should automatically write the first 64 bytes
# after decoding eight bytes of the SETUP data. SW will be interrupted
# to write the 65th byte when the USB host ACKs to the first 64 bytes.
# For a 513-byte control-read transfer for SS, SW should automatically
# write the first 512-byte and will be interrupted to write the 513th
# byte when the USB host ACKs to the first 512 bytes. This bit will
# remain asserted until SW starts to write data into the control
# transfer FIFO (CXF) of FOTG330. For the stall condition, this bit will
# be cleared after SW sets the CX_STL bit of the CX_Config_Status
# register.
FTUSB_IGR1_CX_IN_INT_BIT         = 4
FTUSB_IGR1_CX_IN_INT_MASK        = 0x00000010
FTUSB_IGR1_CX_IN_INT_SH          = 4
FTUSB_IGR1_CX_IN_INT_DEF         = 0x00000000
# ------
# CX_OUT_INT: 
# Access RO
# This bit indicates that the control transfer contains valid data for
# the control-write transfers. This bit will remain asserted until SW
# starts to read the data from the control transfer FIFO (CXF) of
# FOTG330. For the stall condition, this bit will be cleared after SW
# sets the CX_STL bit of the CX_Config_Status register.
FTUSB_IGR1_CX_OUT_INT_BIT        = 5
FTUSB_IGR1_CX_OUT_INT_MASK       = 0x00000020
FTUSB_IGR1_CX_OUT_INT_SH         = 5
FTUSB_IGR1_CX_OUT_INT_DEF        = 0x00000000
# ------
# CX_CMDEND_INT: 
# Access RO
# This bit indicates that the control transfer has entered the status
# stage. This bit will remain asserted until SW sets the CX_DONE bit or
# CX_STL bit of the CX CX_Config_Status register.
FTUSB_IGR1_CX_CMDEND_INT_BIT     = 6
FTUSB_IGR1_CX_CMDEND_INT_MASK    = 0x00000040
FTUSB_IGR1_CX_CMDEND_INT_SH      = 6
FTUSB_IGR1_CX_CMDEND_INT_DEF     = 0x00000000
# ------
# CX_CMDFAIL_INT: 
# Access RO
# This bit indicates that the control transfer has terminated
# abnormally. This bit will be asserted when FOTG330 receives an extra
# IN/OUT token, comparing the wLength in packet and the real length of
# packet, at the control data stage of a transfer. Once this bit is
# asserted, it will be kept at 1 before the SW sets the CX_STL bit of
# the CX_Config_Status register or receives new SETUP packet.
# CX_COMFAIL_INT and CX_FIFO will be both cleared automatically by HW
# after SW sets CX_STL.
FTUSB_IGR1_CX_CMDFAIL_INT_BIT    = 7
FTUSB_IGR1_CX_CMDFAIL_INT_MASK   = 0x00000080
FTUSB_IGR1_CX_CMDFAIL_INT_SH     = 7
FTUSB_IGR1_CX_CMDFAIL_INT_DEF    = 0x00000000
# ------
# CX_CMDABT_INT: 
# Access W1C
# This bit indicates that a command abort event has occurred. For the
# interrupts recorded in this source register, the command abort
# interrupt should be recognized as the highest priority. This bit will
# be accompanied by CX_SETUP_INT. Because CX FIFO is frozen for access
# when CX_COMABT_INT remains at 1, SW should serve CX_COMABT_INT and
# clear it before CX_SETUP_INT. For the 8-byte SETUP leads to command an
# abort, SW must clear CX_COMABT_INT first.
FTUSB_IGR1_CX_CMDABT_INT_BIT     = 8
FTUSB_IGR1_CX_CMDABT_INT_MASK    = 0x00000100
FTUSB_IGR1_CX_CMDABT_INT_SH      = 8
FTUSB_IGR1_CX_CMDABT_INT_DEF     = 0x00000000
# ------
# DEV_MODE_CHG_INT: 
# Access W1C
# Device Mode Change interrupt. This bit indicates that the device
# operating speed has been changed. SW can check the register
# (Bits[1:0], offset = 0x00) to check the speed that the device
# operates.
FTUSB_IGR1_DEV_MODE_CHG_INT_BIT  = 9
FTUSB_IGR1_DEV_MODE_CHG_INT_MASK = 0x00000200
FTUSB_IGR1_DEV_MODE_CHG_INT_SH   = 9
FTUSB_IGR1_DEV_MODE_CHG_INT_DEF  = 0x00000000
# ------
# LINK_IN_TEST_MODE_INT: 
# Access W1C
# LTSSM in Electrical Test Mode Interrupt. LTSSM in compliance or
# loopback mode.
FTUSB_IGR1_LINK_IN_TEST_MODE_INT_BIT = 10
FTUSB_IGR1_LINK_IN_TEST_MODE_INT_MASK = 0x00000400
FTUSB_IGR1_LINK_IN_TEST_MODE_INT_SH = 10
FTUSB_IGR1_LINK_IN_TEST_MODE_INT_DEF = 0x00000000
# ------
# HS_RST_INT: 
# Access W1C
# USB Reset Interrupt. When the device detects a USB HS/FS bus reset
# from host, SE0 longer than 2.5 us, this bit will be set. When the AP
# has served the interrupt request, this bit must be cleared by SW.
FTUSB_IGR1_HS_RST_INT_BIT        = 11
FTUSB_IGR1_HS_RST_INT_MASK       = 0x00000800
FTUSB_IGR1_HS_RST_INT_SH         = 11
FTUSB_IGR1_HS_RST_INT_DEF        = 0x00000000
# ------
# HS_LPM_INT: 
# Access W1C
# USB LPM Interrupt. When FOTG330 responses ACK for the LPM packet and
# enters the L1 state, this bit will be set. This bit must be cleared by
# SW. It is also cleared by hardware when the HS/FS USB bus resets or a
# resume occurs. When this interrupt was triggered, SW can read LPM_BESL
# to get the BESL value of XHCI receiving LPM Token
FTUSB_IGR1_HS_LPM_INT_BIT        = 12
FTUSB_IGR1_HS_LPM_INT_MASK       = 0x00001000
FTUSB_IGR1_HS_LPM_INT_SH         = 12
FTUSB_IGR1_HS_LPM_INT_DEF        = 0x00000000
# ------
# HS_SUSP_INT: 
# Access W1C
# Suspend Interrupt. When the HS/FS bus remains in an idle state for
# over 3 ms, this bit will be set. This bit must be cleared before SW
# sets ?HS_GOSUSP?. This bit will also be cleared when the HS/FS USB bus
# resets or a resume occurs.
FTUSB_IGR1_HS_SUSP_INT_BIT       = 13
FTUSB_IGR1_HS_SUSP_INT_MASK      = 0x00002000
FTUSB_IGR1_HS_SUSP_INT_SH        = 13
FTUSB_IGR1_HS_SUSP_INT_DEF       = 0x00000000
# ------
# HS_RESM_INT: 
# Access W1C
# Resume Interrupt. This bit indicates that FOTG330 has resumed from the
# suspend/LPM state. After SW has served the interrupt request, this bit
# must be cleared by SW. When a HS/FS USB bus reset occurs, it will also
# be cleared.
FTUSB_IGR1_HS_RESM_INT_BIT       = 14
FTUSB_IGR1_HS_RESM_INT_MASK      = 0x00004000
FTUSB_IGR1_HS_RESM_INT_SH        = 14
FTUSB_IGR1_HS_RESM_INT_DEF       = 0x00000000
# ------
# WARM_RST_INT: 
# Access W1C
# SS warm reset received.
FTUSB_IGR1_WARM_RST_INT_BIT      = 15
FTUSB_IGR1_WARM_RST_INT_MASK     = 0x00008000
FTUSB_IGR1_WARM_RST_INT_SH       = 15
FTUSB_IGR1_WARM_RST_INT_DEF      = 0x00000000
# ------
# HOT_RST_INT: 
# Access W1C
# SS hot reset received
FTUSB_IGR1_HOT_RST_INT_BIT       = 16
FTUSB_IGR1_HOT_RST_INT_MASK      = 0x00010000
FTUSB_IGR1_HOT_RST_INT_SH        = 16
FTUSB_IGR1_HOT_RST_INT_DEF       = 0x00000000
# ------
# U1_ENTRY_INT: 
# Access W1C
# This interrupt indicates that FOTG330 has successfully entered the U1
# state. The condition includes the following items: FOTG330 receives
# the request to enter the SS U1 state. FOTG330 requests to actively
# enter the U1 state. U1_TIMEOUT timer timeout
FTUSB_IGR1_U1_ENTRY_INT_BIT      = 17
FTUSB_IGR1_U1_ENTRY_INT_MASK     = 0x00020000
FTUSB_IGR1_U1_ENTRY_INT_SH       = 17
FTUSB_IGR1_U1_ENTRY_INT_DEF      = 0x00000000
# ------
# U2_ENTRY_INT: 
# Access W1C
# This interrupt indicates that FOTG330 has successfully entered the U2
# state. The condition includes the following items: FOTG330 receives
# the request to enter the SS U2 state. FOTG330 requests to actively
# enter the U2 state. U2_TIMEOUT timer timeout FOTG330 actively enters
# to U2 from U1.
FTUSB_IGR1_U2_ENTRY_INT_BIT      = 18
FTUSB_IGR1_U2_ENTRY_INT_MASK     = 0x00040000
FTUSB_IGR1_U2_ENTRY_INT_SH       = 18
FTUSB_IGR1_U2_ENTRY_INT_DEF      = 0x00000000
# ------
# U3_ENTRY_INT: 
# Access W1C
# This interrupt indicates that FOTG330 receives the request to enter
# the SS U3 state. When asserting this bit, SW should set GO_U3_DONE of
# SS CR1 after the application is ready to enter the U3 state.
FTUSB_IGR1_U3_ENTRY_INT_BIT      = 19
FTUSB_IGR1_U3_ENTRY_INT_MASK     = 0x00080000
FTUSB_IGR1_U3_ENTRY_INT_SH       = 19
FTUSB_IGR1_U3_ENTRY_INT_DEF      = 0x00000000
# ------
# U1_EXIT_INT: 
# Access W1C
# This interrupt indicates that FOTG330 successfully exits from the SS
# U1 state.
FTUSB_IGR1_U1_EXIT_INT_BIT       = 20
FTUSB_IGR1_U1_EXIT_INT_MASK      = 0x00100000
FTUSB_IGR1_U1_EXIT_INT_SH        = 20
FTUSB_IGR1_U1_EXIT_INT_DEF       = 0x00000000
# ------
# U2_EXIT_INT: 
# Access W1C
# This interrupt indicates that FOTG330 successfully exits from the SS
# U2 state.
FTUSB_IGR1_U2_EXIT_INT_BIT       = 21
FTUSB_IGR1_U2_EXIT_INT_MASK      = 0x00200000
FTUSB_IGR1_U2_EXIT_INT_SH        = 21
FTUSB_IGR1_U2_EXIT_INT_DEF       = 0x00000000
# ------
# U3_EXIT_INT: 
# Access W1C
# This interrupt indicates that FOTG330 successfully exits from the SS
# U3 state.
FTUSB_IGR1_U3_EXIT_INT_BIT       = 22
FTUSB_IGR1_U3_EXIT_INT_MASK      = 0x00400000
FTUSB_IGR1_U3_EXIT_INT_SH        = 22
FTUSB_IGR1_U3_EXIT_INT_DEF       = 0x00000000
# ------
# U1_ENTRY_FAIL_INT: 
# Access W1C
# This interrupt indicates that FOTG330 actively requests to enter to
# the U1 state, but the link partner rejects this request.
FTUSB_IGR1_U1_ENTRY_FAIL_INT_BIT = 23
FTUSB_IGR1_U1_ENTRY_FAIL_INT_MASK = 0x00800000
FTUSB_IGR1_U1_ENTRY_FAIL_INT_SH  = 23
FTUSB_IGR1_U1_ENTRY_FAIL_INT_DEF = 0x00000000
# ------
# U2_ENTRY_FAIL_INT: 
# Access W1C
# This interrupt indicates that FOTG330 actively requests to enter to
# the U2 state, but the link partner rejects this request.
FTUSB_IGR1_U2_ENTRY_FAIL_INT_BIT = 24
FTUSB_IGR1_U2_ENTRY_FAIL_INT_MASK = 0x01000000
FTUSB_IGR1_U2_ENTRY_FAIL_INT_SH  = 24
FTUSB_IGR1_U2_ENTRY_FAIL_INT_DEF = 0x00000000
# ------
# U1_EXIT_FAIL_INT: 
# Access W1C
# This interrupt indicates that FOTG330 actively requests to exit from
# U1 to U0, but the exit handshake failed.
FTUSB_IGR1_U1_EXIT_FAIL_INT_BIT  = 25
FTUSB_IGR1_U1_EXIT_FAIL_INT_MASK = 0x02000000
FTUSB_IGR1_U1_EXIT_FAIL_INT_SH   = 25
FTUSB_IGR1_U1_EXIT_FAIL_INT_DEF  = 0x00000000
# ------
# U2_EXIT_FAIL_INT: 
# Access W1C
# This interrupt indicates that FOTG330 actively requests to exit from
# U2 to U0, but the exit handshake failed.
FTUSB_IGR1_U2_EXIT_FAIL_INT_BIT  = 26
FTUSB_IGR1_U2_EXIT_FAIL_INT_MASK = 0x04000000
FTUSB_IGR1_U2_EXIT_FAIL_INT_SH   = 26
FTUSB_IGR1_U2_EXIT_FAIL_INT_DEF  = 0x00000000
# ------
# U3_EXIT_FAIL_INT: 
# Access W1C
# This interrupt indicates that FOTG330 actively requests to exit from
# U3 to U0, but the exit handshake failed.
FTUSB_IGR1_U3_EXIT_FAIL_INT_BIT  = 27
FTUSB_IGR1_U3_EXIT_FAIL_INT_MASK = 0x08000000
FTUSB_IGR1_U3_EXIT_FAIL_INT_SH   = 27
FTUSB_IGR1_U3_EXIT_FAIL_INT_DEF  = 0x00000000
# ------
# SYNF0_EMPTY_INT: 
# Access RO
# Sync FIFO0 Empty interrupt. Before writing data to the data port of
# FOTG330 through Slave0, SW should ensure that SYNF is empty and FIFO
# is not full by using the EPn FIFO Register.
FTUSB_IGR1_SYNF0_EMPTY_INT_BIT   = 28
FTUSB_IGR1_SYNF0_EMPTY_INT_MASK  = 0x10000000
FTUSB_IGR1_SYNF0_EMPTY_INT_SH    = 28
FTUSB_IGR1_SYNF0_EMPTY_INT_DEF   = 0x00000000
# ------
# VBUS_CHG_INT: 
# Access W1C
# VBUS Change Interrupt. This bit will be asserted, when VBUS changes
# from 1 to 0 or from 0 to 1. SW can check the VBUS status (Bit 7 of
# Global Control Register, offset = 0x000) to check whether VBUS exists
# or not. When VBUS changes from 1 to 0, the system should generate the
# hardware reset through hwrst_n to FOTG330. Otherwise, there may be
# unexpected response after FOTG330 re-plugging into the host.
FTUSB_IGR1_VBUS_CHG_INT_BIT      = 30
FTUSB_IGR1_VBUS_CHG_INT_MASK     = 0x40000000
FTUSB_IGR1_VBUS_CHG_INT_SH       = 30
FTUSB_IGR1_VBUS_CHG_INT_DEF      = 0x00000000
# ------
# INT_GRP5: 
# Access RO
# This bit indicates that some interrupts occur in the Interrupt Group 5
# Register.
FTUSB_IGR1_INT_GRP5_BIT          = 31
FTUSB_IGR1_INT_GRP5_MASK         = 0x80000000
FTUSB_IGR1_INT_GRP5_SH           = 31
FTUSB_IGR1_INT_GRP5_DEF          = 0x00000000
# -----------------------------------------------------------------
# ftusb IGR2: Interrupt Group 2 Register
# This register is part of the Interrupt Source Registers set.
# Access RW
# -----------------------------------------------------------------
FTUSB_ADDR_IGR2                  = 0x10302408
# -----------------------------------------------------------------
# ------
# EP1_STR_PRIME_INT: 
# Access W1C
# EP is ready to serve the Stream Protocol. This bit indicates that EP
# has received the Prime Stream package and entered the IDLE state.
FTUSB_IGR2_EP1_STR_PRIME_INT_BIT = 0
FTUSB_IGR2_EP1_STR_PRIME_INT_MASK = 0x00000001
FTUSB_IGR2_EP1_STR_PRIME_INT_SH  = 0
FTUSB_IGR2_EP1_STR_PRIME_INT_DEF = 0x00000000
# ------
# EP1_STR_NOTRDY_INT: 
# Access W1C
# iThis interrupt indicates that the host rejects the proposal Stream ID
# of EP from FOTG330. SW can try to propose other Stream ID if other
# Stream is ready. This bit will be cleared by hardware after EPn_STR_EN
# is set.
FTUSB_IGR2_EP1_STR_NOTRDY_INT_BIT = 1
FTUSB_IGR2_EP1_STR_NOTRDY_INT_MASK = 0x00000002
FTUSB_IGR2_EP1_STR_NOTRDY_INT_SH = 1
FTUSB_IGR2_EP1_STR_NOTRDY_INT_DEF = 0x00000000
# ------
# EP1_STR_REQ_INT: 
# Access RO
# EP Stream ID Request. This bit indicates that the state of Stream
# Protocol transfers to IDLE from Move Data due to FOTG330 returns NRDY
# or the host completes the transfer. SW can propose other Stream ID by
# programming EPn_STR_ID and activate EP4_STR_EN. This bit is
# automatically cleared by HW when EP4_STR_EN is set. Please note that
# providing the same Stream IP is not allowed by SW until
# EPn_STR_PRIME_INT is asserted.
FTUSB_IGR2_EP1_STR_REQ_INT_BIT   = 2
FTUSB_IGR2_EP1_STR_REQ_INT_MASK  = 0x00000004
FTUSB_IGR2_EP1_STR_REQ_INT_SH    = 2
FTUSB_IGR2_EP1_STR_REQ_INT_DEF   = 0x00000000
# ------
# EP1_STR_RESUME_INT: 
# Access W1C
# EP Stream ID Resume Interrupt. This interrupt indicates that the host
# actively issues the package with LCStream ID and the state of Stream
# Protocol transfers to Move Data from IDLE.
FTUSB_IGR2_EP1_STR_RESUME_INT_BIT = 3
FTUSB_IGR2_EP1_STR_RESUME_INT_MASK = 0x00000008
FTUSB_IGR2_EP1_STR_RESUME_INT_SH = 3
FTUSB_IGR2_EP1_STR_RESUME_INT_DEF = 0x00000000
# ------
# EP1_STR_ACCEPT_INT: 
# Access W1C
# EP Stream ID Accept Interrupt. This interrupt indicates that the host
# accepts the Stream ID proposed by FOTG330. The state of Stream
# Protocol transfers to Move Data from Start Stream.
FTUSB_IGR2_EP1_STR_ACCEPT_INT_BIT = 4
FTUSB_IGR2_EP1_STR_ACCEPT_INT_MASK = 0x00000010
FTUSB_IGR2_EP1_STR_ACCEPT_INT_SH = 4
FTUSB_IGR2_EP1_STR_ACCEPT_INT_DEF = 0x00000000
# ------
# EP2_STR_PRIME_INT: 
# Access W1C
# EP is ready to serve the Stream Protocol. This bit indicates that EP
# has received the Prime Stream package and entered the IDLE state.
FTUSB_IGR2_EP2_STR_PRIME_INT_BIT = 5
FTUSB_IGR2_EP2_STR_PRIME_INT_MASK = 0x00000020
FTUSB_IGR2_EP2_STR_PRIME_INT_SH  = 5
FTUSB_IGR2_EP2_STR_PRIME_INT_DEF = 0x00000000
# ------
# EP2_STR_NOTRDY_INT: 
# Access W1C
# iThis interrupt indicates that the host rejects the proposal Stream ID
# of EP from FOTG330. SW can try to propose other Stream ID if other
# Stream is ready. This bit will be cleared by hardware after EPn_STR_EN
# is set.
FTUSB_IGR2_EP2_STR_NOTRDY_INT_BIT = 6
FTUSB_IGR2_EP2_STR_NOTRDY_INT_MASK = 0x00000040
FTUSB_IGR2_EP2_STR_NOTRDY_INT_SH = 6
FTUSB_IGR2_EP2_STR_NOTRDY_INT_DEF = 0x00000000
# ------
# EP2_STR_REQ_INT: 
# Access RO
# EP Stream ID Request. This bit indicates that the state of Stream
