FTUSB_IGR2_EP2_STR_REQ_INT_BIT   = 7
FTUSB_IGR2_EP2_STR_REQ_INT_MASK  = 0x00000080
FTUSB_IGR2_EP2_STR_REQ_INT_SH    = 7
FTUSB_IGR2_EP2_STR_REQ_INT_DEF   = 0x00000000
# ------
# EP2_STR_RESUME_INT: 
# Access W1C
# EP Stream ID Resume Interrupt. This interrupt indicates that the host
