FTUSB_IGR2_EP2_STR_RESUME_INT_BIT = 8
FTUSB_IGR2_EP2_STR_RESUME_INT_MASK = 0x00000100
FTUSB_IGR2_EP2_STR_RESUME_INT_SH = 8
FTUSB_IGR2_EP2_STR_RESUME_INT_DEF = 0x00000000
# ------
# EP2_STR_ACCEPT_INT: 
# Access W1C
# EP Stream ID Accept Interrupt. This interrupt indicates that the host
