FTUSB_IGR2_EP2_STR_ACCEPT_INT_BIT = 9
FTUSB_IGR2_EP2_STR_ACCEPT_INT_MASK = 0x00000200
FTUSB_IGR2_EP2_STR_ACCEPT_INT_SH = 9
FTUSB_IGR2_EP2_STR_ACCEPT_INT_DEF = 0x00000000
# ------
# EP3_STR_PRIME_INT: 
# Access W1C
# EP is ready to serve the Stream Protocol. This bit indicates that EP
