FTUSB_EP14_PRD_TABLE0_H_BIT      = 24
FTUSB_EP14_PRD_TABLE0_H_MASK     = 0x01000000
FTUSB_EP14_PRD_TABLE0_H_SH       = 24
FTUSB_EP14_PRD_TABLE0_H_DEF      = 0x00000000
