FTUSB_EP14_PRD_TABLE0_L_MASK     = 0x02000000
FTUSB_EP14_PRD_TABLE0_L_SH       = 25
FTUSB_EP14_PRD_TABLE0_L_DEF      = 0x00000000
# ------
# A: 
# Access RW
# DMA Address Control. 0: Address is incremented by 4. 1: Add is fixed
# as PAR.
FTUSB_EP14_PRD_TABLE0_A_BIT      = 26
FTUSB_EP14_PRD_TABLE0_A_MASK     = 0x04000000
FTUSB_EP14_PRD_TABLE0_A_SH       = 26
FTUSB_EP14_PRD_TABLE0_A_DEF      = 0x00000000
# ------
# I: 
# Access RW
# PRD Transfer Finish Interrupt Enable. When set, this bit indicates
# that the PRD-finished interrupt will be asserted on completion of the
# current PRD transfer. When receiving the short package, PRD will be
# finished as well.
FTUSB_EP14_PRD_TABLE0_I_BIT      = 27
FTUSB_EP14_PRD_TABLE0_I_MASK     = 0x08000000
FTUSB_EP14_PRD_TABLE0_I_SH       = 27
FTUSB_EP14_PRD_TABLE0_I_DEF      = 0x00000000
# ------
# F: 
# Access RW
# Transaction Finish. This bit indicates  that this is the last PRD of
# this transaction. The internal DMA may change to serve other EP if
# there are requests from other EPs after it finishes serving PRD.
FTUSB_EP14_PRD_TABLE0_F_BIT      = 28
FTUSB_EP14_PRD_TABLE0_F_MASK     = 0x10000000
FTUSB_EP14_PRD_TABLE0_F_SH       = 28
FTUSB_EP14_PRD_TABLE0_F_DEF      = 0x00000000
# ------
# O: 
# Access RW
# Transmit 0 Byte. This bit informs DMA to set the register,
# EPn_TX0BYTE, after this PRD is finished.
FTUSB_EP14_PRD_TABLE0_O_BIT      = 29
FTUSB_EP14_PRD_TABLE0_O_MASK     = 0x20000000
FTUSB_EP14_PRD_TABLE0_O_SH       = 29
FTUSB_EP14_PRD_TABLE0_O_DEF      = 0x00000000
