# -----------------------------------------------------------------
# ------
DBI_MSIP_BITS                    = 32
DBI_MSIP_LSB                     = 0
DBI_MSIP_MSB                     = 31
DBI_MSIP_MASK                    = 0xffffffff
DBI_MSIP_SH                      = 0
DBI_MSIP_DEF                     = 0x00000000
