# -----------------------------------------------------------------
# ------
# GEN1_EI_INFERENCE: 
# Access RW
# Electrical Idle Inference Mode at Gen1 Rate. Programmable mode to
# determine inferred electrical idle (EI) in Recovery.Speed or
# Loopback.Active (as slave) state at Gen1 speed by looking for a "1"
# value on RxElecIdle instead of looking for a "0" on RxValid. If the
# PHY fails to deassert the RxValid signal in Recovery.Speed or
# Loopback.Active (because of corrupted EIOS for example), then EI
# cannot be inferred successfully in the controller by just detecting
# the condition RxValid=0.
DBI_GCO_GEN1_EI_INFERENCE_BIT    = 21
DBI_GCO_GEN1_EI_INFERENCE_MASK   = 0x00200000
DBI_GCO_GEN1_EI_INFERENCE_SH     = 21
DBI_GCO_GEN1_EI_INFERENCE_DEF    = 0x00000000
