DBI_GCO_SEL_DEEMPHASIS_MASK      = 0x00100000
DBI_GCO_SEL_DEEMPHASIS_SH        = 20
DBI_GCO_SEL_DEEMPHASIS_DEF       = 0x00000000
# ------
# CONFIG_TX_COMP_RX: 
# Access RW
# Config Tx Compliance Receive Bit. When set to 1, signals LTSSM to
# transmit TS ordered sets with the compliance receive bit assert (equal
# to "1"). This field is reserved (fixed to '0') for M-PCIe.
DBI_GCO_CONFIG_TX_COMP_RX_BIT    = 19
DBI_GCO_CONFIG_TX_COMP_RX_MASK   = 0x00080000
DBI_GCO_CONFIG_TX_COMP_RX_SH     = 19
DBI_GCO_CONFIG_TX_COMP_RX_DEF    = 0x00000000
