# AUTO_LANE_FLIP_CTRL_EN: 
# Access RW
# Enable Auto flipping of the lanes. You must set the
# CX_AUTO_LANE_FLIP_CTRL_EN configuration parameter to include the
# hardware for this feature in the controller. For more details, see the
# 'Lane Reversal' appendix in the
DBI_GCO_AUTO_LANE_FLIP_CTRL_EN_BIT = 16
