DBI_GCO_AUTO_LANE_FLIP_CTRL_EN_SH = 16
DBI_GCO_AUTO_LANE_FLIP_CTRL_EN_DEF = 0x00000000
# ------
# PRE_DET_LANE: 
# Access RW
# Predetermined Lane for Auto Flip. This field defines which physical
# lane is connected to logical Lane0 by the flip operation performed in
# Detect. Allowed values are:
DBI_GCO_PRE_DET_LANE_BITS        = 3
DBI_GCO_PRE_DET_LANE_LSB         = 13
DBI_GCO_PRE_DET_LANE_MSB         = 15
DBI_GCO_PRE_DET_LANE_MASK        = 0x0000e000
DBI_GCO_PRE_DET_LANE_SH          = 13
DBI_GCO_PRE_DET_LANE_DEF         = 0x00000000
# ------
# NUM_OF_LANES: 
# Access RW
# Predetermined Number of Lanes. Defines the number of lanes which are
# connected and not bad. Used to limit the effective link width to
# ignore 'broken" or "unused" lanes that detect a receiver. Indicates
# the number of lanes to check for exit from Electrical Idle in
# Polling.Active and L2.Idle. It is possible that the LTSSM might detect
# a receiver on a bad or broken lane during the Detect Substate.
# However, it is also possible that such a lane might also fail to exit
# Electrical Idle and therefore prevent a valid link from being
# configured. This value is referred to as the "Predetermined Number of
# Lanes" in section 4.2.6.2.1 of the PCI Express Base 3.0 Specification,
# revision 1.0. Encoding is as follows:
DBI_GCO_NUM_OF_LANES_BITS        = 5
DBI_GCO_NUM_OF_LANES_LSB         = 8
DBI_GCO_NUM_OF_LANES_MSB         = 12
DBI_GCO_NUM_OF_LANES_MASK        = 0x00001f00
DBI_GCO_NUM_OF_LANES_SH          = 8
DBI_GCO_NUM_OF_LANES_DEF         = 0x00000000
