# -----------------------------------------------------------------
# dbi AERDO: AMBA_ERROR_RESPONSE_DEFAULT_OFF
# AXI Bridge Slave Error Response Register.
# Access RW
# -----------------------------------------------------------------
DBI_ADDR_AERDO                   = 0x104008d0
# -----------------------------------------------------------------
# ------
# AMBA_ERROR_RESPONSE_MAP: 
# Access RW
# AXI Slave Response Error Map. Allows you to selectively map the errors
# received from the PCIe completion (for non-posted requests) to the AXI
# slave responses, slv_rresp or slv_bresp. The recommended setting is
# SLVERR. CRS is always mapped to OKAY. [0] - 0: UR (unsupported
# request) -> DECERR - 1: UR (unsupported request) -> SLVERR. [1] - 0:
# CRS (configuration retry status) -> DECERR - 1: CRS (configuration
# retry status) -> SLVERR. [2] - 0: CA (completer abort) -> DECERR - 1:
# CA (completer abort) -> SLVERR. [3]: Reserved. [4]: Reserved. [5]: -
# 0: Completion Timeout -> DECERR - 1: Completion Timeout -> SLVERR. The
# AXI bridge internally drops (processes internally but not passed to
# your application) a completion that has been marked by the Rx filter
# as UC or MLF, and does not pass its status directly down to the slave
# interface. It waits for a timeout and then signals Completion Timeout
# to the slave interface. The controller sets the AXI slave read databus
# to 0xFFFF for all error responses.
DBI_AERDO_AMBA_ERROR_RESPONSE_MAP_BITS = 6
DBI_AERDO_AMBA_ERROR_RESPONSE_MAP_LSB = 10
DBI_AERDO_AMBA_ERROR_RESPONSE_MAP_MSB = 15
DBI_AERDO_AMBA_ERROR_RESPONSE_MAP_MASK = 0x0000fc00
DBI_AERDO_AMBA_ERROR_RESPONSE_MAP_SH = 10
DBI_AERDO_AMBA_ERROR_RESPONSE_MAP_DEF = 0x00000027
# ------
# AMBA_ERROR_RESPONSE_CRS: 
# Access RW
# CRS Slave Error Response Mapping. Determines the AXI slave response
# for CRS completions. For more details see "Error Handling" in the AXI
# chapter of the Databook. AXI: 00: OKAY. 01: OKAY with all FFFF_FFFF
# data for all CRS completions. 10: OKAY with FFFF_0001 data for CRS
# completions to vendor ID read requests, OKAY with FFFF_FFFF data for
# all other CRS completions. 11: SLVERR/DECERR (the
# AXI_ERROR_RESPONSE_MAP field determines the PCIe-to-AXI Slave error
# response mapping).
DBI_AERDO_AMBA_ERROR_RESPONSE_CRS_BITS = 2
DBI_AERDO_AMBA_ERROR_RESPONSE_CRS_LSB = 3
DBI_AERDO_AMBA_ERROR_RESPONSE_CRS_MSB = 4
DBI_AERDO_AMBA_ERROR_RESPONSE_CRS_MASK = 0x00000018
DBI_AERDO_AMBA_ERROR_RESPONSE_CRS_SH = 3
DBI_AERDO_AMBA_ERROR_RESPONSE_CRS_DEF = 0x00000000
# ------
# AMBA_ERROR_RESPONSE_VENDORID: 
# Access RW
# Vendor ID Non-existent Slave Error Response Mapping. Determines the
# AXI slave response for errors on reads to non-existent Vendor ID
# register. For more details see "Error Handling" in the AXI chapter of
# the Databook 0: OKAY (with FFFF data). 1: SLVERR/DECERR (the
# AXI_ERROR_RESPONSE_MAP field determines the PCIe-to-AXI Slave error
# response mapping).
DBI_AERDO_AMBA_ERROR_RESPONSE_VENDORID_BIT = 2
DBI_AERDO_AMBA_ERROR_RESPONSE_VENDORID_MASK = 0x00000004
DBI_AERDO_AMBA_ERROR_RESPONSE_VENDORID_SH = 2
DBI_AERDO_AMBA_ERROR_RESPONSE_VENDORID_DEF = 0x00000000
# ------
# AMBA_ERROR_RESPONSE_GLOBAL: 
# Access RW
# Global Slave Error Response Mapping. Determines the AXI slave response
# for all error scenarios on non-posted requests. For more details see
# "Error Handling" in the AXI chapter of the Databook. 0: OKAY (with
# FFFF data for non-posted requests). 1: SLVERR/DECERR (the
# AXI_ERROR_RESPONSE_MAP field determines the PCIe-to-AXI Slave error
# response mapping). The error response mapping is not applicable to
# Non-existent Vendor ID register reads.
DBI_AERDO_AMBA_ERROR_RESPONSE_GLOBAL_BIT = 0
DBI_AERDO_AMBA_ERROR_RESPONSE_GLOBAL_MASK = 0x00000001
DBI_AERDO_AMBA_ERROR_RESPONSE_GLOBAL_SH = 0
DBI_AERDO_AMBA_ERROR_RESPONSE_GLOBAL_DEF = 0x00000000
# -----------------------------------------------------------------
# dbi AMBALTO: AMBA_LINK_TIMEOUT_OFF
# Link Down AXI Bridge Slave Timeout Register. If your application AXI
# master issues outbound requests to the AXI bridge slave interface
# before the PCIe link is operational, the controller starts a "flush"
# timer. The timeout value of the timer is set by this register. The
# timer will timeout and then flush the bridge TX request queues after
# this amount of time. The timer counts when there are pending outbound
# AXI slave interface (or DMA) requests and the PCIe TX link is not
# transmitting any of these requests. For more details, see the "AXI
# Bridge Initialization, Clocking and Reset" section in the AXI chapter
# of the
# Access RW
# -----------------------------------------------------------------
DBI_ADDR_AMBALTO                 = 0x104008d4
# -----------------------------------------------------------------
# ------
# LINK_TIMEOUT_ENABLE_DEFAULT: 
# Access RW
# Disable Flush. You can disable the flush feature by setting this field
# to "1".
DBI_AMBALTO_LINK_TIMEOUT_ENABLE_DEFAULT_BIT = 8
DBI_AMBALTO_LINK_TIMEOUT_ENABLE_DEFAULT_MASK = 0x00000100
DBI_AMBALTO_LINK_TIMEOUT_ENABLE_DEFAULT_SH = 8
DBI_AMBALTO_LINK_TIMEOUT_ENABLE_DEFAULT_DEF = 0x00000000
# ------
# LINK_TIMEOUT_PERIOD_DEFAULT: 
# Access RW
# Timeout Value (ms). The timer will timeout and then flush the bridge
# TX request queues after this amount of time. The timer counts when
# there are pending outbound AXI slave interface requests and the PCIe
# TX link is not transmitting any of these requests. The timer is
# clocked by core_clk.
DBI_AMBALTO_LINK_TIMEOUT_PERIOD_DEFAULT_BITS = 8
DBI_AMBALTO_LINK_TIMEOUT_PERIOD_DEFAULT_LSB = 0
DBI_AMBALTO_LINK_TIMEOUT_PERIOD_DEFAULT_MSB = 7
DBI_AMBALTO_LINK_TIMEOUT_PERIOD_DEFAULT_MASK = 0x000000ff
DBI_AMBALTO_LINK_TIMEOUT_PERIOD_DEFAULT_SH = 0
DBI_AMBALTO_LINK_TIMEOUT_PERIOD_DEFAULT_DEF = 0x00000000
# -----------------------------------------------------------------
# dbi AOCO: AMBA_ORDERING_CTRL_OFF
# AMBA Ordering Control.
# Access RW
# -----------------------------------------------------------------
DBI_ADDR_AOCO                    = 0x104008d8
# -----------------------------------------------------------------
# ------
# AX_MSTR_ORDR_P_EVENT_SEL: 
# Access RW
# AXI Master Posted Ordering Event Selector. 00: B'last event: wait for
# the all of the write responses on the B channel thereby ensuring that
# the complete Posted transaction has effectively reached the
# application slave (default). 01: AW'last event: wait until the
# complete Posted transaction has left the AXI address channel at the
# bridge master. 10: W'last event: wait until the complete Posted
# transaction has left the AXI data channel at the bridge master. 11:
# Reserved Note 2: This setting will not affect: MSI interrupt catcher
# and P data ordering. This is always driven by the B'last event. DMA
# read engine TLP ordering. This is always driven by the B'last event.
# NP write transactions which are always serialized with P write
# transactions.
DBI_AOCO_AX_MSTR_ORDR_P_EVENT_SEL_BITS = 2
DBI_AOCO_AX_MSTR_ORDR_P_EVENT_SEL_LSB = 3
DBI_AOCO_AX_MSTR_ORDR_P_EVENT_SEL_MSB = 4
DBI_AOCO_AX_MSTR_ORDR_P_EVENT_SEL_MASK = 0x00000018
DBI_AOCO_AX_MSTR_ORDR_P_EVENT_SEL_SH = 3
DBI_AOCO_AX_MSTR_ORDR_P_EVENT_SEL_DEF = 0x00000000
# ------
# AX_SNP_EN: 
# Access RW
# AXI Serialize Non-Posted Requests Enable. This field enables the AXI
# Bridge to serialize same ID Non-Posted Read/Write Requests on the
# wire. Serialization implies one outstanding same ID NP Read or Write
# on the wire and used to avoid AXI RAR and WAW hazards at the remote
# link partner. For more details, see the "Optional Serialization of AXI
# Slave Non-posted Requests" section in the AXI chapter of the Databook.
DBI_AOCO_AX_SNP_EN_BIT           = 1
DBI_AOCO_AX_SNP_EN_MASK          = 0x00000002
DBI_AOCO_AX_SNP_EN_SH            = 1
DBI_AOCO_AX_SNP_EN_DEF           = 0x00000000
