# iATU Region Control 2 Register.
# Access RW
# -----------------------------------------------------------------
DBI_ADDR_IRC2OOI31               = 0x10703e04
# -----------------------------------------------------------------
# ------
# REGION_EN: 
# Access RW
# Region Enable. This bit must be set to '1' for address translation to
# take place.
DBI_IRC2OOI31_REGION_EN_BIT      = 31
DBI_IRC2OOI31_REGION_EN_MASK     = 0x80000000
DBI_IRC2OOI31_REGION_EN_SH       = 31
DBI_IRC2OOI31_REGION_EN_DEF      = 0x00000000
# ------
# INVERT_MODE: 
# Access RW
# Invert Mode. When set the address matching region is inverted.
# Therefore, an address match occurs when the untranslated address is in
# the region outside the defined range (Base Address to Limit Address).
DBI_IRC2OOI31_INVERT_MODE_BIT    = 29
DBI_IRC2OOI31_INVERT_MODE_MASK   = 0x20000000
DBI_IRC2OOI31_INVERT_MODE_SH     = 29
DBI_IRC2OOI31_INVERT_MODE_DEF    = 0x00000000
# ------
# CFG_SHIFT_MODE: 
# Access RW
# CFG Shift Mode.
DBI_IRC2OOI31_CFG_SHIFT_MODE_BIT = 28
DBI_IRC2OOI31_CFG_SHIFT_MODE_MASK = 0x10000000
DBI_IRC2OOI31_CFG_SHIFT_MODE_SH  = 28
DBI_IRC2OOI31_CFG_SHIFT_MODE_DEF = 0x00000000
# ------
# DMA_BYPASS: 
# Access RW
# DMA Bypass Mode. Allows request TLPs which are initiated by the DMA
# controller to pass through the iATU untranslated.
DBI_IRC2OOI31_DMA_BYPASS_BIT     = 27
DBI_IRC2OOI31_DMA_BYPASS_MASK    = 0x08000000
DBI_IRC2OOI31_DMA_BYPASS_SH      = 27
DBI_IRC2OOI31_DMA_BYPASS_DEF     = 0x00000000
# ------
# HEADER_SUBSTITUTE_EN: 
# Access RW
# Header Substitute Enable.
DBI_IRC2OOI31_HEADER_SUBSTITUTE_EN_BIT = 23
DBI_IRC2OOI31_HEADER_SUBSTITUTE_EN_MASK = 0x00800000
DBI_IRC2OOI31_HEADER_SUBSTITUTE_EN_SH = 23
DBI_IRC2OOI31_HEADER_SUBSTITUTE_EN_DEF = 0x00000000
# ------
# INHIBIT_PAYLOAD: 
# Access RW
# Inhibit TLP Payload Data for TLP's in Matched Region; assign iATU
# region to be TLP without data. When enabled and region address is
# matched, the iATU marks all TLPs as having no payload data by forcing
# the TLP header Fmt[1] bit =0, regardless of the application inputs
# such as slv_wstrb.
DBI_IRC2OOI31_INHIBIT_PAYLOAD_BIT = 22
DBI_IRC2OOI31_INHIBIT_PAYLOAD_MASK = 0x00400000
DBI_IRC2OOI31_INHIBIT_PAYLOAD_SH = 22
DBI_IRC2OOI31_INHIBIT_PAYLOAD_DEF = 0x00000000
# ------
# SNP: 
# Access RW
# Serialize Non-Posted Requests. In this mode, when the AXI Bridge is
# populated, same AXI ID Non-Posted Read/Write Requests are transmitted
# on the wire if there are no other same ID Non-Posted Requests
# outstanding.
DBI_IRC2OOI31_SNP_BIT            = 20
DBI_IRC2OOI31_SNP_MASK           = 0x00100000
DBI_IRC2OOI31_SNP_SH             = 20
DBI_IRC2OOI31_SNP_DEF            = 0x00000000
# ------
# FUNC_BYPASS: 
# Access RW
# Function Number Translation Bypass. In this mode, the function number
# of the translated TLP is taken from your application transmit
# interface and not from the CTRL_1_FUNC_NUM field of the "iATU Control
# 1 Register" or the VF_NUMBER field of the "iATU Control 3 Register."
DBI_IRC2OOI31_FUNC_BYPASS_BIT    = 19
DBI_IRC2OOI31_FUNC_BYPASS_MASK   = 0x00080000
DBI_IRC2OOI31_FUNC_BYPASS_SH     = 19
DBI_IRC2OOI31_FUNC_BYPASS_DEF    = 0x00000000
# ------
# TAG_SUBSTITUTE_EN: 
# Access RW
# TAG Substitute Enable.
DBI_IRC2OOI31_TAG_SUBSTITUTE_EN_BIT = 16
DBI_IRC2OOI31_TAG_SUBSTITUTE_EN_MASK = 0x00010000
DBI_IRC2OOI31_TAG_SUBSTITUTE_EN_SH = 16
DBI_IRC2OOI31_TAG_SUBSTITUTE_EN_DEF = 0x00000000
# ------
# TAG: 
# Access RW
# TAG.
DBI_IRC2OOI31_TAG_BITS           = 8
DBI_IRC2OOI31_TAG_LSB            = 8
DBI_IRC2OOI31_TAG_MSB            = 15
DBI_IRC2OOI31_TAG_MASK           = 0x0000ff00
DBI_IRC2OOI31_TAG_SH             = 8
DBI_IRC2OOI31_TAG_DEF            = 0x00000000
# ------
# MSG_CODE: 
# Access RW
# MSG TLPs (Message Code). When the address of an outbound TLP is
# matched to this region, and the translated TLP TYPE field is Msg or
# MsgD; then the message field of the TLP is changed to the value in
# this register.
DBI_IRC2OOI31_MSG_CODE_BITS      = 8
DBI_IRC2OOI31_MSG_CODE_LSB       = 0
DBI_IRC2OOI31_MSG_CODE_MSB       = 7
DBI_IRC2OOI31_MSG_CODE_MASK      = 0x000000ff
DBI_IRC2OOI31_MSG_CODE_SH        = 0
DBI_IRC2OOI31_MSG_CODE_DEF       = 0x00000000
