# sys INT0: System Interrupt 0 Register
# Each bit corresponds to an interrupt condition. When an interrupt
# condition occurs this register will hold that value until it is
# cleared. The rising edge of the interrupt will trigger the sending of
# an MSI message. Write a 1 to each bit to clear the interrupt. If the
# underlying condition is still present the interrupt will be triggered
# again. Interrupts are only set in this register when enabled in the
# sys_int_mask register.
# Access RW
# -----------------------------------------------------------------
SYS_ADDR_INT0                    = 0x10a00010
