# -----------------------------------------------------------------
# ------
# INL: 
# Access RW
# Only MSI interrupts associated with Data Types can be sent inline.
# Each bit that is set will send the corresponding MSI using the inline
# writes to the PCIe core.  Otherwise MSI messages will be sent using
# the sideband signals. Sideband is the default method. However, it does
# not guarantee ordering of the MSI and data.  Inline guarantees
# ordering such that the MSI will arrive at the host after the data has
# been sent. Inline requires the iATU to be configured properly.
SYS_MSICTL_INL_BITS              = 8
SYS_MSICTL_INL_LSB               = 0
SYS_MSICTL_INL_MSB               = 7
SYS_MSICTL_INL_MASK              = 0x000000ff
