# =================================================================
# uart: UART Controller Registers
# By default the UART runs at 19200 BAUD with 1 stop, no parity bits and
# no hardware flow control. The UART can act as a slave to an external
# device or as a master to an external device. By default the UART acts
# as a slave.  In this mode the UART receives instructions to initiate
# SMP bus transactions. The external entity sends a command byte, a 4
# byte address, and for a write 4 bytes of data. The UART responds with
# 4 bytes of data for a read and a status command byte.  Master mode is
# enabled by setting the cpu_mode bit in the ctl register. In this mode
# the UART can send and receive one byte at a time under CPU control.
# -----------------------------------------------------------------
# uart ST: Status Register
# 
# Access RW
# -----------------------------------------------------------------
UART_ADDR_ST                     = 0x10a01000
# -----------------------------------------------------------------
# ------
# RX_DONE: 
# Access RO
# Set when a byte is received on the UART. An interrupt can be triggered
# if enabled. Self-clearing.
UART_ST_RX_DONE_BIT              = 0
UART_ST_RX_DONE_MASK             = 0x00000001
UART_ST_RX_DONE_SH               = 0
UART_ST_RX_DONE_DEF              = 0x00000000
# ------
# TX_DONE: 
# Access RO
# Set when a byte is transmitted on the UART. An interrupt can be
# triggered if enabled. Self-clearing.
UART_ST_TX_DONE_BIT              = 1
UART_ST_TX_DONE_MASK             = 0x00000002
UART_ST_TX_DONE_SH               = 1
UART_ST_TX_DONE_DEF              = 0x00000000
# ------
# BUSY: 
# Access RO
# Valid only when the UART is acting as a slave device to an external
# device. Set when the UART is busy transmitting or receiving. Self-
# clearing.
UART_ST_BUSY_BIT                 = 2
UART_ST_BUSY_MASK                = 0x00000004
UART_ST_BUSY_SH                  = 2
UART_ST_BUSY_DEF                 = 0x00000000
# ------
# RX_BUSY: 
# Access RO
# Set when the UART transceiver is busy receiving a byte.
UART_ST_RX_BUSY_BIT              = 3
UART_ST_RX_BUSY_MASK             = 0x00000008
UART_ST_RX_BUSY_SH               = 3
UART_ST_RX_BUSY_DEF              = 0x00000000
# ------
# TX_BUSY: 
