WDMA_ST_PCIE_LBOUND_ERR_MASK     = 0x00000002
WDMA_ST_PCIE_LBOUND_ERR_SH       = 1
WDMA_ST_PCIE_LBOUND_ERR_DEF      = 0x00000000
