SEQ_ST_BUSY_MASK                 = 0x00000001
SEQ_ST_BUSY_SH                   = 0
SEQ_ST_BUSY_DEF                  = 0x00000000
# ------
# WAITBB: 
# Access RO
# When set indicates the sequencer is currently waiting on a Beam
# Boundary.
SEQ_ST_WAITBB_BIT                = 1
SEQ_ST_WAITBB_MASK               = 0x00000002
SEQ_ST_WAITBB_SH                 = 1
SEQ_ST_WAITBB_DEF                = 0x00000000
# ------
# WAITFB: 
# Access RO
# When set indicates the sequencer is currently waiting on a Frame
# Boundary.
SEQ_ST_WAITFB_BIT                = 2
SEQ_ST_WAITFB_MASK               = 0x00000004
SEQ_ST_WAITFB_SH                 = 2
SEQ_ST_WAITFB_DEF                = 0x00000000
# ------
# WAITTB: 
# Access RO
# When set indicates the sequencer is currently waiting on a Timer
# Boundary.
SEQ_ST_WAITTB_BIT                = 3
SEQ_ST_WAITTB_MASK               = 0x00000008
SEQ_ST_WAITTB_SH                 = 3
SEQ_ST_WAITTB_DEF                = 0x00000000
# ------
# WAITSB: 
# Access RO
# When set indicates the sequencer is currently waiting on a Sequencer
# Boundary.
SEQ_ST_WAITSB_BIT                = 4
SEQ_ST_WAITSB_MASK               = 0x00000010
SEQ_ST_WAITSB_SH                 = 4
SEQ_ST_WAITSB_DEF                = 0x00000000
# ------
# SMP_ERR: 
# Access WC
# Set when a CPU write to a register that does not exist occurs.
SEQ_ST_SMP_ERR_BIT               = 5
SEQ_ST_SMP_ERR_MASK              = 0x00000020
SEQ_ST_SMP_ERR_SH                = 5
SEQ_ST_SMP_ERR_DEF               = 0x00000000
# ------
# ERR_PRI: 
# Access WC
# Set when a PRI Sync occurs at an unexpected time. An unexpected PRI
# Sync is one that occurs when the sequencer is not waiting on a
# boundary. This will trigger an interrupt if enabled.
SEQ_ST_ERR_PRI_BIT               = 6
SEQ_ST_ERR_PRI_MASK              = 0x00000040
SEQ_ST_ERR_PRI_SH                = 6
SEQ_ST_ERR_PRI_DEF               = 0x00000000
# ------
# ERR_LLE: 
# Access WC
# Set when an invalid LLE is received. Validity is determined by
# checking the magic number in the LLE against the Magic Check Value
# Register. This will trigger an interrupt if enabled.
SEQ_ST_ERR_LLE_BIT               = 7
SEQ_ST_ERR_LLE_MASK              = 0x00000080
SEQ_ST_ERR_LLE_SH                = 7
SEQ_ST_ERR_LLE_DEF               = 0x00000000
# ------
# ERR_PLD: 
# Access WC
# Set when an error occurs on a Payload write. This will trigger an
# interrupt if enabled.
SEQ_ST_ERR_PLD_BIT               = 8
SEQ_ST_ERR_PLD_MASK              = 0x00000100
SEQ_ST_ERR_PLD_SH                = 8
SEQ_ST_ERR_PLD_DEF               = 0x00000000
# ------
# FSM: 
# Access RO
# Current Sequencer FSM State.
# Value      | State
# _________________________________________________________________
# 0          | IDLE
# 1          | FAIL
# 2          | START
# 3          | WAKE0
# 4          | WAKE1
# 5          | LLE_READ
# 6          | LLE_RDAT
# 7          | LLE_CHK
# 8          | LLE_PROC
# 9          | B_WAIT
# 10         | PYLD_CHK
# 11         | PYLD
# 12         | ACTION
# 13         | JUMP
# 14         | STOP
# 
SEQ_ST_FSM_BITS                  = 4
SEQ_ST_FSM_LSB                   = 12
SEQ_ST_FSM_MSB                   = 15
SEQ_ST_FSM_MASK                  = 0x0000f000
SEQ_ST_FSM_SH                    = 12
SEQ_ST_FSM_DEF                   = 0x00000000
# ------
# FSM_ERR: 
# Access WC
# Sequencer FSM State when a err_pri or err_lle is encountered.
SEQ_ST_FSM_ERR_BITS              = 4
SEQ_ST_FSM_ERR_LSB               = 16
SEQ_ST_FSM_ERR_MSB               = 19
SEQ_ST_FSM_ERR_MASK              = 0x000f0000
SEQ_ST_FSM_ERR_SH                = 16
SEQ_ST_FSM_ERR_DEF               = 0x00000000
# ------
# WEST: 
# Access WC
# Sequencer Write Engine State.
SEQ_ST_WEST_BITS                 = 5
SEQ_ST_WEST_LSB                  = 24
SEQ_ST_WEST_MSB                  = 28
SEQ_ST_WEST_MASK                 = 0x1f000000
SEQ_ST_WEST_SH                   = 24
SEQ_ST_WEST_DEF                  = 0x00000000
