SEQ_CTL_NOSLEEP_LSB              = 8
SEQ_CTL_NOSLEEP_MSB              = 12
SEQ_CTL_NOSLEEP_MASK             = 0x00001f00
SEQ_CTL_NOSLEEP_SH               = 8
SEQ_CTL_NOSLEEP_DEF              = 0x00000000
