SEQ_BB_ACT_BITS                  = 2
SEQ_BB_ACT_LSB                   = 0
SEQ_BB_ACT_MSB                   = 1
SEQ_BB_ACT_MASK                  = 0x00000003
SEQ_BB_ACT_SH                    = 0
SEQ_BB_ACT_DEF                   = 0x00000000
# -----------------------------------------------------------------
# seq FB: Frame Boundary Action Register
# 
# Access RW
# -----------------------------------------------------------------
SEQ_ADDR_FB                      = 0x10a04010
# -----------------------------------------------------------------
# ------
# ACT: 
# Access RW
# This setting determines what action the sequencer will take when
# waiting for this boundary. This field uses the seq_action encoded
# values.
SEQ_FB_ACT_BITS                  = 2
SEQ_FB_ACT_LSB                   = 0
SEQ_FB_ACT_MSB                   = 1
SEQ_FB_ACT_MASK                  = 0x00000003
SEQ_FB_ACT_SH                    = 0
SEQ_FB_ACT_DEF                   = 0x00000000
# -----------------------------------------------------------------
# seq TB: Timer Boundary Action Register
# 
# Access RW
# -----------------------------------------------------------------
SEQ_ADDR_TB                      = 0x10a04014
# -----------------------------------------------------------------
# ------
# ACT: 
# Access RW
# This setting determines what action the sequencer will take when
# waiting for this boundary. This field uses the seq_action encoded
# values.
SEQ_TB_ACT_BITS                  = 2
SEQ_TB_ACT_LSB                   = 0
SEQ_TB_ACT_MSB                   = 1
SEQ_TB_ACT_MASK                  = 0x00000003
SEQ_TB_ACT_SH                    = 0
SEQ_TB_ACT_DEF                   = 0x00000000
# -----------------------------------------------------------------
# seq SB: Sequence Boundary Action Register
# 
# Access RW
# -----------------------------------------------------------------
SEQ_ADDR_SB                      = 0x10a04018
# -----------------------------------------------------------------
# ------
# ACT: 
# Access RW
# This setting determines what action the sequencer will take when
# waiting for this boundary. This field uses the seq_action encoded
# values.
SEQ_SB_ACT_BITS                  = 2
SEQ_SB_ACT_LSB                   = 0
SEQ_SB_ACT_MSB                   = 1
SEQ_SB_ACT_MASK                  = 0x00000003
SEQ_SB_ACT_SH                    = 0
SEQ_SB_ACT_DEF                   = 0x00000000
# -----------------------------------------------------------------
# seq INDEX: Index Action Register
# 
# Access RW
# -----------------------------------------------------------------
SEQ_ADDR_INDEX                   = 0x10a0401c
# -----------------------------------------------------------------
# ------
# ACTION_ON_INDEX: 
# Access RW
# When set the sequencer will execute the action if it encounters a LLE
# matching the index set in the Index field.
SEQ_INDEX_ACTION_ON_INDEX_BITS   = 2
SEQ_INDEX_ACTION_ON_INDEX_LSB    = 0
SEQ_INDEX_ACTION_ON_INDEX_MSB    = 1
SEQ_INDEX_ACTION_ON_INDEX_MASK   = 0x00000003
SEQ_INDEX_ACTION_ON_INDEX_SH     = 0
SEQ_INDEX_ACTION_ON_INDEX_DEF    = 0x00000000
# ------
# ACTION_INDEX: 
# Access RW
# When action_on_index is set sequencer will perform the action on the
# LLE whose index matches this field.
SEQ_INDEX_ACTION_INDEX_BITS      = 10
SEQ_INDEX_ACTION_INDEX_LSB       = 16
SEQ_INDEX_ACTION_INDEX_MSB       = 25
SEQ_INDEX_ACTION_INDEX_MASK      = 0x03ff0000
SEQ_INDEX_ACTION_INDEX_SH        = 16
SEQ_INDEX_ACTION_INDEX_DEF       = 0x00000000
# -----------------------------------------------------------------
# seq JMP: Jump Address Register
# When the Go bit in the cmd register is written the sequencer will
# begin fetching LLE from this address.
# Access RW
# -----------------------------------------------------------------
SEQ_ADDR_JMP                     = 0x10a04020
# -----------------------------------------------------------------
# ------
# ADR: 
# Access RW
SEQ_JMP_ADR_BITS                 = 10
SEQ_JMP_ADR_LSB                  = 0
SEQ_JMP_ADR_MSB                  = 9
SEQ_JMP_ADR_MASK                 = 0x000003ff
SEQ_JMP_ADR_SH                   = 0
SEQ_JMP_ADR_DEF                  = 0x00000000
# -----------------------------------------------------------------
# seq MAGIC: Magic Check Value Register
# 
# Access RW
# -----------------------------------------------------------------
SEQ_ADDR_MAGIC                   = 0x10a04028
# -----------------------------------------------------------------
# ------
# NUMBER: 
# Access RO
# This value is checked against the Magic number field of a LLE to
# determine if it is valid.
SEQ_MAGIC_NUMBER_BITS            = 16
SEQ_MAGIC_NUMBER_LSB             = 0
SEQ_MAGIC_NUMBER_MSB             = 15
SEQ_MAGIC_NUMBER_MASK            = 0x0000ffff
SEQ_MAGIC_NUMBER_SH              = 0
SEQ_MAGIC_NUMBER_DEF             = 0x0000cada
# -----------------------------------------------------------------
# seq LLE0: Current LLE Word 0 Register
# Bits 31:0 of the current LLE being processed.
# Access RO
# -----------------------------------------------------------------
SEQ_ADDR_LLE0                    = 0x10a04030
# -----------------------------------------------------------------
# ------
SEQ_LLE0_BITS                    = 32
SEQ_LLE0_LSB                     = 0
SEQ_LLE0_MSB                     = 31
SEQ_LLE0_MASK                    = 0xffffffff
SEQ_LLE0_SH                      = 0
SEQ_LLE0_DEF                     = 0x00000000
# -----------------------------------------------------------------
# seq LLE1: Current LLE Word 1 Register
# Bits 63:32 of the current LLE being processed.
# Access RO
# -----------------------------------------------------------------
SEQ_ADDR_LLE1                    = 0x10a04034
# -----------------------------------------------------------------
# ------
SEQ_LLE1_BITS                    = 32
SEQ_LLE1_LSB                     = 0
SEQ_LLE1_MSB                     = 31
SEQ_LLE1_MASK                    = 0xffffffff
SEQ_LLE1_SH                      = 0
SEQ_LLE1_DEF                     = 0x00000000
# -----------------------------------------------------------------
# seq LLE2: Current LLE Word 2 Register
# Bits 95:64 of the current LLE being processed.
# Access RO
# -----------------------------------------------------------------
SEQ_ADDR_LLE2                    = 0x10a04038
# -----------------------------------------------------------------
# ------
SEQ_LLE2_BITS                    = 32
SEQ_LLE2_LSB                     = 0
SEQ_LLE2_MSB                     = 31
SEQ_LLE2_MASK                    = 0xffffffff
SEQ_LLE2_SH                      = 0
SEQ_LLE2_DEF                     = 0x00000000
# -----------------------------------------------------------------
# seq LLE3: Current LLE Word 3 Register
# Bits 127:96 of the current LLE being processed.
# Access RO
# -----------------------------------------------------------------
SEQ_ADDR_LLE3                    = 0x10a0403c
# -----------------------------------------------------------------
# ------
SEQ_LLE3_BITS                    = 32
SEQ_LLE3_LSB                     = 0
SEQ_LLE3_MSB                     = 31
SEQ_LLE3_MASK                    = 0xffffffff
SEQ_LLE3_SH                      = 0
SEQ_LLE3_DEF                     = 0x00000000
# -----------------------------------------------------------------
# seq PYLD: Current Payload Destination Register
# Payload desination address and word count of LLE being processed.
# Access RO
# -----------------------------------------------------------------
SEQ_ADDR_PYLD                    = 0x10a04040
# -----------------------------------------------------------------
# ------
# ADR: 
# Access RO
# Payload destination address.
SEQ_PYLD_ADR_BITS                = 24
SEQ_PYLD_ADR_LSB                 = 0
SEQ_PYLD_ADR_MSB                 = 23
SEQ_PYLD_ADR_MASK                = 0x00ffffff
SEQ_PYLD_ADR_SH                  = 0
SEQ_PYLD_ADR_DEF                 = 0x00000000
# ------
# WDS: 
# Access RO
# Payload word count.
SEQ_PYLD_WDS_BITS                = 8
SEQ_PYLD_WDS_LSB                 = 24
SEQ_PYLD_WDS_MSB                 = 31
SEQ_PYLD_WDS_MASK                = 0xff000000
SEQ_PYLD_WDS_SH                  = 24
SEQ_PYLD_WDS_DEF                 = 0x00000000
# -----------------------------------------------------------------
# seq DEBUG: Debug Control Register
# 
# Access RW
# -----------------------------------------------------------------
SEQ_ADDR_DEBUG                   = 0x10a04050
# -----------------------------------------------------------------
