# TRIGGER: 
# Access RW
# If the sequencer is waiting at a boundary force the trigger condition.
# Clear and set to force again.
SEQ_DEBUG_TRIGGER_BIT            = 0
SEQ_DEBUG_TRIGGER_MASK           = 0x00000001
SEQ_DEBUG_TRIGGER_SH             = 0
SEQ_DEBUG_TRIGGER_DEF            = 0x00000000
# ------
# PRBMX_SEL: 
# Access RW
# Sequencer probe mux selects.
# Value      | Setting
# _________________________________________________________________
# 0          | {sb_wait, tb_wait, fb_wait, bb_wait, state}
# 1          | {clr_status, pri_eos, pri_eof, pri_sync, state}
# 2          | {sb_jump, tb_jump, fb_jump, bb_jump, state}
# 3          | {sb_stop, tb_stop, fb_stop, bb_stop, state}
# 4          | {sb_wait, tb_wait, fb_wait, bb_wait, pri_eos, timer_done,
# pri_eof, pri_sync}
# 5          | {pyld_last, pyld_strt, pyld_done, pyld_state}
# 6          | {pyld_last, pyld_words}
# 7          | {lle_sleep, lle_sleep_fsm, lle_sleep_cpu, no_sleep}
# 
SEQ_DEBUG_PRBMX_SEL_BITS         = 3
SEQ_DEBUG_PRBMX_SEL_LSB          = 8
SEQ_DEBUG_PRBMX_SEL_MSB          = 10
SEQ_DEBUG_PRBMX_SEL_MASK         = 0x00000700
SEQ_DEBUG_PRBMX_SEL_SH           = 8
SEQ_DEBUG_PRBMX_SEL_DEF          = 0x00000000

# =================================================================
# se: Streaming Engine Registers
# 
# -----------------------------------------------------------------
# se ST: Status Register
# 
# Access RW
# -----------------------------------------------------------------
SE_ADDR_ST                       = 0x10a05000
# -----------------------------------------------------------------
# ------
# SMP_ERR: 
# Access WC
# Set when a CPU write to a register that does not exist occurs.
SE_ST_SMP_ERR_BIT                = 0
SE_ST_SMP_ERR_MASK               = 0x00000001
SE_ST_SMP_ERR_SH                 = 0
SE_ST_SMP_ERR_DEF                = 0x00000000
# ------
# CPL_ST: 
# Access WC
# Completion status of DMA initiated by the streaming engine.
SE_ST_CPL_ST_BITS                = 2
SE_ST_CPL_ST_LSB                 = 1
SE_ST_CPL_ST_MSB                 = 2
SE_ST_CPL_ST_MASK                = 0x00000006
SE_ST_CPL_ST_SH                  = 1
SE_ST_CPL_ST_DEF                 = 0x00000000
# ------
# BOF: 
# Access WC
# Buffer overflow. Indicates a buffer with data from a previous line was
# overwritten with a new line.
SE_ST_BOF_BITS                   = 8
SE_ST_BOF_LSB                    = 8
SE_ST_BOF_MSB                    = 15
SE_ST_BOF_MASK                   = 0x0000ff00
SE_ST_BOF_SH                     = 8
SE_ST_BOF_DEF                    = 0x00000000
# ------
# DOF: 
# Access WC
# Data overflow. Indicates the line was longer than the maximum buffer
# size of 2048 words.
SE_ST_DOF_BITS                   = 8
SE_ST_DOF_LSB                    = 16
SE_ST_DOF_MSB                    = 23
SE_ST_DOF_MASK                   = 0x00ff0000
SE_ST_DOF_SH                     = 16
SE_ST_DOF_DEF                    = 0x00000000
# ------
# PS: 
# Access WC
# PRI Sync Error. Another PRI sync was received before the current line
# was finished being received. PRF is too high.
SE_ST_PS_BITS                    = 8
SE_ST_PS_LSB                     = 24
SE_ST_PS_MSB                     = 31
SE_ST_PS_MASK                    = 0xff000000
SE_ST_PS_SH                      = 24
SE_ST_PS_DEF                     = 0x00000000
# -----------------------------------------------------------------
# se CTL: Control Register
# 
# Access RW
# -----------------------------------------------------------------
SE_ADDR_CTL                      = 0x10a05004
# -----------------------------------------------------------------
# ------
# RESET: 
# Access RW
# Reset the streaming engine state and state machine.
SE_CTL_RESET_BIT                 = 0
SE_CTL_RESET_MASK                = 0x00000001
SE_CTL_RESET_SH                  = 0
SE_CTL_RESET_DEF                 = 0x00000000
# ------
# SLAVE: 
# Access RW
# The Streaming Engine is operating as a AXI slave for USB. This is
# necessary to prevent the SE sending DMA commands to PCIe when in USB
# mode.
SE_CTL_SLAVE_BIT                 = 1
SE_CTL_SLAVE_MASK                = 0x00000002
SE_CTL_SLAVE_SH                  = 1
SE_CTL_SLAVE_DEF                 = 0x00000000
# ------
# L1: 
# Access RW
# Enable SE to control when PCIe enters the L1 power managment state.
SE_CTL_L1_BIT                    = 2
SE_CTL_L1_MASK                   = 0x00000004
SE_CTL_L1_SH                     = 2
SE_CTL_L1_DEF                    = 0x00000000
# ------
# FAXP: 
# Access RW
# Force app_xfer_pending to 1.
SE_CTL_FAXP_BIT                  = 3
SE_CTL_FAXP_MASK                 = 0x00000008
SE_CTL_FAXP_SH                   = 3
SE_CTL_FAXP_DEF                  = 0x00000000
# ------
# NOSLEEP: 
# Access RW
# Prevent memory bank N from entering the sleep state.
SE_CTL_NOSLEEP_BITS              = 4
SE_CTL_NOSLEEP_LSB               = 4
SE_CTL_NOSLEEP_MSB               = 7
SE_CTL_NOSLEEP_MASK              = 0x000000f0
SE_CTL_NOSLEEP_SH                = 4
SE_CTL_NOSLEEP_DEF               = 0x00000000
# ------
# RESET_E: 
# Access RW
# Per engine soft reset. Bit 8: BeamFormer. Bit 9: CW, Bit 10: Sensor.
SE_CTL_RESET_E_BITS              = 3
SE_CTL_RESET_E_LSB               = 8
SE_CTL_RESET_E_MSB               = 10
SE_CTL_RESET_E_MASK              = 0x00000700
SE_CTL_RESET_E_SH                = 8
SE_CTL_RESET_E_DEF               = 0x00000000
# ------
# PRBMX_SEL: 
# Access WO
# Streaming engine probe mux selects.
# Value      | Setting
# _________________________________________________________________
# 0          | {bif.dv, bif.start, bif.enable, bif.eof, tp_sof_bf,
# tp_state_bf}
# 1          | {cif.dv, cif.start, cif.enable, cif.eof, tp_sof_cw,
# tp_state_cw}
# 2          | {sif.dv, sif.start, sif.enable, sif.eof, tp_sof_ss,
# tp_state_ss}
# 3          | {cif.dv, cif.rdy, sif.dv, sif.rdy, 4'b0}
# 4          | {dma_d.vld, dma_d.rdy, dma_d.dt, dma_d.cb}
# 5          | {dma_d.vld, dma_d.rdy, dma_d.intr, dma_cpl.vld,
# dma_cpl.dt, dma_cpl.status}
# 6          | {dma_cpl.vld, dma_cpl.dt, dma_cpl.cb, 1'b0}
# 7          | {sys_flush_req, sys_xfer_pending, active, 3'b0}
# 
SE_CTL_PRBMX_SEL_BITS            = 3
SE_CTL_PRBMX_SEL_LSB             = 12
SE_CTL_PRBMX_SEL_MSB             = 14
SE_CTL_PRBMX_SEL_MASK            = 0x00007000
SE_CTL_PRBMX_SEL_SH              = 12
SE_CTL_PRBMX_SEL_DEF             = 0x00000000
# ------
# FLUSH: 
# Access WO
# Force PCIe core to flush its buffers. Use with caution.
SE_CTL_FLUSH_BIT                 = 16
SE_CTL_FLUSH_MASK                = 0x00010000
SE_CTL_FLUSH_SH                  = 16
SE_CTL_FLUSH_DEF                 = 0x00000000
# -----------------------------------------------------------------
# se DT0_FADDR: Data Type 0 (B-Mode) Frame Buffer AXI Address Register
# Frame Buffer Base Address in AXI memory space. Frame buffer should
# begin on a 1MB address boundary and in the range 0x2000_0000 to
# 0x3fff_ffff. Frame stride must be < 1 MB
# Access RW
# -----------------------------------------------------------------
SE_ADDR_DT0_FADDR                = 0x10a05020
# -----------------------------------------------------------------
# ------
# ADDR: 
# Access RW
# Forced to 8 byte alignment.
SE_DT0_FADDR_ADDR_BITS           = 27
SE_DT0_FADDR_ADDR_LSB            = 3
SE_DT0_FADDR_ADDR_MSB            = 29
SE_DT0_FADDR_ADDR_MASK           = 0x3ffffff8
SE_DT0_FADDR_ADDR_SH             = 3
SE_DT0_FADDR_ADDR_DEF            = 0x00000000
# -----------------------------------------------------------------
# se DT0_FSTR: Data Type 0 (B-Mode) Frame Stride Register
# 
# Access RW
# -----------------------------------------------------------------
SE_ADDR_DT0_FSTR                 = 0x10a05024
# -----------------------------------------------------------------
# ------
# STRIDE: 
# Access RW
# For the next frame the streaming engine will add this value to the
# current address pointer. When the last frame in the buffer is reached
# the streaming engine will wrap back to the beginning. The frame stride
# must be a multiple of 8 bytes. For best performance it should be an
# integral number of 4KB pages.
SE_DT0_FSTR_STRIDE_BITS          = 17
SE_DT0_FSTR_STRIDE_LSB           = 3
SE_DT0_FSTR_STRIDE_MSB           = 19
SE_DT0_FSTR_STRIDE_MASK          = 0x000ffff8
SE_DT0_FSTR_STRIDE_SH            = 3
SE_DT0_FSTR_STRIDE_DEF           = 0x00000000
# ------
# SIZE: 
# Access RW
# Number of buffers in the frame buffer. Buffers = 1 << size.
SE_DT0_FSTR_SIZE_BITS            = 3
SE_DT0_FSTR_SIZE_LSB             = 24
SE_DT0_FSTR_SIZE_MSB             = 26
SE_DT0_FSTR_SIZE_MASK            = 0x07000000
SE_DT0_FSTR_SIZE_SH              = 24
SE_DT0_FSTR_SIZE_DEF             = 0x00000000
# -----------------------------------------------------------------
# se DT0_LSTR: Data Type 0 (B-Mode) Line Stride Register
# 
# Access RW
# -----------------------------------------------------------------
SE_ADDR_DT0_LSTR                 = 0x10a05028
# -----------------------------------------------------------------
# ------
# STRIDE: 
# Access RW
# Each time a line is written to a frame buffer the streaming engine
# adds this value to the current address pointer. The line stride must
# be a multiple of 8 bytes.
SE_DT0_LSTR_STRIDE_BITS          = 10
SE_DT0_LSTR_STRIDE_LSB           = 3
SE_DT0_LSTR_STRIDE_MSB           = 12
SE_DT0_LSTR_STRIDE_MASK          = 0x00001ff8
SE_DT0_LSTR_STRIDE_SH            = 3
SE_DT0_LSTR_STRIDE_DEF           = 0x00000000
# -----------------------------------------------------------------
# se DT0_FIDX: Data Type 0 (B-Mode) Frame Header Start Index Register
# 
# Access RW
# -----------------------------------------------------------------
SE_ADDR_DT0_FIDX                 = 0x10a0502c
# -----------------------------------------------------------------
# ------
# INDEX: 
# Access RW
# This is the starting index value the streaming engine will use in the
# frame header.
SE_DT0_FIDX_INDEX_BITS           = 24
SE_DT0_FIDX_INDEX_LSB            = 0
SE_DT0_FIDX_INDEX_MSB            = 23
SE_DT0_FIDX_INDEX_MASK           = 0x00ffffff
SE_DT0_FIDX_INDEX_SH             = 0
SE_DT0_FIDX_INDEX_DEF            = 0x00000000
# -----------------------------------------------------------------
# se DT0_CADDR: Data Type 0 (B-Mode) On Chip Frame Buffer Base Address
# 
# Access RW
# -----------------------------------------------------------------
SE_ADDR_DT0_CADDR                = 0x10a05030
# -----------------------------------------------------------------
# ------
# ADDR: 
# Access RW
# This is the starting address of the on chip frame buffer. 8 byte
# aligned.
SE_DT0_CADDR_ADDR_BITS           = 17
SE_DT0_CADDR_ADDR_LSB            = 3
SE_DT0_CADDR_ADDR_MSB            = 19
SE_DT0_CADDR_ADDR_MASK           = 0x000ffff8
SE_DT0_CADDR_ADDR_SH             = 3
SE_DT0_CADDR_ADDR_DEF            = 0x00000000
# ------
# CBSIZE: 
# Access RW
# Number of buffers in the on chip frame buffer. Buffers = 1 << size.
SE_DT0_CADDR_CBSIZE_BITS         = 2
SE_DT0_CADDR_CBSIZE_LSB          = 24
SE_DT0_CADDR_CBSIZE_MSB          = 25
SE_DT0_CADDR_CBSIZE_MASK         = 0x03000000
SE_DT0_CADDR_CBSIZE_SH           = 24
SE_DT0_CADDR_CBSIZE_DEF          = 0x00000000
# -----------------------------------------------------------------
# se DT0_CTL: Data Type 0 Control Register
# 
# Access RW
# -----------------------------------------------------------------
SE_ADDR_DT0_CTL                  = 0x10a05034
# -----------------------------------------------------------------
# ------
# ENABLE: 
# Access RW
# Enable collection of this data type.
SE_DT0_CTL_ENABLE_BIT            = 1
