# =================================================================
# i2s: I2S Registers
# 
# -----------------------------------------------------------------
# i2s I2SFRAMECFG: Streaming engine packets Configuration Register.
# 
# Access RW
# -----------------------------------------------------------------
I2S_ADDR_I2SFRAMECFG             = 0x10a06000
# -----------------------------------------------------------------
# ------
# FRAMESIZE: 
# Access RW
# Indicates, number of samples per frame.
I2S_I2SFRAMECFG_FRAMESIZE_BITS   = 16
I2S_I2SFRAMECFG_FRAMESIZE_LSB    = 0
I2S_I2SFRAMECFG_FRAMESIZE_MSB    = 15
I2S_I2SFRAMECFG_FRAMESIZE_MASK   = 0x0000ffff
I2S_I2SFRAMECFG_FRAMESIZE_SH     = 0
I2S_I2SFRAMECFG_FRAMESIZE_DEF    = 0x0000000f
# ------
# SAMPLESIZE: 
# Access RW
# Indicates, number of words per sample. Per cycle I2S received data
# from left, right channel.. 2 words, keep this as multiple of 2. Valid
# range 0-31. 0 means 1 ... similarly 31 means 32 words.
I2S_I2SFRAMECFG_SAMPLESIZE_BITS  = 8
I2S_I2SFRAMECFG_SAMPLESIZE_LSB   = 16
I2S_I2SFRAMECFG_SAMPLESIZE_MSB   = 23
I2S_I2SFRAMECFG_SAMPLESIZE_MASK  = 0x00ff0000
I2S_I2SFRAMECFG_SAMPLESIZE_SH    = 16
I2S_I2SFRAMECFG_SAMPLESIZE_DEF   = 0x00000000
# -----------------------------------------------------------------
# i2s START: I2S Start Configuration Register
# 
# Access RW
# -----------------------------------------------------------------
I2S_ADDR_START                   = 0x10a06004
# -----------------------------------------------------------------
# ------
# CWSTART: 
# Access RW
# Must be set to 1 during entire I2S active period, to kick-off I2S
# activity.
I2S_START_CWSTART_BIT            = 0
I2S_START_CWSTART_MASK           = 0x00000001
I2S_START_CWSTART_SH             = 0
I2S_START_CWSTART_DEF            = 0x00000000
# -----------------------------------------------------------------
# i2s I2SCLKDIV: I2S clock dividers
# 
# Access RW
# -----------------------------------------------------------------
I2S_ADDR_I2SCLKDIV               = 0x10a06008
# -----------------------------------------------------------------
# ------
# LRCLKDIV: 
# Access RW
# LRCLK Divider(N), lrclk = SCLK/(N+1); must be set in Master mode. N
# should be minimum:63
I2S_I2SCLKDIV_LRCLKDIV_BITS      = 8
I2S_I2SCLKDIV_LRCLKDIV_LSB       = 0
I2S_I2SCLKDIV_LRCLKDIV_MSB       = 7
I2S_I2SCLKDIV_LRCLKDIV_MASK      = 0x000000ff
I2S_I2SCLKDIV_LRCLKDIV_SH        = 0
I2S_I2SCLKDIV_LRCLKDIV_DEF       = 0x0000003f
# ------
# MCLKDIV: 
# Access RW
# MCLK Divider(N), mclk = sysbus_clock/(N+1)
I2S_I2SCLKDIV_MCLKDIV_BITS       = 8
I2S_I2SCLKDIV_MCLKDIV_LSB        = 8
I2S_I2SCLKDIV_MCLKDIV_MSB        = 15
I2S_I2SCLKDIV_MCLKDIV_MASK       = 0x0000ff00
I2S_I2SCLKDIV_MCLKDIV_SH         = 8
I2S_I2SCLKDIV_MCLKDIV_DEF        = 0x00000003
# ------
# SCLKDIV: 
# Access RW
# SCLK Divider(N), sclk = sysbus_clock/(N+1); must be set in Master mode
I2S_I2SCLKDIV_SCLKDIV_BITS       = 8
I2S_I2SCLKDIV_SCLKDIV_LSB        = 16
I2S_I2SCLKDIV_SCLKDIV_MSB        = 23
I2S_I2SCLKDIV_SCLKDIV_MASK       = 0x00ff0000
I2S_I2SCLKDIV_SCLKDIV_SH         = 16
I2S_I2SCLKDIV_SCLKDIV_DEF        = 0x00000003
# -----------------------------------------------------------------
# i2s I2SCONFIG: I2S configuration register
# 
# Access RW
# -----------------------------------------------------------------
I2S_ADDR_I2SCONFIG               = 0x10a0600c
# -----------------------------------------------------------------
# ------
# I2SMODE: 
# Access RW
# 1: Master Mode; 0: Slave mode
I2S_I2SCONFIG_I2SMODE_BIT        = 0
I2S_I2SCONFIG_I2SMODE_MASK       = 0x00000001
I2S_I2SCONFIG_I2SMODE_SH         = 0
I2S_I2SCONFIG_I2SMODE_DEF        = 0x00000000
# ------
# I2SENABLE: 
# Access RW
# 1: I2S/LJ is enabled; 0: Disabled
I2S_I2SCONFIG_I2SENABLE_BIT      = 1
I2S_I2SCONFIG_I2SENABLE_MASK     = 0x00000002
I2S_I2SCONFIG_I2SENABLE_SH       = 1
I2S_I2SCONFIG_I2SENABLE_DEF      = 0x00000000
# ------
# I2SLJ: 
# Access RW
# 1: I2S Mode; 0: LJ mode
I2S_I2SCONFIG_I2SLJ_BIT          = 2
I2S_I2SCONFIG_I2SLJ_MASK         = 0x00000004
I2S_I2SCONFIG_I2SLJ_SH           = 2
I2S_I2SCONFIG_I2SLJ_DEF          = 0x00000000
# ------
# DASTLRCK: 
# Access RW
# 1: Acquire start on rising edge of LRCK; 0: Acquire start on falling
# edge of LRCK.
I2S_I2SCONFIG_DASTLRCK_BIT       = 3
I2S_I2SCONFIG_DASTLRCK_MASK      = 0x00000008
I2S_I2SCONFIG_DASTLRCK_SH        = 3
I2S_I2SCONFIG_DASTLRCK_DEF       = 0x00000001
# ------
# I2SCORERESET: 
# Access RW
# 1: Bit clock Core logic gets reset; 0: no reset; logic must be reset
# before enabling I2S/LJ
I2S_I2SCONFIG_I2SCORERESET_BIT   = 31
I2S_I2SCONFIG_I2SCORERESET_MASK  = 0x80000000
I2S_I2SCONFIG_I2SCORERESET_SH    = 31
I2S_I2SCONFIG_I2SCORERESET_DEF   = 0x00000001
# -----------------------------------------------------------------
# i2s I2SDATARCVD: I2S Received Data
# 
# Access RW
# -----------------------------------------------------------------
I2S_ADDR_I2SDATARCVD             = 0x10a06010
# -----------------------------------------------------------------
# ------
# I2SDATA: 
# Access RO
# Received channel data.
I2S_I2SDATARCVD_I2SDATA_BITS     = 24
I2S_I2SDATARCVD_I2SDATA_LSB      = 0
I2S_I2SDATARCVD_I2SDATA_MSB      = 23
I2S_I2SDATARCVD_I2SDATA_MASK     = 0x00ffffff
I2S_I2SDATARCVD_I2SDATA_SH       = 0
I2S_I2SDATARCVD_I2SDATA_DEF      = 0x00000000
# ------
# I2SCHANNEL: 
# Access RO
# 0-> Right Channel; 1-> Left Channel
I2S_I2SDATARCVD_I2SCHANNEL_BIT   = 24
I2S_I2SDATARCVD_I2SCHANNEL_MASK  = 0x01000000
I2S_I2SDATARCVD_I2SCHANNEL_SH    = 24
I2S_I2SDATARCVD_I2SCHANNEL_DEF   = 0x00000000
# -----------------------------------------------------------------
# i2s I2SST: I2S Status
# 
# Access RW
# -----------------------------------------------------------------
I2S_ADDR_I2SST                   = 0x10a06014
# -----------------------------------------------------------------
# ------
# I2SDATARDY: 
# Access W1C
# 1-> Channel data is ready. If not cleared then it will stay high
# forever. Debug status bit...
I2S_I2SST_I2SDATARDY_BIT         = 0
I2S_I2SST_I2SDATARDY_MASK        = 0x00000001
I2S_I2SST_I2SDATARDY_SH          = 0
I2S_I2SST_I2SDATARDY_DEF         = 0x00000000

# =================================================================
# sensor: System Monitor and Sensor Registers
# Sensor engine to manage I2C, SPI and DA/EKG sensors.
# -----------------------------------------------------------------
# sensor ST: Status Register
# 
# Access RW
# -----------------------------------------------------------------
SENSOR_ADDR_ST                   = 0x10a07400
# -----------------------------------------------------------------
# ------
# BUSY: 
# Access RO
# 1 --> Either I2C or SPI engine are busy. Useful when running manual
# mode single channel data acquisition
SENSOR_ST_BUSY_BIT               = 0
SENSOR_ST_BUSY_MASK              = 0x00000001
