SENSOR_SPIMCFG_SPIDEV_LSB        = 1
SENSOR_SPIMCFG_SPIDEV_MSB        = 2
SENSOR_SPIMCFG_SPIDEV_MASK       = 0x00000006
SENSOR_SPIMCFG_SPIDEV_SH         = 1
SENSOR_SPIMCFG_SPIDEV_DEF        = 0x00000000
