SENSOR_I2C1CTL_CLKDIV_SH         = 0
SENSOR_I2C1CTL_CLKDIV_DEF        = 0x000000ea
# -----------------------------------------------------------------
# sensor I2C1CMD: Command Register
# Initiate an I2C write by writing 1 to 4 bytes to the WDAT register.
# Then write the slave address, clear the read bit and set the byte
# count and go bit in this register. Initiate an I2C read by writing the
# slave address, setting the read bit, the byte count and the go bit in
# this register. Poll or enable the I2C completion interrupt. When a
# read operation is complete read the data from the RDAT register.
# Access RW
# -----------------------------------------------------------------
SENSOR_ADDR_I2C1CMD              = 0x10a07134
# -----------------------------------------------------------------
# ------
# BYTECNT: 
# Access RW
# Byte count of transfer. Up to 16 bytes can be writen. BCnt =
# num_bytes-1. That is, a value of 0 indicates 1 byte, 3 indicates 4
# bytes, etc.
SENSOR_I2C1CMD_BYTECNT_BITS      = 4
SENSOR_I2C1CMD_BYTECNT_LSB       = 0
SENSOR_I2C1CMD_BYTECNT_MSB       = 3
SENSOR_I2C1CMD_BYTECNT_MASK      = 0x0000000f
SENSOR_I2C1CMD_BYTECNT_SH        = 0
SENSOR_I2C1CMD_BYTECNT_DEF       = 0x00000000
# ------
# READ: 
# Access RW
# Set to one to initiate an I2C read. Set to 0 for a write.
SENSOR_I2C1CMD_READ_BIT          = 8
SENSOR_I2C1CMD_READ_MASK         = 0x00000100
SENSOR_I2C1CMD_READ_SH           = 8
SENSOR_I2C1CMD_READ_DEF          = 0x00000000
