PMONCTRL_PWRCONFIG_AUTOACQ_MASK  = 0x00000004
PMONCTRL_PWRCONFIG_AUTOACQ_SH    = 2
PMONCTRL_PWRCONFIG_AUTOACQ_DEF   = 0x00000000
