PMONCTRL_PWRCONFIG_CONTMODE_MASK = 0x00000008
PMONCTRL_PWRCONFIG_CONTMODE_SH   = 3
PMONCTRL_PWRCONFIG_CONTMODE_DEF  = 0x00000000
