# 1: HVP Instantaneous Current is above Threshold HvpPeakThi; 0: HVP
# Instantaneous Current is below Threshold HvpPeakThi.
PMONCTRL_HVPEAKSTAT_HVPPEAKFAULTI_BIT = 1
PMONCTRL_HVPEAKSTAT_HVPPEAKFAULTI_MASK = 0x00000002
PMONCTRL_HVPEAKSTAT_HVPPEAKFAULTI_SH = 1
PMONCTRL_HVPEAKSTAT_HVPPEAKFAULTI_DEF = 0x00000000
# ------
# HVNPEAKFAULTV: 
# Access RO
# 1: HVN Instantaneous Voltage is above Threshold HvnPeakThv; 0: HVN
# Instantaneous Voltage is below Threshold HvnPeakThv.
PMONCTRL_HVPEAKSTAT_HVNPEAKFAULTV_BIT = 2
PMONCTRL_HVPEAKSTAT_HVNPEAKFAULTV_MASK = 0x00000004
PMONCTRL_HVPEAKSTAT_HVNPEAKFAULTV_SH = 2
PMONCTRL_HVPEAKSTAT_HVNPEAKFAULTV_DEF = 0x00000000
# ------
# HVNPEAKFAULTI: 
# Access RO
# 1: HVN Instantaneous Current is above Threshold HvnPeakThi; 0: HVN
# Instantaneous Current is below Threshold HvnPeakThi.
PMONCTRL_HVPEAKSTAT_HVNPEAKFAULTI_BIT = 3
PMONCTRL_HVPEAKSTAT_HVNPEAKFAULTI_MASK = 0x00000008
PMONCTRL_HVPEAKSTAT_HVNPEAKFAULTI_SH = 3
PMONCTRL_HVPEAKSTAT_HVNPEAKFAULTI_DEF = 0x00000000

# =================================================================
# bf: Beam Former Core
# Beam former registers are described elsewhere. Here lie monsters.
# -----------------------------------------------------------------
# bf TR0: beam former resets configuration/control Register
# Errata. An issue was found late in the design cycle where some
# registers were not getting reset properly the first time. The issue
# was resolved by resetting tr_swrst twice. SW should set tr_swrst and
# clear it and then set and clear it again.
# Access RW
# -----------------------------------------------------------------
BF_ADDR_TR0                      = 0x10c00000
# -----------------------------------------------------------------
# ------
# TR_SWRST: 
# Access RW
# Top level SW reset of beamformer signal processing and control logic.
# Other resets controled by following bits. This bit will not reset the
# top, beam parameter, or diagnostic register files.
BF_TR0_TR_SWRST_BIT              = 0
BF_TR0_TR_SWRST_MASK             = 0x00000001
BF_TR0_TR_SWRST_SH               = 0
BF_TR0_TR_SWRST_DEF              = 0x00000000
# ------
# TR_SPI_SWRST: 
# Access RW
# AFE5832 SPI interface SW reset.
BF_TR0_TR_SPI_SWRST_BIT          = 1
BF_TR0_TR_SPI_SWRST_MASK         = 0x00000002
BF_TR0_TR_SPI_SWRST_SH           = 1
BF_TR0_TR_SPI_SWRST_DEF          = 0x00000000
# ------
# TR_AFEIO_SWRST: 
# Access RW
# AFE5832 input interface SW reset.
BF_TR0_TR_AFEIO_SWRST_BIT        = 2
BF_TR0_TR_AFEIO_SWRST_MASK       = 0x00000004
BF_TR0_TR_AFEIO_SWRST_SH         = 2
BF_TR0_TR_AFEIO_SWRST_DEF        = 0x00000000
# ------
# TR_AFE_SWRST: 
# Access RW
# AFE5832 SW reset.
BF_TR0_TR_AFE_SWRST_BIT          = 3
BF_TR0_TR_AFE_SWRST_MASK         = 0x00000008
BF_TR0_TR_AFE_SWRST_SH           = 3
BF_TR0_TR_AFE_SWRST_DEF          = 0x00000000
# ------
# TR_TX_SWRST: 
# Access RW
# STHV1600 reset.
BF_TR0_TR_TX_SWRST_BIT           = 4
BF_TR0_TR_TX_SWRST_MASK          = 0x00000010
BF_TR0_TR_TX_SWRST_SH            = 4
BF_TR0_TR_TX_SWRST_DEF           = 0x00000000
# ------
# TR_PSV_SWRST: 
# Access RW
# Reset of HV power supply voltage control PWM signals. Both HV+ and HV-
# pulse width modulation signals will be forced to the de- asserted
# state as defined in register HVPS0.
BF_TR0_TR_PSV_SWRST_BIT          = 5
BF_TR0_TR_PSV_SWRST_MASK         = 0x00000020
BF_TR0_TR_PSV_SWRST_SH           = 5
BF_TR0_TR_PSV_SWRST_DEF          = 0x00000000
# ------
# HV_FAULT_SWRST: 
# Access RW
# Clear HV disable due to hv fault input from power monitor.
BF_TR0_HV_FAULT_SWRST_BIT        = 8
BF_TR0_HV_FAULT_SWRST_MASK       = 0x00000100
BF_TR0_HV_FAULT_SWRST_SH         = 8
BF_TR0_HV_FAULT_SWRST_DEF        = 0x00000000
# ------
# HV_INT_SWRST: 
# Access RW
# Clear HV disable due to interrupt from HV pulsers.
BF_TR0_HV_INT_SWRST_BIT          = 9
BF_TR0_HV_INT_SWRST_MASK         = 0x00000200
BF_TR0_HV_INT_SWRST_SH           = 9
BF_TR0_HV_INT_SWRST_DEF          = 0x00000000
# -----------------------------------------------------------------
# bf LS0: beam former resets configuration/control Register
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_LS0                      = 0x10c00004
# -----------------------------------------------------------------
# ------
# TR_LS_EN: 
# Access RW
# PRI timer enable.
BF_LS0_TR_LS_EN_BIT              = 0
BF_LS0_TR_LS_EN_MASK             = 0x00000001
BF_LS0_TR_LS_EN_SH               = 0
BF_LS0_TR_LS_EN_DEF              = 0x00000000
# -----------------------------------------------------------------
# bf EN0: beam former resets configuration/control Register
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_EN0                      = 0x10c00008
# -----------------------------------------------------------------
# ------
# TR_TX_EN: 
# Access RW
# Top level transmit (TX) enable. 0 = TX is disabled. 1 = TX determined
# by beam parameter.
BF_EN0_TR_TX_EN_BIT              = 0
BF_EN0_TR_TX_EN_MASK             = 0x00000001
BF_EN0_TR_TX_EN_SH               = 0
BF_EN0_TR_TX_EN_DEF              = 0x00000000
# ------
# TR_RX_EN: 
# Access RW
# Top level receive (RX) enable. RX is defined as input from the AF5832
# and write to delay memory. 0 = RX disabled. 1 = RX determined by beam
# parameter.
BF_EN0_TR_RX_EN_BIT              = 1
BF_EN0_TR_RX_EN_MASK             = 0x00000002
BF_EN0_TR_RX_EN_SH               = 1
BF_EN0_TR_RX_EN_DEF              = 0x00000000
# ------
# TR_BF_EN: 
# Access RW
# Top level beamforming (BF) enable. 0 = BF disabled. 1 = BF defined by
# beam parameters.
BF_EN0_TR_BF_EN_BIT              = 2
BF_EN0_TR_BF_EN_MASK             = 0x00000004
BF_EN0_TR_BF_EN_SH               = 2
BF_EN0_TR_BF_EN_DEF              = 0x00000000
# ------
# TR_AFE_AUTO_RST_EN: 
# Access RW
# Enable automatic reset of AFE5832 parts after transition from power
# down to standby or full power. The time of the actual reset is defined
# by a delay from the start of AFE power up.
BF_EN0_TR_AFE_AUTO_RST_EN_BIT    = 5
BF_EN0_TR_AFE_AUTO_RST_EN_MASK   = 0x00000020
BF_EN0_TR_AFE_AUTO_RST_EN_SH     = 5
BF_EN0_TR_AFE_AUTO_RST_EN_DEF    = 0x00000000
# ------
# TR_AFEIO_AUTO_RST_EN: 
# Access RW
# AFE interface auto-reset enable. Enables automatic reset of the
# AFE5832 input interface on transition from power down to standby or
# full power. The time of the actual reset is defined by a delay from
# the start of AFE power up.
BF_EN0_TR_AFEIO_AUTO_RST_EN_BIT  = 6
BF_EN0_TR_AFEIO_AUTO_RST_EN_MASK = 0x00000040
BF_EN0_TR_AFEIO_AUTO_RST_EN_SH   = 6
BF_EN0_TR_AFEIO_AUTO_RST_EN_DEF  = 0x00000000
# ------
# TR_AFEIO_CONFIG_EN: 
# Access RW
# AFE auto config enable. Enables a set of SPI write commands initiated
# after the AFE auto reset. This set of initialization commands is
# stored in a seperate LUT from the normal write queue.
BF_EN0_TR_AFEIO_CONFIG_EN_BIT    = 7
BF_EN0_TR_AFEIO_CONFIG_EN_MASK   = 0x00000080
BF_EN0_TR_AFEIO_CONFIG_EN_SH     = 7
BF_EN0_TR_AFEIO_CONFIG_EN_DEF    = 0x00000000
# ------
# TR_THSD: 
# Access RW
# Transmit pulser shutdown (STHV800) 0=Normal operation, 1=Force
# shutdown of TX pulser parts.
BF_EN0_TR_THSD_BIT               = 8
BF_EN0_TR_THSD_MASK              = 0x00000100
BF_EN0_TR_THSD_SH                = 8
BF_EN0_TR_THSD_DEF               = 0x00000000
# ------
# AFE0_SLOPE_EN: 
# Access RW
# AFE0 TGC_SLOPE pulse enable: 0 = TGC_SLOPE pulse disabled 1 =
# TGC_SLOPE pulse enable.
BF_EN0_AFE0_SLOPE_EN_BIT         = 16
BF_EN0_AFE0_SLOPE_EN_MASK        = 0x00010000
BF_EN0_AFE0_SLOPE_EN_SH          = 16
BF_EN0_AFE0_SLOPE_EN_DEF         = 0x00000000
# ------
# AFE1_SLOPE_EN: 
# Access RW
# AFE1 TGC_SLOPE pulse enable: 0 = TGC_SLOPE pulse disabled 1 =
# TGC_SLOPE pulse enable.
BF_EN0_AFE1_SLOPE_EN_BIT         = 17
BF_EN0_AFE1_SLOPE_EN_MASK        = 0x00020000
BF_EN0_AFE1_SLOPE_EN_SH          = 17
BF_EN0_AFE1_SLOPE_EN_DEF         = 0x00000000
# ------
# AFE0_UPDN_EN: 
# Access RW
# AFE0 TGC_UPDN pulse enable: 0 = TGC_UPDN pulse disabled 1 = TGC_UPDN
# pulse enable.
BF_EN0_AFE0_UPDN_EN_BIT          = 18
BF_EN0_AFE0_UPDN_EN_MASK         = 0x00040000
BF_EN0_AFE0_UPDN_EN_SH           = 18
BF_EN0_AFE0_UPDN_EN_DEF          = 0x00000000
# ------
# AFE1_UPDN_EN: 
# Access RW
# AFE1 TGC_UPDN pulse enable: 0 = TGC_UPDN pulse disabled 1 = TGC_UPDN
# pulse enable.
BF_EN0_AFE1_UPDN_EN_BIT          = 19
BF_EN0_AFE1_UPDN_EN_MASK         = 0x00080000
BF_EN0_AFE1_UPDN_EN_SH           = 19
BF_EN0_AFE1_UPDN_EN_DEF          = 0x00000000
# ------
# AFE0_TRIG_DISEN: 
# Access RW
# AFE0 TRIG signal disable: 0 = Normal mode 1 = TRIG signal output
# disabled.
BF_EN0_AFE0_TRIG_DISEN_BIT       = 20
BF_EN0_AFE0_TRIG_DISEN_MASK      = 0x00100000
BF_EN0_AFE0_TRIG_DISEN_SH        = 20
BF_EN0_AFE0_TRIG_DISEN_DEF       = 0x00000000
# ------
# AFE1_TRIG_DISEN: 
# Access RW
# AFE1 TRIG signal disable: 0 = Normal mode 1 = TRIG signal output
# disabled.
BF_EN0_AFE1_TRIG_DISEN_BIT       = 21
BF_EN0_AFE1_TRIG_DISEN_MASK      = 0x00200000
BF_EN0_AFE1_TRIG_DISEN_SH        = 21
BF_EN0_AFE1_TRIG_DISEN_DEF       = 0x00000000
# ------
# HV_TX_TRIG_POL: 
# Access RW
# 0 = Normal mode. STHV trigger signal is driven to 0 for SPI write
# time. 1 = Trigger signal driven to 1 for SPI write time.
BF_EN0_HV_TX_TRIG_POL_BIT        = 24
BF_EN0_HV_TX_TRIG_POL_MASK       = 0x01000000
BF_EN0_HV_TX_TRIG_POL_SH         = 24
BF_EN0_HV_TX_TRIG_POL_DEF        = 0x00000000
# ------
# HV_FAULT_DIS_MODE: 
# Access RW
# 0 = HV fault signal from power monitor will not force HV off. 1 = HV
# fault signal will force HV off if beam parameter
# bp_hv_fault_disable_mode is also 1.
BF_EN0_HV_FAULT_DIS_MODE_BIT     = 25
BF_EN0_HV_FAULT_DIS_MODE_MASK    = 0x02000000
BF_EN0_HV_FAULT_DIS_MODE_SH      = 25
BF_EN0_HV_FAULT_DIS_MODE_DEF     = 0x00000000
# ------
# HV_INT_DIS_MODE: 
# Access RW
# 0 = An interrupt from the STHV1600 parts will force HV off. 1 = An
# interrupt will force HV off if the beam parameter bp_int_dis_mode is
# also 1.
BF_EN0_HV_INT_DIS_MODE_BIT       = 26
BF_EN0_HV_INT_DIS_MODE_MASK      = 0x04000000
BF_EN0_HV_INT_DIS_MODE_SH        = 26
BF_EN0_HV_INT_DIS_MODE_DEF       = 0x00000000
# ------
# HV_TX_TRIG_ON: 
# Access RW
# 0 = Normal mode. 1 = Force tx_trigger pin to asserted state
BF_EN0_HV_TX_TRIG_ON_BIT         = 27
BF_EN0_HV_TX_TRIG_ON_MASK        = 0x08000000
BF_EN0_HV_TX_TRIG_ON_SH          = 27
BF_EN0_HV_TX_TRIG_ON_DEF         = 0x00000000
# ------
# HV_TX_TRIG_OFF: 
# Access RW
# 0 = Normal mode. 1 = Force tx_trigger pin to de-asserted state
BF_EN0_HV_TX_TRIG_OFF_BIT        = 28
BF_EN0_HV_TX_TRIG_OFF_MASK       = 0x10000000
BF_EN0_HV_TX_TRIG_OFF_SH         = 28
BF_EN0_HV_TX_TRIG_OFF_DEF        = 0x00000000
# ------
# HV_TX_TRIG_PULSE: 
# Access RW
# 0 = Normal mode. 1 = Generate one cycle pulse on tx_trigger when bit
# changes from 0 to 1
BF_EN0_HV_TX_TRIG_PULSE_BIT      = 29
BF_EN0_HV_TX_TRIG_PULSE_MASK     = 0x20000000
BF_EN0_HV_TX_TRIG_PULSE_SH       = 29
BF_EN0_HV_TX_TRIG_PULSE_DEF      = 0x00000000
# ------
# HV_FAULT_RST_MODE: 
# Access RW
# 0 = Normal mode. 1 = STHV1600 part reset asserted on HV fault
BF_EN0_HV_FAULT_RST_MODE_BIT     = 30
BF_EN0_HV_FAULT_RST_MODE_MASK    = 0x40000000
BF_EN0_HV_FAULT_RST_MODE_SH      = 30
BF_EN0_HV_FAULT_RST_MODE_DEF     = 0x00000000
# ------
# HV_FAULT_EN_MODE: 
# Access RW
# 0 = Normal mode. 1 = both hvps_en0 and hvps_en1 de-asserted on HV
# fault
BF_EN0_HV_FAULT_EN_MODE_BIT      = 31
BF_EN0_HV_FAULT_EN_MODE_MASK     = 0x80000000
BF_EN0_HV_FAULT_EN_MODE_SH       = 31
BF_EN0_HV_FAULT_EN_MODE_DEF      = 0x00000000
# -----------------------------------------------------------------
# bf CK0: Clock Gating and RAM Sleep Control Register
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_CK0                      = 0x10c0000c
# -----------------------------------------------------------------
# ------
# TR_CG4X_EN: 
# Access RW
# Clock gating enable for clk4x domain. 0=Clock on 1=Clock gating
# enabled
BF_CK0_TR_CG4X_EN_BIT            = 0
BF_CK0_TR_CG4X_EN_MASK           = 0x00000001
BF_CK0_TR_CG4X_EN_SH             = 0
BF_CK0_TR_CG4X_EN_DEF            = 0x00000000
# ------
# TR_CG8X_EN: 
# Access RW
# Clock gating enable for clk8x domain. 0=Clock on 1=Clock gating
# enabled
BF_CK0_TR_CG8X_EN_BIT            = 1
BF_CK0_TR_CG8X_EN_MASK           = 0x00000002
BF_CK0_TR_CG8X_EN_SH             = 1
BF_CK0_TR_CG8X_EN_DEF            = 0x00000000
# ------
# TR_CGTX_EN: 
# Access RW
# TX clock gating enable clk4x. This is the power management control for
# the external TX clock fanout buffer. In proto v1p and v2 and ASIC this
# will force the HV TX and SPI clock on. 0=TX clock buffer enabled. 1=TX
# clock buffer gating enabled. The TX clock will be enabled when needed
# for transmit time or a SPI write.
BF_CK0_TR_CGTX_EN_BIT            = 2
BF_CK0_TR_CGTX_EN_MASK           = 0x00000004
BF_CK0_TR_CGTX_EN_SH             = 2
BF_CK0_TR_CGTX_EN_DEF            = 0x00000000
# ------
# TR_LVDSPM_EN: 
# Access RW
# LVDS power management enable. 0=LVDS input buffers on. 1=Enable power
# management for LVDS input buffers for AFE5832 interface.
BF_CK0_TR_LVDSPM_EN_BIT          = 3
BF_CK0_TR_LVDSPM_EN_MASK         = 0x00000008
BF_CK0_TR_LVDSPM_EN_SH           = 3
BF_CK0_TR_LVDSPM_EN_DEF          = 0x00000000
# ------
# TR_TR_EN_EN: 
# Access RW
# TR_EN signal control for AFE5832. 0=TR_EN control disabled. 1=Enable
# TR_EN pin control.
BF_CK0_TR_TR_EN_EN_BIT           = 4
BF_CK0_TR_TR_EN_EN_MASK          = 0x00000010
BF_CK0_TR_TR_EN_EN_SH            = 4
BF_CK0_TR_TR_EN_EN_DEF           = 0x00000000
# ------
# TR_SLEEP_EN: 
# Access RW
# Block ram sleep mode control. 0=Block ram full power mode. 1=Block ram
# power management enabled. Enabled real time control of SRAM sleep mode
# pin.
BF_CK0_TR_SLEEP_EN_BIT           = 5
BF_CK0_TR_SLEEP_EN_MASK          = 0x00000020
BF_CK0_TR_SLEEP_EN_SH            = 5
BF_CK0_TR_SLEEP_EN_DEF           = 0x00000000
# ------
# TR_LVDSPM_CH_EN: 
# Access RW
# Enable per channel LVDS input buffer power management. 0 = All 32 LVDS
# data inputs in the same power state. 1 = Power state depends on
# receive aperture enables.
BF_CK0_TR_LVDSPM_CH_EN_BIT       = 6
BF_CK0_TR_LVDSPM_CH_EN_MASK      = 0x00000040
BF_CK0_TR_LVDSPM_CH_EN_SH        = 6
BF_CK0_TR_LVDSPM_CH_EN_DEF       = 0x00000000
# ------
# CW_LS_RST_EN: 
# Access RW
# CW clock LS reset enable. 0 = CW clock is free running 1 = BF outputs
# reset signal on LS. This is used as a phase reset in the top level
# clock generator block.
BF_CK0_CW_LS_RST_EN_BIT          = 7
BF_CK0_CW_LS_RST_EN_MASK         = 0x00000080
BF_CK0_CW_LS_RST_EN_SH           = 7
BF_CK0_CW_LS_RST_EN_DEF          = 0x00000000
# ------
# TR_WAKEUP_EN: 
# Access RW
# Global ram sleep mode override control. 0=Normal operation of sleep
# mode control. Individual blocks can be forced into power on mode using
# register bits [20:16] defined below. This may be used to enable live
# update of specific LUTs. 1=Force SRAM to power on mode. Used to enable
# CPU interface to LUTs when the real time power management would
# normally force SRAMSs into sleep mode. This bit must be set prior to
# any SW LUT write.
BF_CK0_TR_WAKEUP_EN_BIT          = 8
BF_CK0_TR_WAKEUP_EN_MASK         = 0x00000100
BF_CK0_TR_WAKEUP_EN_SH           = 8
BF_CK0_TR_WAKEUP_EN_DEF          = 0x00000000
# ------
# TR_HVSPIPM_EN: 
# Access RW
# Enable power management for HV pulser SPI interface port. 0 = HV SPI
# port LVDS buffer enabled. 1 = Enable power management for HV SPI LVDS
# buffers. The LVDS buffers for the four SPI data signals will be
# disabled by default and enabled only during SPI writes. The SPI enable
# signal is enabled at all times.
BF_CK0_TR_HVSPIPM_EN_BIT         = 9
BF_CK0_TR_HVSPIPM_EN_MASK        = 0x00000200
BF_CK0_TR_HVSPIPM_EN_SH          = 9
BF_CK0_TR_HVSPIPM_EN_DEF         = 0x00000000
# ------
