# Access RW
# 0 = Normal mode with LVDS buffer for SPI en0 enabled 1 = Disable en0.
BF_CK0_HVSPIEN0_DISABLE_BIT      = 10
BF_CK0_HVSPIEN0_DISABLE_MASK     = 0x00000400
BF_CK0_HVSPIEN0_DISABLE_SH       = 10
BF_CK0_HVSPIEN0_DISABLE_DEF      = 0x00000000
# ------
# HVSPIEN1_DISABLE: 
# Access RW
# 0 = Normal mode with LVDS buffer for SPI en1 enabled 1 = Disable en1.
BF_CK0_HVSPIEN1_DISABLE_BIT      = 11
BF_CK0_HVSPIEN1_DISABLE_MASK     = 0x00000800
BF_CK0_HVSPIEN1_DISABLE_SH       = 11
BF_CK0_HVSPIEN1_DISABLE_DEF      = 0x00000000
# ------
# DTGC_WAKEUP: 
# Access RW
# 1 = Force wakeup of DTGC LUT.
BF_CK0_DTGC_WAKEUP_BIT           = 16
BF_CK0_DTGC_WAKEUP_MASK          = 0x00010000
BF_CK0_DTGC_WAKEUP_SH            = 16
BF_CK0_DTGC_WAKEUP_DEF           = 0x00000000
# ------
# COMP_WAKEUP: 
# Access RW
# 1 = Force wakeup of compression LUT.
BF_CK0_COMP_WAKEUP_BIT           = 17
BF_CK0_COMP_WAKEUP_MASK          = 0x00020000
BF_CK0_COMP_WAKEUP_SH            = 17
BF_CK0_COMP_WAKEUP_DEF           = 0x00000000
# ------
# BPF_WAKEUP: 
# Access RW
# 1 = Force wakeup of BPF coef LUT.
BF_CK0_BPF_WAKEUP_BIT            = 18
BF_CK0_BPF_WAKEUP_MASK           = 0x00040000
BF_CK0_BPF_WAKEUP_SH             = 18
BF_CK0_BPF_WAKEUP_DEF            = 0x00000000
# ------
# WF_WAKEUP: 
# Access RW
# 1 = Force wakeup of wall filter coef LUT.
BF_CK0_WF_WAKEUP_BIT             = 19
BF_CK0_WF_WAKEUP_MASK            = 0x00080000
BF_CK0_WF_WAKEUP_SH              = 19
BF_CK0_WF_WAKEUP_DEF             = 0x00000000
# ------
# BLEND_WAKEUP: 
# Access RW
# 1 = Force wakeup of blending coef LUT.
BF_CK0_BLEND_WAKEUP_BIT          = 20
BF_CK0_BLEND_WAKEUP_MASK         = 0x00100000
BF_CK0_BLEND_WAKEUP_SH           = 20
BF_CK0_BLEND_WAKEUP_DEF          = 0x00000000
# ------
# CCOMP_WAKEUP: 
# Access RW
# 1 = Force wakeup of compounding block coef LUT.
BF_CK0_CCOMP_WAKEUP_BIT          = 21
BF_CK0_CCOMP_WAKEUP_MASK         = 0x00200000
BF_CK0_CCOMP_WAKEUP_SH           = 21
BF_CK0_CCOMP_WAKEUP_DEF          = 0x00000000
# ------
# BF_FLAG1_SEL: 
# Access RW
# 0 = Select beam parameter for bf_flag1 output pin. 1 = Select spare
# beam timer for bf_flag1 output pin.
BF_CK0_BF_FLAG1_SEL_BIT          = 24
BF_CK0_BF_FLAG1_SEL_MASK         = 0x01000000
BF_CK0_BF_FLAG1_SEL_SH           = 24
BF_CK0_BF_FLAG1_SEL_DEF          = 0x00000000
# ------
# BF_FLAG1_POL: 
# Access RW
# 0 = Spare beam timer on/off defines high time. 1 = Spare beam timer
# on/off defines low time.
BF_CK0_BF_FLAG1_POL_BIT          = 25
BF_CK0_BF_FLAG1_POL_MASK         = 0x02000000
BF_CK0_BF_FLAG1_POL_SH           = 25
BF_CK0_BF_FLAG1_POL_DEF          = 0x00000000
# -----------------------------------------------------------------
# bf PS0: Power supply configuration/control register 0
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_PS0                      = 0x10c00010
# -----------------------------------------------------------------
# ------
# PS_ENABLE: 
