BF_PS0_PS_CLK_FL_MSB             = 15
BF_PS0_PS_CLK_FL_MASK            = 0x0000f000
BF_PS0_PS_CLK_FL_SH              = 12
BF_PS0_PS_CLK_FL_DEF             = 0x00000000
# ------
# HVPS_V2_EN: 
# Access RW
# Enable for HV1p and HV1n LDO Polarity TBD
