BF_AFE4_AFE_UPDN_DEL_LSB         = 16
BF_AFE4_AFE_UPDN_DEL_MSB         = 31
BF_AFE4_AFE_UPDN_DEL_MASK        = 0xffff0000
BF_AFE4_AFE_UPDN_DEL_SH          = 16
BF_AFE4_AFE_UPDN_DEL_DEF         = 0x00000000
