# bf AFE5: Afe configuration/control Register-5
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_AFE5                     = 0x10c00030
# -----------------------------------------------------------------
# ------
# AFE_TRIG_DEL: 
# Access RW
# Delay from PRI to output of TX_TRIG pulse to AFEs in units of 4*Fs
# (100Mhz).
BF_AFE5_AFE_TRIG_DEL_BITS        = 16
BF_AFE5_AFE_TRIG_DEL_LSB         = 0
BF_AFE5_AFE_TRIG_DEL_MSB         = 15
BF_AFE5_AFE_TRIG_DEL_MASK        = 0x0000ffff
BF_AFE5_AFE_TRIG_DEL_SH          = 0
BF_AFE5_AFE_TRIG_DEL_DEF         = 0x00000000
# -----------------------------------------------------------------
# bf BP0: 0 word offset from base.
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_BP0                      = 0x10c04000
# -----------------------------------------------------------------
# ------
# ADC_S: 
# Access RW
# Number of ADC samples received for beam -1 Defines the total number of
# ADC samples stored in the delay memory circular buffer.
BF_BP0_ADC_S_BITS                = 13
BF_BP0_ADC_S_LSB                 = 0
BF_BP0_ADC_S_MSB                 = 12
BF_BP0_ADC_S_MASK                = 0x00001fff
BF_BP0_ADC_S_SH                  = 0
BF_BP0_ADC_S_DEF                 = 0x00000000
# ------
# ADC_S_PRE: 
# Access RW
# Number of ADC stamples stored in delay memory prior to start of
# beamforming -1
BF_BP0_ADC_S_PRE_BITS            = 10
BF_BP0_ADC_S_PRE_LSB             = 16
BF_BP0_ADC_S_PRE_MSB             = 25
BF_BP0_ADC_S_PRE_MASK            = 0x03ff0000
BF_BP0_ADC_S_PRE_SH              = 16
BF_BP0_ADC_S_PRE_DEF             = 0x00000000
# -----------------------------------------------------------------
# bf FPS: Focal Point Params
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_FPS                      = 0x10c04004
# -----------------------------------------------------------------
# ------
# FP_S: 
# Access RW
# Number of calculated focal points -1 Defines the total number of focal
# points calculate from TX/RX time of flight. This value is choses as a
# function of imaging depth, required delay accuracy, and any applied
# focal point correction.
BF_FPS_FP_S_BITS                 = 14
BF_FPS_FP_S_LSB                  = 0
BF_FPS_FP_S_MSB                  = 13
BF_FPS_FP_S_MASK                 = 0x00003fff
BF_FPS_FP_S_SH                   = 0
BF_FPS_FP_S_DEF                  = 0x00000000
# ------
# DM_START: 
# Access RW
# Delay memory start address. This value is used for C beams when the
# top of the color ROI is below the skin line. The delay calculations
# are absolute so if data capture starts after the skin line then the
# write address must represent the correct sample address as if starting
# from the skin line. With Rs is the range from the origin to the top of
# the color ROI.
BF_FPS_DM_START_BITS             = 10
BF_FPS_DM_START_LSB              = 16
BF_FPS_DM_START_MSB              = 25
BF_FPS_DM_START_MASK             = 0x03ff0000
BF_FPS_DM_START_SH               = 16
BF_FPS_DM_START_DEF              = 0x00000000
# ------
# DEL_SCALE: 
# Access RW
# Delay calculation scale. Defines scaling of calculated delays prior to
# interpolation. Used when focal points and element postions are scaled
# by a power of two in order to trade delay range for accuracy. 0x0= 1
# 0x1 = 1/2 0x2 = 1/4 0x3 = 1/8 others = 1
BF_FPS_DEL_SCALE_BITS            = 3
BF_FPS_DEL_SCALE_LSB             = 28
BF_FPS_DEL_SCALE_MSB             = 30
BF_FPS_DEL_SCALE_MASK            = 0x70000000
BF_FPS_DEL_SCALE_SH              = 28
BF_FPS_DEL_SCALE_DEF             = 0x00000000
# -----------------------------------------------------------------
# bf BPS: Beam Param Samples
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_BPS                      = 0x10c04008
# -----------------------------------------------------------------
# ------
# BF_S: 
# Access RW
# Total number of generated delays -1 Defines the total number of delay
# and apodization weights calculated after interpolation.
BF_BPS_BF_S_BITS                 = 14
BF_BPS_BF_S_LSB                  = 0
BF_BPS_BF_S_MSB                  = 13
BF_BPS_BF_S_MASK                 = 0x00003fff
BF_BPS_BF_S_SH                   = 0
BF_BPS_BF_S_DEF                  = 0x00000000
# ------
# BFOUT_S: 
# Access RW
#  Beamformer output words B -1 Defines the total number of 32 bit
# output words for PRI. Value depends on data type: B mode: B samples -1
# C mode: Color flow processing samples*4 -1 (N,D,P,U words for each
# color sample) IQ data: Sample*4-1 (One 32 bit I/Q word per sample per
# beam)
BF_BPS_BFOUT_S_BITS              = 11
BF_BPS_BFOUT_S_LSB               = 16
BF_BPS_BFOUT_S_MSB               = 26
BF_BPS_BFOUT_S_MASK              = 0x07ff0000
BF_BPS_BFOUT_S_SH                = 16
BF_BPS_BFOUT_S_DEF               = 0x00000000
