BF_FPLUT_HV_CLKEN_OFF_BITS       = 16
BF_FPLUT_HV_CLKEN_OFF_LSB        = 0
BF_FPLUT_HV_CLKEN_OFF_MSB        = 15
BF_FPLUT_HV_CLKEN_OFF_MASK       = 0x0000ffff
BF_FPLUT_HV_CLKEN_OFF_SH         = 0
BF_FPLUT_HV_CLKEN_OFF_DEF        = 0x00000000
# ------
# HV_CLKEN_ON: 
# Access RW
