BF_FPLUT_HV_CLKEN_ON_BITS        = 16
BF_FPLUT_HV_CLKEN_ON_LSB         = 16
BF_FPLUT_HV_CLKEN_ON_MSB         = 31
BF_FPLUT_HV_CLKEN_ON_MASK        = 0xffff0000
BF_FPLUT_HV_CLKEN_ON_SH          = 16
BF_FPLUT_HV_CLKEN_ON_DEF         = 0x00000000
