BF_BENABLE_BX_TX_EN_MASK         = 0x00000001
BF_BENABLE_BX_TX_EN_SH           = 0
BF_BENABLE_BX_TX_EN_DEF          = 0x00000000
# ------
# BX_RX_EN: 
# Access RW
# Beam RX enable. The top level register bit rx_en must also be set to
