BF_BENABLE_BX_RX_EN_BIT          = 1
BF_BENABLE_BX_RX_EN_MASK         = 0x00000002
BF_BENABLE_BX_RX_EN_SH           = 1
BF_BENABLE_BX_RX_EN_DEF          = 0x00000000
