BF_BENABLE_BP_BF_EN_BIT          = 2
BF_BENABLE_BP_BF_EN_MASK         = 0x00000004
BF_BENABLE_BP_BF_EN_SH           = 2
BF_BENABLE_BP_BF_EN_DEF          = 0x00000000
