BF_BENABLE_OUT_TYPE_BITS         = 3
BF_BENABLE_OUT_TYPE_LSB          = 4
BF_BENABLE_OUT_TYPE_MSB          = 6
BF_BENABLE_OUT_TYPE_MASK         = 0x00000070
BF_BENABLE_OUT_TYPE_SH           = 4
BF_BENABLE_OUT_TYPE_DEF          = 0x00000000
# ------
# OUT_IQ_TYPE: 
