BF_BENABLE_OUT_IQ_TYPE_BITS      = 2
BF_BENABLE_OUT_IQ_TYPE_LSB       = 8
BF_BENABLE_OUT_IQ_TYPE_MSB       = 9
BF_BENABLE_OUT_IQ_TYPE_MASK      = 0x00000300
BF_BENABLE_OUT_IQ_TYPE_SH        = 8
BF_BENABLE_OUT_IQ_TYPE_DEF       = 0x00000000
# ------
# CTB_WRITE_EN: 
# Access RW
