BF_BENABLE_BP_ALT_HV_CONFIG_MASK = 0x10000000
BF_BENABLE_BP_ALT_HV_CONFIG_SH   = 28
BF_BENABLE_BP_ALT_HV_CONFIG_DEF  = 0x00000000
