BF_BPWR_PM_AFE_PWR_ON_BIT        = 1
BF_BPWR_PM_AFE_PWR_ON_MASK       = 0x00000002
BF_BPWR_PM_AFE_PWR_ON_SH         = 1
BF_BPWR_PM_AFE_PWR_ON_DEF        = 0x00000000
# ------
# PM_AFE_PWR_OFF: 
# Access RW
