BF_BPWR_PM_AFE_PWR_SB_BIT        = 3
BF_BPWR_PM_AFE_PWR_SB_MASK       = 0x00000008
BF_BPWR_PM_AFE_PWR_SB_SH         = 3
BF_BPWR_PM_AFE_PWR_SB_DEF        = 0x00000000
# ------
# PM_AFE_GBL_TIMER: 
# Access RW
