BF_BPWR_PM_AFE_GBL_TIMER_BIT     = 4
BF_BPWR_PM_AFE_GBL_TIMER_MASK    = 0x00000010
BF_BPWR_PM_AFE_GBL_TIMER_SH      = 4
BF_BPWR_PM_AFE_GBL_TIMER_DEF     = 0x00000000
# ------
