# register writes to configure the TX parts for a particular beam angle.
BF_TXLUT_TXD_SPI_PTR_BITS        = 13
BF_TXLUT_TXD_SPI_PTR_LSB         = 0
BF_TXLUT_TXD_SPI_PTR_MSB         = 12
BF_TXLUT_TXD_SPI_PTR_MASK        = 0x00001fff
BF_TXLUT_TXD_SPI_PTR_SH          = 0
BF_TXLUT_TXD_SPI_PTR_DEF         = 0x00000000
# ------
# TXD_W_C: 
# Access RW
