BF_TXLUT_TXD_W_C_BITS            = 12
BF_TXLUT_TXD_W_C_LSB             = 16
BF_TXLUT_TXD_W_C_MSB             = 27
BF_TXLUT_TXD_W_C_MASK            = 0x0fff0000
