BF_TXLEN_TXLEN_BITS              = 14
BF_TXLEN_TXLEN_LSB               = 0
BF_TXLEN_TXLEN_MSB               = 13
BF_TXLEN_TXLEN_MASK              = 0x00003fff
BF_TXLEN_TXLEN_SH                = 0
BF_TXLEN_TXLEN_DEF               = 0x00000000
# -----------------------------------------------------------------
# bf RXAP_LOW: Receive Element Enable Register Low
# RX element [31:0] enable. rxap_low(n) = 0 RX disabled for element n.
# Delay memory read data forced to zero. rxap_low(n) = 1 RX enabled for
# element n.
# Access RW
# -----------------------------------------------------------------
BF_ADDR_RXAP_LOW                 = 0x10c04028
# -----------------------------------------------------------------
# ------
BF_RXAP_LOW_BITS                 = 32
BF_RXAP_LOW_LSB                  = 0
