BF_RXAP_LOW_SH                   = 0
BF_RXAP_LOW_DEF                  = 0x00000000
# -----------------------------------------------------------------
# bf RXAP_HIGH: Receive Element Enable Register High
# RX element [63:32] enable. rxap_low(n) = 0 RX disabled for element n.
