# element n.
# Access RW
# -----------------------------------------------------------------
BF_ADDR_RXAP_HIGH                = 0x10c0402c
# -----------------------------------------------------------------
# ------
BF_RXAP_HIGH_BITS                = 32
BF_RXAP_HIGH_LSB                 = 0
BF_RXAP_HIGH_MSB                 = 31
BF_RXAP_HIGH_MASK                = 0xffffffff
BF_RXAP_HIGH_SH                  = 0
BF_RXAP_HIGH_DEF                 = 0x00000000
