# bf BPRF: bprf
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_BPRF                     = 0x10c0403c
# -----------------------------------------------------------------
# ------
# BPT_SPARE_ON: 
# Access RW
# ASIC: Spare beam timer output on time in units of Fs/16 or 16 ADC
# samples. Used to define a spare signal that is asserted for a defined
# range of the PRI time and routed to the spare ASIC pin bf_flag1.
BF_BPRF_BPT_SPARE_ON_BITS        = 16
BF_BPRF_BPT_SPARE_ON_LSB         = 0
BF_BPRF_BPT_SPARE_ON_MSB         = 15
BF_BPRF_BPT_SPARE_ON_MASK        = 0x0000ffff
BF_BPRF_BPT_SPARE_ON_SH          = 0
BF_BPRF_BPT_SPARE_ON_DEF         = 0x00000000
