# BPT_SPARE_OFF: 
# Access RW
# Off time in units of Fs/16.
BF_BPRF_BPT_SPARE_OFF_BITS       = 16
BF_BPRF_BPT_SPARE_OFF_LSB        = 16
BF_BPRF_BPT_SPARE_OFF_MSB        = 31
BF_BPRF_BPT_SPARE_OFF_MASK       = 0xffff0000
BF_BPRF_BPT_SPARE_OFF_SH         = 16
BF_BPRF_BPT_SPARE_OFF_DEF        = 0x00000000
