# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_BPF2                     = 0x10c04048
# -----------------------------------------------------------------
# ------
# VBP_PHASE_INC: 
# Access RW
# U5.3, U4.4, BPF filter phase increment. With vbp_pr = 0: vbp_phase_inc
# = D*8 With vbp_pr = 1 : vbp_phase_inc = D*16
BF_BPF2_VBP_PHASE_INC_BITS       = 8
BF_BPF2_VBP_PHASE_INC_LSB        = 0
BF_BPF2_VBP_PHASE_INC_MSB        = 7
BF_BPF2_VBP_PHASE_INC_MASK       = 0x000000ff
BF_BPF2_VBP_PHASE_INC_SH         = 0
BF_BPF2_VBP_PHASE_INC_DEF        = 0x00000000
# ------
# VBP_W_C: 
# Access RW
# BPF output word count. vbp_w_c[13:0] = O_S-1
BF_BPF2_VBP_W_C_BITS             = 14
BF_BPF2_VBP_W_C_LSB              = 16
BF_BPF2_VBP_W_C_MSB              = 29
BF_BPF2_VBP_W_C_MASK             = 0x3fff0000
BF_BPF2_VBP_W_C_SH               = 16
BF_BPF2_VBP_W_C_DEF              = 0x00000000
