# APOD_SCALE: 
# Access RW
# Format 8.8. This is the fixed, non range dependent scale factor
# applied to apod element positions. The typical value is 1.0
BF_APOD0_APOD_SCALE_BITS         = 16
BF_APOD0_APOD_SCALE_LSB          = 16
BF_APOD0_APOD_SCALE_MSB          = 31
BF_APOD0_APOD_SCALE_MASK         = 0xffff0000
BF_APOD0_APOD_SCALE_SH           = 16
BF_APOD0_APOD_SCALE_DEF          = 0x00000000
