BF_APOD1_APOD_FLAT_BIT           = 0
BF_APOD1_APOD_FLAT_MASK          = 0x00000001
BF_APOD1_APOD_FLAT_SH            = 0
BF_APOD1_APOD_FLAT_DEF           = 0x00000000
