BF_DTGC1_TGC1_LGC_BITS           = 24
BF_DTGC1_TGC1_LGC_LSB            = 0
BF_DTGC1_TGC1_LGC_MSB            = 23
BF_DTGC1_TGC1_LGC_MASK           = 0x00ffffff
BF_DTGC1_TGC1_LGC_SH             = 0
BF_DTGC1_TGC1_LGC_DEF            = 0x00000000
# ------
