BF_DTGC1_TGC1_FLAT_BIT           = 24
BF_DTGC1_TGC1_FLAT_MASK          = 0x01000000
BF_DTGC1_TGC1_FLAT_SH            = 24
BF_DTGC1_TGC1_FLAT_DEF           = 0x00000000
