# bf AFE1_WDATA: AFE1 Write Data Register
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_AFE1_WDATA               = 0x10c14800
# -----------------------------------------------------------------
# ------
# AFE1_WDATA: 
# Access RW
# Write data for AFE1.
BF_AFE1_WDATA_AFE1_WDATA_BITS    = 16
BF_AFE1_WDATA_AFE1_WDATA_LSB     = 0
BF_AFE1_WDATA_AFE1_WDATA_MSB     = 15
BF_AFE1_WDATA_AFE1_WDATA_MASK    = 0x0000ffff
BF_AFE1_WDATA_AFE1_WDATA_SH      = 0
BF_AFE1_WDATA_AFE1_WDATA_DEF     = 0x00000000
# -----------------------------------------------------------------
# bf AFE1_RDATA: AFE1 Read Data Register
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_AFE1_RDATA               = 0x10c14804
# -----------------------------------------------------------------
# ------
# AFE1_RDATA: 
# Access RO
# Read data for AFE1.
BF_AFE1_RDATA_AFE1_RDATA_BITS    = 16
BF_AFE1_RDATA_AFE1_RDATA_LSB     = 0
BF_AFE1_RDATA_AFE1_RDATA_MSB     = 15
BF_AFE1_RDATA_AFE1_RDATA_MASK    = 0x0000ffff
BF_AFE1_RDATA_AFE1_RDATA_SH      = 0
BF_AFE1_RDATA_AFE1_RDATA_DEF     = 0x00000000
# -----------------------------------------------------------------
