# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_AFE1_STATUS              = 0x10c14808
# -----------------------------------------------------------------
# ------
# AFE1_SPI_BUSY: 
# Access RO
# 0 = SPI port ready 1 = SPI port busy.
BF_AFE1_STATUS_AFE1_SPI_BUSY_BIT = 0
