BF_AFE1_STATUS_AFE1_SPI_BUSY_SH  = 0
BF_AFE1_STATUS_AFE1_SPI_BUSY_DEF = 0x00000000
# -----------------------------------------------------------------
# bf AFE1_CLKDIV: AFE1 Clock Divide Register
# 
# Access RW
# -----------------------------------------------------------------
BF_ADDR_AFE1_CLKDIV              = 0x10c1480c
# -----------------------------------------------------------------
# ------
# AFE1_CLKDIV: 
# Access RW
# Defines SPI bit clock rate. If Divider value is afe1_clkdiv, then SPI
